// SEC-008: Audit log — tamper-evident record of privileged actions

// BST/DST helper: add N weeks to a game date while preserving wall-clock time in Europe/London.
// Standard Date.setDate() operates in UTC, so crossing a DST boundary shifts the stored hour by 1.
// This function extracts the London local hour/minute from the original date, adds weeks to the
// calendar date, then returns the UTC instant that gives the same wall-clock time in London.
// N2: Reject any social URL that doesn't start with https:// — prevents javascript: URI stored XSS
function validateSocialUrl(url) {
    if (!url) return null;
    const trimmed = String(url).trim();
    if (!trimmed.startsWith('https://')) return null;
    return trimmed;
}

// CRIT-8/10/15/N8: htmlEncode for user-supplied values inside HTML email bodies
function htmlEncode(str) {
    if (str === null || str === undefined) return '';
    return String(str)
        .replace(/&/g, '&amp;')
        .replace(/</g, '&lt;')
        .replace(/>/g, '&gt;')
        .replace(/"/g, '&quot;')
        .replace(/'/g, '&#39;');
}

// ── COMMS CAMPAIGN HELPERS ──────────────────────────────────────────────────
// Renders {firstName}, {claimUrl}, {expiryDate} placeholders inside the
// admin-supplied body template. Newlines become <br> for HTML email.
function _renderCommsBody(template, firstName, claimUrl, expiryDate) {
    const safeName    = (firstName || 'there').replace(/[<>&]/g, '');
    const safeUrl     = String(claimUrl).replace(/[<>"']/g, '');
    const safeExpiry  = String(expiryDate).replace(/[<>&]/g, '');
    const html = (template || '')
        .replace(/\{firstName\}/g, safeName)
        .replace(/\{expiryDate\}/g, safeExpiry)
        .replace(/\{claimUrl\}/g, safeUrl)
        .replace(/\n/g, '<br>');
    return html;
}

// Generate a URL-safe random claim token. crypto.randomBytes is already
// available via the existing require at the top of this file.
const _crypto = require('crypto');
function _generateClaimToken() {
    return _crypto.randomBytes(24).toString('base64url'); // 32-char URL-safe
}

// wrapEmailHtml: consistent dark-theme email wrapper used by signup + topup emails
function wrapEmailHtml(inner, options) {
    // FIX-316: optional broadcast-footer (unsubscribe link) for mass messages.
    // Transactional emails (registration, payment, RSVP) MUST NOT pass options —
    // legally we only need an unsubscribe link on marketing / broadcast emails.
    // Backward-compat: existing call sites with single arg get the original behaviour.
    const broadcastFooter = (options && options.unsubToken)
        ? `<p style="color:#333;font-size:11px;margin-top:16px;letter-spacing:0.5px;">
              Don't want broadcast emails from TotalFooty?
              <a href="https://totalfooty.co.uk/api/unsubscribe/broadcasts/${options.unsubToken}" style="color:#555;text-decoration:underline;">Unsubscribe</a>
              — you'll still get game confirmations and payment receipts.
           </p>`
        : '';
    return `<div style="background:#0d0d0d;padding:40px;font-family:Arial,sans-serif;max-width:520px;margin:0 auto;">
        <img src="https://totalfooty.co.uk/assets/logo.png" width="80" style="margin-bottom:24px"/>
        ${inner}
        <p style="color:#333;font-size:11px;margin-top:32px;letter-spacing:1px;">TOTALFOOTY — COVENTRY FOOTBALL COMMUNITY</p>
        ${broadcastFooter}
    </div>`;
}

function addWeeksLondon(isoDateStr, weeks) {
    const orig = new Date(isoDateStr);
    const fmt = new Intl.DateTimeFormat('en-CA', {
        timeZone: 'Europe/London',
        year: 'numeric', month: '2-digit', day: '2-digit',
        hour: '2-digit', minute: '2-digit', second: '2-digit',
        hour12: false
    });
    const parts = fmt.formatToParts(orig);
    const get = (type) => parseInt(parts.find(p => p.type === type)?.value || '0');
    const year = get('year'), month = get('month'), day = get('day');
    const hour = get('hour'), minute = get('minute'), second = get('second');

    // Build target date: same wall-clock time but weeks * 7 days later (JS Date handles month overflow)
    const target = new Date(Date.UTC(year, month - 1, day + weeks * 7, hour, minute, second));

    // Check what London hour this UTC instant corresponds to (may differ across DST boundary).
    // FIX-DST2: clamp hourDiff to ±1 to guard against the midnight edge case where a 23h→0h
    // or 0h→23h wrap produces a spurious diff of ±23 instead of the real ±1 DST shift.
    const checkParts = fmt.formatToParts(target);
    const checkHour = parseInt(checkParts.find(p => p.type === 'hour')?.value || '0');
    let hourDiff = checkHour - hour;
    if (hourDiff > 12)  hourDiff -= 24;   // e.g. 23 - 0 = 23  → clamp to -1 (clocks went back)
    if (hourDiff < -12) hourDiff += 24;   // e.g. 0  - 23 = -23 → clamp to +1 (clocks went forward)
    if (hourDiff !== 0) {
        return new Date(target.getTime() - hourDiff * 3600 * 1000);
    }
    return target;
}

// Builds the "tonight, 7:30pm at Daimler Green" trailer used in guest-invite messages.
// All formatting in Europe/London. Returns null if either field is missing so callers
// can fall back to a simpler message.
//   • today + game time ≥ 17:00 → "tonight"
//   • today + game time <  17:00 → "today"
//   • next calendar day → "tomorrow"
//   • else → weekday name (e.g. "Saturday")
//   • time: "7pm" / "7:30pm" (drops :00 on the hour; handles 12am/12pm)
function buildGuestInviteWhenAtVenue(gameDate, venueName) {
    if (!gameDate || !venueName) return null;
    const d = gameDate instanceof Date ? gameDate : new Date(gameDate);
    if (isNaN(d.getTime())) return null;
    const tz = 'Europe/London';

    const dayFmt = new Intl.DateTimeFormat('en-CA', {
        timeZone: tz, year: 'numeric', month: '2-digit', day: '2-digit'
    });
    const gameDay = dayFmt.format(d);
    const now = new Date();
    const todayDay = dayFmt.format(now);
    const tomorrow = new Date(now.getTime() + 24 * 60 * 60 * 1000);
    const tomorrowDay = dayFmt.format(tomorrow);

    const hmStr = new Intl.DateTimeFormat('en-GB', {
        timeZone: tz, hour: '2-digit', minute: '2-digit', hour12: false
    }).format(d);
    const [hh, mm] = hmStr.split(':');
    const h24 = parseInt(hh, 10);
    const h12 = h24 === 0 ? 12 : (h24 > 12 ? h24 - 12 : h24);
    const ampm = h24 < 12 ? 'am' : 'pm';
    const timeLabel = mm === '00' ? `${h12}${ampm}` : `${h12}:${mm}${ampm}`;

    let whenLabel;
    if (gameDay === todayDay) {
        whenLabel = h24 >= 17 ? 'tonight' : 'today';
    } else if (gameDay === tomorrowDay) {
        whenLabel = 'tomorrow';
    } else {
        whenLabel = new Intl.DateTimeFormat('en-GB', { timeZone: tz, weekday: 'long' }).format(d);
    }

    return `${whenLabel}, ${timeLabel} at ${venueName}`;
}

// UUID v4 validator — used to reject truncated/malformed IDs from clients with a
// clean 400 before they hit Postgres and throw 22P02 (which shows as an error in
// Render logs even though it's really a bad request).
const _UUID_RE = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;
function isValidUuid(s) { return typeof s === 'string' && _UUID_RE.test(s); }

// FIX-334 (ROW Day 20): TF Coventry becomes a real tenant. This constant is
// the fixed UUID for the TF Coventry tenant row (inserted by FIX-334 migration
// Block 1). Code that previously special-cased tenant_id IS NULL for TF root
// can now reference this UUID where needed.
//
