// FIX-271: lightweight player search for admin tooling — matches alias,
// full_name, or squad_number (numeric exact match). Returns up to 20 rows
// with just the columns the mute form needs. Cheap, deliberately narrow
// projection so we don't leak unrelated fields (the master prompt's "no
// SELECT *" convention). Admin auth required.
app.get('/api/admin/players/search', authenticateToken, requireAdmin, async (req, res) => {
    try {
        const q = (req.query.q || '').toString().trim();
        if (!q) return res.json({ players: [] });

        const like = '%' + q.toLowerCase() + '%';
        const squadNum = parseInt(q, 10);
        const isNumeric = Number.isFinite(squadNum) && String(squadNum) === q;

        // Two-branch query: numeric input also matches exact squad_number.
        // LIMIT 20 caps result size for the dropdown.
        // FIX-353: email searched + returned. FIX-382: `email` lives on `users`,
        // NOT `players` — the original FIX-353 query selected/filtered p.email which
        // does not exist, 500-ing the endpoint (and the 4 features that call it).
        // Rewritten to LEFT JOIN users (matches the grid query convention just below;
        // LEFT so players without a user row still appear). Explicit columns, no SELECT *.
        const sql = isNumeric
            ? `SELECT p.id, p.alias, p.full_name, p.squad_number, u.email
                 FROM players p
                 LEFT JOIN users u ON u.id = p.user_id
                WHERE LOWER(p.alias)     LIKE $1
                   OR LOWER(p.full_name) LIKE $1
                   OR LOWER(u.email)     LIKE $1
                   OR p.squad_number = $2
                ORDER BY (p.squad_number = $2) DESC, p.alias NULLS LAST, p.full_name
                LIMIT 20`
            : `SELECT p.id, p.alias, p.full_name, p.squad_number, u.email
                 FROM players p
                 LEFT JOIN users u ON u.id = p.user_id
                WHERE LOWER(p.alias)     LIKE $1
                   OR LOWER(p.full_name) LIKE $1
                   OR LOWER(u.email)     LIKE $1
                ORDER BY p.alias NULLS LAST, p.full_name
                LIMIT 20`;
        const params = isNumeric ? [like, squadNum] : [like];

        const result = await pool.query(sql, params);
        res.json({ players: result.rows });
    } catch (e) {
        console.error('GET /api/admin/players/search error:', e);
        res.status(500).json({ error: 'server_error', detail: e.message });
    }
});

app.get('/api/admin/players/grid', authenticateToken, requireAdmin, async (req, res) => {
    try {
        const result = await pool.query(`
            SELECT 
                p.id, p.full_name, p.alias, p.squad_number, p.player_number, p.player_number_text, p.photo_url, /* FIX-302 */
                p.reliability_tier, p.phone,
                p.overall_rating, p.defending_rating, p.strength_rating, p.fitness_rating,
                p.pace_rating, p.decisions_rating, p.assisting_rating, p.shooting_rating,
                p.goalkeeper_rating,
                p.is_clm_admin, p.is_organiser,
                p.ovr_suspicion, -- FIX-245: rating-suspicion flag for the 🚩/🔥 indicator
                u.role as user_role, u.email,
                c.balance as credits,

                -- Badges with IDs
                (SELECT json_agg(json_build_object('id', b.id, 'name', b.name, 'color', b.color, 'icon', b.icon))
                 FROM player_badges pb JOIN badges b ON pb.badge_id = b.id WHERE pb.player_id = p.id) as badges,

                -- GAME STATS: all time
                p.total_appearances, p.total_wins, p.total_draws, p.motm_wins,

                -- GAME STATS: last 3 months
                (SELECT COUNT(DISTINCT r.game_id)
                 FROM registrations r JOIN games g ON g.id = r.game_id
                 WHERE r.player_id = p.id AND r.status = 'confirmed'
                 AND g.game_status = 'completed'
                 AND g.game_date >= NOW() - INTERVAL '3 months') as apps_3m,

                (SELECT COUNT(*) FROM games g WHERE g.motm_winner_id = p.id
                 AND g.game_status = 'completed' AND NOT g.stats_void
                 AND g.game_date >= NOW() - INTERVAL '3 months') as motm_3m,

                (SELECT COUNT(DISTINCT r.game_id)
                 FROM registrations r JOIN games g ON g.id = r.game_id
                 JOIN team_players tp ON tp.player_id = r.player_id
                 JOIN teams t ON t.id = tp.team_id AND t.game_id = g.id
                 WHERE r.player_id = p.id AND r.status = 'confirmed'
                 AND g.game_status = 'completed'
                 AND LOWER(g.winning_team) = LOWER(t.team_name)
                 AND g.game_date >= NOW() - INTERVAL '3 months') as wins_3m,

                -- GAME STATS: calendar year
                (SELECT COUNT(DISTINCT r.game_id)
                 FROM registrations r JOIN games g ON g.id = r.game_id
                 WHERE r.player_id = p.id AND r.status = 'confirmed'
                 AND g.game_status = 'completed'
                 AND g.game_date >= DATE_TRUNC('year', NOW())) as apps_year,

                (SELECT COUNT(*) FROM games g WHERE g.motm_winner_id = p.id
                 AND g.game_status = 'completed' AND NOT g.stats_void
                 AND g.game_date >= DATE_TRUNC('year', NOW())) as motm_year,

                (SELECT COUNT(DISTINCT r.game_id)
                 FROM registrations r JOIN games g ON g.id = r.game_id
                 JOIN team_players tp ON tp.player_id = r.player_id
                 JOIN teams t ON t.id = tp.team_id AND t.game_id = g.id
                 WHERE r.player_id = p.id AND r.status = 'confirmed'
                 AND g.game_status = 'completed'
                 AND LOWER(g.winning_team) = LOWER(t.team_name)
                 AND g.game_date >= DATE_TRUNC('year', NOW())) as wins_year,

                -- FINANCIAL: all time
                COALESCE((SELECT SUM(ct.amount) FROM credit_transactions ct
                 WHERE ct.player_id = p.id AND ct.type = 'admin_adjustment' AND ct.amount > 0), 0) as topped_up,

                COALESCE((SELECT SUM(ABS(ct.amount)) FROM credit_transactions ct
                 WHERE ct.player_id = p.id AND ct.type = 'game_fee'), 0) as spent,

                (SELECT COUNT(*) FROM game_guests gg WHERE gg.invited_by = p.id) as guests_invited,

                (SELECT COUNT(*) FROM players ref WHERE ref.referred_by = p.id) as players_referred,

                COALESCE((SELECT SUM(ABS(ct.amount)) FROM credit_transactions ct
                 JOIN players ref ON ct.player_id = ref.id
                 WHERE ref.referred_by = p.id AND ct.type = 'game_fee'), 0) as referred_spend,

                -- CLM REVENUE per player: their fees at CLM games + their guests' fees at CLM games
                COALESCE((SELECT SUM(g.cost_per_player) FROM registrations r
                 JOIN games g ON g.id = r.game_id
                 WHERE r.player_id = p.id AND r.status = 'confirmed'
                 AND g.exclusivity = 'clm' AND g.game_status = 'completed'), 0)
                +
                COALESCE((SELECT SUM(gg.amount_paid) FROM game_guests gg
                 JOIN games g ON g.id = gg.game_id
                 WHERE gg.invited_by = p.id AND g.exclusivity = 'clm'), 0) as clm_revenue,

                -- FINANCIAL: last 3 months
                COALESCE((SELECT SUM(ct.amount) FROM credit_transactions ct
                 WHERE ct.player_id = p.id AND ct.type = 'admin_adjustment' AND ct.amount > 0
                 AND ct.created_at >= NOW() - INTERVAL '3 months'), 0) as topped_up_3m,

                COALESCE((SELECT SUM(ABS(ct.amount)) FROM credit_transactions ct
                 WHERE ct.player_id = p.id AND ct.type = 'game_fee'
                 AND ct.created_at >= NOW() - INTERVAL '3 months'), 0) as spent_3m,

                (SELECT COUNT(*) FROM game_guests gg
                 JOIN games g ON g.id = gg.game_id
                 WHERE gg.invited_by = p.id
                 AND g.game_date >= NOW() - INTERVAL '3 months') as guests_invited_3m,

                (SELECT COUNT(*) FROM players ref WHERE ref.referred_by = p.id
                 AND ref.created_at >= NOW() - INTERVAL '3 months') as players_referred_3m,

                COALESCE((SELECT SUM(ABS(ct.amount)) FROM credit_transactions ct
                 JOIN players ref ON ct.player_id = ref.id
                 WHERE ref.referred_by = p.id AND ct.type = 'game_fee'
                 AND ct.created_at >= NOW() - INTERVAL '3 months'), 0) as referred_spend_3m,

                COALESCE((SELECT SUM(g.cost_per_player) FROM registrations r
                 JOIN games g ON g.id = r.game_id
                 WHERE r.player_id = p.id AND r.status = 'confirmed'
                 AND g.exclusivity = 'clm' AND g.game_status = 'completed'
                 AND g.game_date >= NOW() - INTERVAL '3 months'), 0)
                +
                COALESCE((SELECT SUM(gg.amount_paid) FROM game_guests gg
                 JOIN games g ON g.id = gg.game_id
                 WHERE gg.invited_by = p.id AND g.exclusivity = 'clm'
                 AND g.game_date >= NOW() - INTERVAL '3 months'), 0) as clm_revenue_3m,

                -- FINANCIAL: calendar year
                COALESCE((SELECT SUM(ct.amount) FROM credit_transactions ct
                 WHERE ct.player_id = p.id AND ct.type = 'admin_adjustment' AND ct.amount > 0
                 AND ct.created_at >= DATE_TRUNC('year', NOW())), 0) as topped_up_year,

                COALESCE((SELECT SUM(ABS(ct.amount)) FROM credit_transactions ct
                 WHERE ct.player_id = p.id AND ct.type = 'game_fee'
                 AND ct.created_at >= DATE_TRUNC('year', NOW())), 0) as spent_year,

                (SELECT COUNT(*) FROM game_guests gg
                 JOIN games g ON g.id = gg.game_id
                 WHERE gg.invited_by = p.id
                 AND g.game_date >= DATE_TRUNC('year', NOW())) as guests_invited_year,

                (SELECT COUNT(*) FROM players ref WHERE ref.referred_by = p.id
                 AND ref.created_at >= DATE_TRUNC('year', NOW())) as players_referred_year,

                COALESCE((SELECT SUM(ABS(ct.amount)) FROM credit_transactions ct
                 JOIN players ref ON ct.player_id = ref.id
                 WHERE ref.referred_by = p.id AND ct.type = 'game_fee'
                 AND ct.created_at >= DATE_TRUNC('year', NOW())), 0) as referred_spend_year,

                COALESCE((SELECT SUM(g.cost_per_player) FROM registrations r
                 JOIN games g ON g.id = r.game_id
                 WHERE r.player_id = p.id AND r.status = 'confirmed'
                 AND g.exclusivity = 'clm' AND g.game_status = 'completed'
                 AND g.game_date >= DATE_TRUNC('year', NOW())), 0)
                +
                COALESCE((SELECT SUM(gg.amount_paid) FROM game_guests gg
                 JOIN games g ON g.id = gg.game_id
                 WHERE gg.invited_by = p.id AND g.exclusivity = 'clm'
                 AND g.game_date >= DATE_TRUNC('year', NOW())), 0) as clm_revenue_year,

                -- FREE CREDITS: all time
                COALESCE((SELECT SUM(ct.amount) FROM credit_transactions ct
                 WHERE ct.player_id = p.id AND ct.type = 'free_credit'), 0) as free_credits,

                -- FREE CREDITS: last 3 months
                COALESCE((SELECT SUM(ct.amount) FROM credit_transactions ct
                 WHERE ct.player_id = p.id AND ct.type = 'free_credit'
                 AND ct.created_at >= NOW() - INTERVAL '3 months'), 0) as free_credits_3m,

                -- FREE CREDITS: calendar year
                COALESCE((SELECT SUM(ct.amount) FROM credit_transactions ct
                 WHERE ct.player_id = p.id AND ct.type = 'free_credit'
                 AND ct.created_at >= DATE_TRUNC('year', NOW())), 0) as free_credits_year,

                -- FEATURED PROFILE & SOCIALS
                COALESCE(p.is_featured, false) as is_featured,
                p.social_tiktok,
                p.social_instagram,
                p.social_youtube,
                p.social_facebook,
                COALESCE(p.position, 'outfield') as position,

                -- DISCIPLINE: all-time total points
                COALESCE((
                    SELECT SUM(dr.points) FROM discipline_records dr WHERE dr.player_id = p.id
                ), 0) as disc_points_total,

                -- DISCIPLINE: revolving — last 10 completed games + all manual (admin) entries
                COALESCE((
                    SELECT SUM(dr.points)
                    FROM discipline_records dr
                    WHERE dr.player_id = p.id
                    AND (dr.game_id IS NULL OR dr.game_id IN (
                        SELECT r.game_id FROM registrations r
                        JOIN games g2 ON g2.id = r.game_id
                        WHERE r.player_id = p.id AND r.status = 'confirmed'
                        AND g2.game_status = 'completed'
                        ORDER BY g2.game_date DESC LIMIT 10
                    ))
                ), 0) as disc_points_revolving,

                -- DISCIPLINE: most recent offense type
                (SELECT dr.offense_type FROM discipline_records dr
                 WHERE dr.player_id = p.id AND dr.game_id IS NOT NULL
                 ORDER BY dr.id DESC LIMIT 1) as last_offense

            FROM players p
            LEFT JOIN credits c ON c.player_id = p.id
            LEFT JOIN users u ON u.id = p.user_id
            ORDER BY p.squad_number NULLS LAST, p.full_name
            LIMIT 1500
        `);

        // All badges for the badge matrix headers
        const badgesResult = await pool.query('SELECT id, name, color, icon FROM badges ORDER BY name');

        // CLM totals (platform-wide) — all time, last 3 months, calendar year
        const clmTotals = await pool.query(`
            SELECT
                COALESCE(SUM(g.cost_per_player * sub.player_count + COALESCE(sub.guest_revenue, 0)), 0) as clm_total,
                COALESCE(SUM(CASE WHEN g.game_date >= NOW() - INTERVAL '3 months'
                    THEN g.cost_per_player * sub.player_count + COALESCE(sub.guest_revenue, 0) ELSE 0 END), 0) as clm_total_3m,
                COALESCE(SUM(CASE WHEN g.game_date >= DATE_TRUNC('year', NOW())
                    THEN g.cost_per_player * sub.player_count + COALESCE(sub.guest_revenue, 0) ELSE 0 END), 0) as clm_total_year
            FROM games g
            JOIN (
                SELECT r.game_id,
                    COUNT(*) as player_count,
                    (SELECT COALESCE(SUM(gg.amount_paid), 0) FROM game_guests gg WHERE gg.game_id = r.game_id) as guest_revenue
                FROM registrations r
                WHERE r.status = 'confirmed'
                GROUP BY r.game_id
            ) sub ON sub.game_id = g.id
            WHERE g.exclusivity = 'clm' AND g.game_status = 'completed'
        `);

        res.json({
            players: result.rows,
            allBadges: badgesResult.rows,
            clmTotals: clmTotals.rows[0] || { clm_total: 0, clm_total_3m: 0, clm_total_year: 0 }
        });
    } catch (error) {
        console.error('Error fetching admin players grid:', error);
        res.status(500).json({ error: 'Failed to fetch players grid data' });
    }
});

// GET /api/players/:playerId/ref-stats — referee profile stats (authenticated)
// BUG-05: was unauthenticated — any caller could enumerate referee PII by player ID
app.get('/api/players/:playerId/ref-stats', authenticateToken, async (req, res) => {
    const { playerId } = req.params;
    try {
        // Total confirmed ref appearances
        const apps = await pool.query(
            `SELECT COUNT(*) AS appearances
             FROM game_referees WHERE player_id = $1 AND status = 'confirmed'`,
            [playerId]
        );

        // All-time average across all games
        const allTime = await pool.query(
            `SELECT ROUND(AVG(rating), 1) AS avg_rating, COUNT(*) AS total_reviews
             FROM referee_reviews WHERE referee_player_id = $1`,
            [playerId]
        );

        // Last 5 game averages (one avg per game, then average those)
        const last5 = await pool.query(
            `SELECT ROUND(AVG(avg_per_game), 1) AS last5_avg
             FROM (
                 SELECT game_id, AVG(rating) AS avg_per_game
                 FROM referee_reviews
                 WHERE referee_player_id = $1
                 GROUP BY game_id
                 ORDER BY MAX(created_at) DESC
                 LIMIT 5
             ) sub`,
            [playerId]
        );

        res.json({
            appearances:   parseInt(apps.rows[0].appearances),
            avg_rating:    allTime.rows[0].avg_rating,
            total_reviews: parseInt(allTime.rows[0].total_reviews),
            last5_avg:     last5.rows[0].last5_avg
        });
    } catch (error) {
        console.error('Ref stats error:', error);
        res.status(500).json({ error: 'Failed to fetch referee stats' });
    }
});


// Must be defined before /api/players/:id to avoid route collision
app.get('/api/players/superadmin-id', authenticateToken, async (req, res) => {
    try {
        const result = await pool.query(
            `SELECT p.id FROM players p JOIN users u ON u.id = p.user_id WHERE u.role = 'superadmin' LIMIT 1`
        );
        if (result.rows.length === 0) return res.status(404).json({ error: 'Not found' });
        res.json({ id: result.rows[0].id });
    } catch (err) {
        console.error('superadmin-id error:', err);
        res.status(500).json({ error: 'Server error' });
    }
});

app.get('/api/players/:id', authenticateToken, playerLookupLimiter, async (req, res) => {
    try {
        const result = await pool.query(`
            SELECT p.*, c.balance as credits, u.email,
            (SELECT json_agg(json_build_object('id', b.id, 'name', b.name, 'color', b.color, 'icon', b.icon))
             FROM player_badges pb JOIN badges b ON pb.badge_id = b.id WHERE pb.player_id = p.id) as badges,
            COALESCE((SELECT SUM(dr.points) FROM discipline_records dr WHERE dr.player_id = p.id), 0) as disc_points_total,
            COALESCE((
                SELECT SUM(dr.points) FROM discipline_records dr
                WHERE dr.player_id = p.id
                AND (dr.game_id IS NULL OR dr.game_id IN (
                    SELECT r.game_id FROM registrations r
                    JOIN games g2 ON g2.id = r.game_id
                    WHERE r.player_id = p.id AND r.status = 'confirmed'
                    AND g2.game_status = 'completed'
                    ORDER BY g2.game_date DESC LIMIT 10
                ))
            ), 0) as disc_points_revolving,
            (SELECT dr.offense_type FROM discipline_records dr
             WHERE dr.player_id = p.id AND dr.game_id IS NOT NULL
             ORDER BY dr.id DESC LIMIT 1) as last_offense
            FROM players p
            LEFT JOIN credits c ON c.player_id = p.id
            LEFT JOIN users u ON u.id = p.user_id
            WHERE p.id = $1
        `, [req.params.id]);
        
        if (result.rows.length === 0) {
            return res.status(404).json({ error: 'Player not found' });
        }
        
        const player = result.rows[0];
        
        // Return different data based on viewer
        const isOwnProfile = player.user_id === req.user.userId;
        const isAdmin = req.user.role === 'admin' || req.user.role === 'superadmin';
        
        // Derive computed stats
        const apps = parseInt(player.total_appearances || 0);
        const wins = parseInt(player.total_wins || 0);
        const motm = parseInt(player.motm_wins || 0);
        const win_percent  = apps > 0 ? parseFloat((wins / apps * 100).toFixed(1)) : 0;
        const motm_percent = apps > 0 ? parseFloat((motm / apps * 100).toFixed(1)) : 0;

        // Derived: tournament wins and external game wins
        const tourneyResult = await pool.query(`
            SELECT COUNT(*) AS cnt FROM registrations r
            JOIN games g ON g.id = r.game_id
            JOIN team_players tp ON tp.player_id = r.player_id
            JOIN teams t ON t.id = tp.team_id AND t.game_id = g.id
            WHERE r.player_id = $1 AND r.status = 'confirmed'
              AND g.game_status = 'completed' AND g.team_selection_type = 'tournament'
              AND LOWER(g.winning_team) = LOWER(t.team_name)
        `, [player.id]);
        const extResult = await pool.query(`
            SELECT COUNT(*) AS cnt FROM registrations r
            JOIN games g ON g.id = r.game_id
            WHERE r.player_id = $1 AND r.status = 'confirmed'
              AND g.game_status = 'completed' AND g.team_selection_type = 'vs_external'
              AND LOWER(g.winning_team) = 'red'
        `, [player.id]);

        const tournament_wins   = parseInt(tourneyResult.rows[0].cnt) || 0;
        const external_game_wins = parseInt(extResult.rows[0].cnt) || 0;

        // Award counts — fetched for all viewers
        const awardsRes = await pool.query(
            `SELECT award_type, COUNT(*) AS cnt FROM game_awards WHERE recipient_player_id = $1 AND NOT removed_due_to_team_drop GROUP BY award_type`,
            [player.id]
        );
        const award_counts = {};
        for (const row of awardsRes.rows) award_counts[row.award_type] = parseInt(row.cnt);

        // FIX-105: compute draws + effective wins once — used by both owner/admin and public branches
        const total_draws = parseInt(player.total_draws || 0);
        const effective_wins = parseFloat((parseInt(player.total_wins || 0) + total_draws * 0.5).toFixed(1));
        const effective_win_percent = parseInt(player.total_appearances) > 0
            ? parseFloat((effective_wins / parseInt(player.total_appearances) * 100).toFixed(1))
            : 0;

        if (isOwnProfile || isAdmin) {
            res.json({ ...player, win_percent, motm_percent, tournament_wins, external_game_wins, award_counts,
                       total_draws, effective_wins, effective_win_percent });
        } else {
            // Public view — limited data per visibility matrix
            res.json({
                id:               player.id,
                alias:            player.alias,
                full_name:        player.full_name,
                squad_number:     player.squad_number,
                photo_url:        player.photo_url,
                reliability_tier: player.reliability_tier,
                total_appearances: player.total_appearances,
                total_wins:       player.total_wins,
                total_draws,              // FIX-105
                effective_wins,           // FIX-105
                effective_win_percent,    // FIX-105
                motm_wins:        player.motm_wins,
                overall_rating:   player.overall_rating,
                win_percent,
                motm_percent,
                tournament_wins,
                external_game_wins,
                award_counts,
                badges:           player.badges,
                ai_bio:           player.ai_bio || null,
                social_tiktok:    player.social_tiktok,
                social_instagram: player.social_instagram,
                social_youtube:   player.social_youtube,
                social_facebook:  player.social_facebook,
            });
        }
    } catch (error) {
        console.error('Error fetching player:', error);
        res.status(500).json({ error: 'Failed to fetch player' });
    }
});

// Get player's games (upcoming and completed)
app.get('/api/players/:playerId/games', authenticateToken, async (req, res) => {
    try {
        const { playerId } = req.params;

        // CRIT-9: Prevent IDOR — only the player themselves or an admin can view game history
        const isAdmin = req.user.role === 'admin' || req.user.role === 'superadmin';
        if (!isAdmin && req.user.playerId !== playerId) {
            return res.status(403).json({ error: 'You can only view your own game history' });
        }
        // Get upcoming games (registered and not completed)
        const upcomingResult = await pool.query(`
            SELECT g.id, g.game_date, g.cost_per_player, g.max_players, g.format, g.game_url,
                   v.name as venue_name,
                   ((SELECT COUNT(*) FROM registrations WHERE game_id = g.id AND status IN ('confirmed', 'rsvp')) + (SELECT COUNT(*) FROM game_guests WHERE game_id = g.id)) as current_players
            FROM registrations r
            JOIN games g ON g.id = r.game_id
            LEFT JOIN venues v ON v.id = g.venue_id
            WHERE r.player_id = $1 
            AND r.status = 'confirmed'
            AND g.game_status IN ('available', 'confirmed')
            AND g.game_date >= CURRENT_TIMESTAMP
            ORDER BY g.game_date ASC
        `, [playerId]);
        
        // Get completed games
        const completedResult = await pool.query(`
            SELECT g.id, g.game_date, g.game_url, g.winning_team,
                   g.score_team_a, g.score_team_b,
                   v.name as venue_name,
                   -- Did this player win?
                   CASE WHEN g.winning_team IS NOT NULL AND g.winning_team != '' AND EXISTS (
                     SELECT 1 FROM team_players tp
                     JOIN teams t ON t.id = tp.team_id
                     WHERE tp.player_id = $1 AND t.game_id = g.id
                       AND LOWER(t.team_name) = LOWER(g.winning_team)
                   ) THEN true ELSE false END AS won,
                   -- Was this player MOTM?
                   (g.motm_winner_id = $1) AS is_motm,
                   -- Position played
                   r.position_preference AS position_played
            FROM registrations r
            JOIN games g ON g.id = r.game_id
            LEFT JOIN venues v ON v.id = g.venue_id
            WHERE r.player_id = $1
            AND r.status = 'confirmed'
            AND g.game_status = 'completed'
            ORDER BY g.game_date DESC
            LIMIT 20
        `, [playerId]);
        
        res.json({
            upcomingGames: upcomingResult.rows,
            completedGames: completedResult.rows
        });
        
    } catch (error) {
        console.error('Get player games error:', error);
        res.status(500).json({ error: 'Failed to get player games' });
    }
});

// GET /api/players/me/pending-votes
// Returns dashboard-ready data for the "Awards" slot on the home dashboard.
// Two buckets:
//   - pending: games I played in where awards_open=true AND I haven't voted yet
//   - results: games I played in where awards have been confirmed (any time)
// Tapping the dashboard slot opens the most recent game in whichever bucket is
// populated (pending takes precedence). When both buckets are empty the client
// falls back to showing Recent Games in that same slot. (Web47)
app.get('/api/players/me/pending-votes', authenticateToken, async (req, res) => {
    try {
        const playerId = req.user.playerId;

        // Bucket 1: games with awards currently open where I haven't cast any vote
        const pendingResult = await pool.query(`
            SELECT g.id            AS game_id,
                   g.game_url      AS game_url,
                   g.game_date     AS game_date,
                   v.name          AS venue_name,
                   COALESCE((SELECT COUNT(*) FROM game_award_votes gav
                             WHERE gav.game_id = g.id AND gav.voter_player_id = $1), 0) AS my_vote_count
            FROM games g
            JOIN registrations r ON r.game_id = g.id
            LEFT JOIN venues v ON v.id = g.venue_id
            WHERE r.player_id = $1
              AND r.status = 'confirmed'
              AND g.awards_open = true
              AND (g.awards_close_at IS NULL OR g.awards_close_at > NOW())
            ORDER BY g.game_date DESC
            LIMIT 20
        `, [playerId]);

        const pending = pendingResult.rows
            .filter(r => parseInt(r.my_vote_count) === 0)
            .map(r => ({
                game_id:    r.game_id,
                game_url:   r.game_url,
                game_date:  r.game_date,
                venue_name: r.venue_name,
            }));

        // Bucket 2: games with awards confirmed that I was in. We look at
        // game_awards.created_at — records are inserted when the awards close/resolve.
        // Fallback: if no created_at field ordering gives inconsistent results, use
        // games.awards_close_at as a proxy for "recently announced".
        // Web51: 48h time filter removed — we now surface all recent award results
        // (LIMIT 5 caps the list; the mobile app (app13 HomeScreen) shares this feed).
        const resultsResult = await pool.query(`
            SELECT DISTINCT g.id   AS game_id,
                   g.game_url      AS game_url,
                   g.game_date     AS game_date,
                   v.name          AS venue_name,
                   g.awards_close_at AS awards_close_at,
                   (SELECT COUNT(*) FROM game_awards ga WHERE ga.game_id = g.id AND NOT ga.removed_due_to_team_drop) AS award_count
            FROM games g
            JOIN registrations r ON r.game_id = g.id
            LEFT JOIN venues v ON v.id = g.venue_id
            JOIN game_awards ga2 ON ga2.game_id = g.id
            WHERE r.player_id = $1
              AND r.status = 'confirmed'
              AND g.awards_open = false
              AND g.awards_close_at IS NOT NULL
              -- 48-hour filter removed (user request): show recent award results regardless of age
            ORDER BY g.awards_close_at DESC
            LIMIT 5
        `, [playerId]);

        const results = resultsResult.rows.map(r => ({
            game_id:         r.game_id,
            game_url:        r.game_url,
            game_date:       r.game_date,
            venue_name:      r.venue_name,
            awards_close_at: r.awards_close_at,
            award_count:     parseInt(r.award_count || 0),
        }));

        res.json({ pending, results });
    } catch (error) {
        console.error('Get pending votes error:', error);
        res.status(500).json({ error: 'Failed to get pending votes' });
    }
});

// POST /api/analytics/vote-widget-tap
// Logs a tap event on the dashboard smart slot. Used to measure engagement with
// the votes/results/recent cascade. Fire-and-forget from the client — we always
// return 200 to avoid blocking the user flow even if logging fails.
// Body: { slot_mode: 'votes'|'results'|'recent'|'empty', game_id?: uuid, platform?: 'web'|'mobile' }
app.post('/api/analytics/vote-widget-tap', authenticateToken, async (req, res) => {
    try {
        const { slot_mode, game_id, platform } = req.body || {};
        const validModes = ['votes', 'results', 'recent', 'empty'];
        const mode = validModes.includes(slot_mode) ? slot_mode : 'empty';
        const plat = (platform === 'mobile' || platform === 'web') ? platform : 'web';
        // game_id is optional and only validated as a string — if it's bad we just
        // store null rather than rejecting the entire event.
        const gid = (typeof game_id === 'string' && game_id.length >= 32 && game_id.length <= 40) ? game_id : null;
        await pool.query(
            `INSERT INTO vote_widget_taps (player_id, slot_mode, game_id, platform, created_at)
             VALUES ($1, $2, $3, $4, NOW())`,
            [req.user.playerId, mode, gid, plat]
        );
        res.json({ ok: true });
    } catch (error) {
        // Silent failure — analytics should never break the user flow
        console.warn('vote-widget-tap log failed:', error.message);
        res.json({ ok: false });
    }
});

app.put('/api/players/me', authenticateToken, async (req, res) => {
    const client = await pool.connect();
    try {
        const { fullName, alias, email, phone, currentPassword } = req.body;

        // FIX-078: Guard against undefined/null fullName (was crashing with TypeError)
        if (!fullName?.trim()) return res.status(400).json({ error: 'Full name is required' });

        // FIX-079: Field length validation
        if (fullName.trim().length > 100) return res.status(400).json({ error: 'Full name: max 100 characters' });
        if (alias?.length > 50) return res.status(400).json({ error: 'Alias: max 50 characters' });
        if (phone?.length > 20) return res.status(400).json({ error: 'Phone: max 20 characters' });
        
        // Split name into first and last
        const nameParts = fullName.trim().split(/\s+/);
        const firstName = nameParts[0];
        const lastName = nameParts.length > 1 ? nameParts.slice(1).join(' ') : firstName;

        // FIX-014: Check email uniqueness before updating
        if (email) {
            const emailCheck = await pool.query(
                'SELECT id FROM users WHERE LOWER(email) = LOWER($1) AND id != $2',
                [email, req.user.userId]
            );
            if (emailCheck.rows.length > 0) {
                return res.status(400).json({ error: 'Email already in use by another account' });
            }

            // N5 removed — password not required to change email; session auth is sufficient
        }

        // N10: Fetch old email before update so we can alert it afterwards
        const oldEmailRow = await pool.query('SELECT email FROM users WHERE id = $1', [req.user.userId]);
        const oldEmail = oldEmailRow.rows[0]?.email || null;

        // FIX-091: Wrap both UPDATEs in a transaction — prevents partial profile update
        await client.query('BEGIN');
        
        // Update player
        await client.query(
            `UPDATE players SET 
             full_name = $1, 
             first_name = $2, 
             last_name = $3, 
             alias = $4, 
             phone = $5, 
             updated_at = CURRENT_TIMESTAMP
             WHERE id = $6`,
            [fullName.trim(), firstName, lastName, alias?.trim(), phone?.trim(), req.user.playerId]
        );
        
        // Update email in users table
        if (email) {
            await client.query(
                'UPDATE users SET email = $1 WHERE id = $2',
                [email.toLowerCase(), req.user.userId]
            );
        }

        await client.query('COMMIT');
        res.json({ message: 'Profile updated successfully' });

        setImmediate(async () => {
            await auditLog(pool, req.user.playerId, 'account_updated', req.user.playerId,
                `name:${fullName?.trim()} alias:${alias?.trim() || '-'} email:${email || '-'} phone:${phone ? 'updated' : '-'}`);

            // N10: Alert old email address when email is changed — lets player spot unauthorised takeover
            if (email && oldEmail && email.toLowerCase() !== oldEmail.toLowerCase()) {
                try {
                    await emailTransporter.sendMail({
                        from: '"TotalFooty" <totalfooty19@gmail.com>',
                        to: oldEmail,
                        subject: '⚠️ Your TotalFooty email address was changed',
                        html: wrapEmailHtml(`
                            <p style="color:#ccc;font-size:15px;margin:0 0 16px;">
                                The email address on your TotalFooty account was just changed to
                                <strong>${htmlEncode(email)}</strong>.
                            </p>
                            <p style="color:#ccc;font-size:15px;margin:0 0 16px;">
                                If you made this change, you can ignore this message.
                            </p>
                            <p style="color:#ff4444;font-size:15px;margin:0;">
                                If you did <strong>not</strong> make this change, contact us immediately at
                                <a href="mailto:totalfooty19@gmail.com" style="color:#ff4444;">totalfooty19@gmail.com</a>.
                            </p>
                        `)
                    });
                } catch (e) {
                    console.error('Email change alert failed (non-critical):', e.message);
                }
            }
        });
    } catch (error) {
        await client.query('ROLLBACK').catch(() => {});
        console.error('Update profile error:', error);
        res.status(500).json({ error: 'Update failed' });
    } finally {
        client.release();
    }
});

// ═══════════════════════════════════════════════════════════════════════════
// PREFERENCES — player-level settings hub (Batch 2 of unified deploy)
// ═══════════════════════════════════════════════════════════════════════════
// Required DDL (run once in production before deploying):
//
//   ALTER TABLE players ADD COLUMN IF NOT EXISTS preferred_locations TEXT DEFAULT NULL;
//   ALTER TABLE players ADD COLUMN IF NOT EXISTS default_positions_11aside TEXT DEFAULT NULL;
//   ALTER TABLE players ADD COLUMN IF NOT EXISTS default_position_areas TEXT DEFAULT NULL;
//   ALTER TABLE players ADD COLUMN IF NOT EXISTS has_seen_help_guide BOOLEAN NOT NULL DEFAULT FALSE;
//   -- Veteran seed (from help-guide audit — avoid surprise tour launch for 700 existing players):
//   UPDATE players SET has_seen_help_guide = TRUE
//     WHERE id IN (SELECT DISTINCT player_id FROM registrations WHERE player_id IS NOT NULL);
//
//   -- DM notification preference (per-player opt-out for new-message pushes/toasts).
//   -- Default TRUE so existing users keep getting notified — they explicitly opt out.
//   ALTER TABLE players ADD COLUMN IF NOT EXISTS dm_notifications_enabled BOOLEAN NOT NULL DEFAULT TRUE;
//
//   -- FIX-271: Superadmin can mute a player from sending DMs platform-wide.
//   --   messaging_blocked_at:    when the current mute started (NULL = not currently muted)
//   --   messaging_blocked_until: when the mute auto-expires (NULL while blocked_at IS NOT NULL = forever)
//   --   messaging_block_reason:  optional admin note shown back to the player in the 403 detail
//   --   last_dm_spree_alert_at:  date of last "3+ unique recipients" alert sent to superadmin for this player.
//   --                            Throttles the auto-alert to at most once per UTC day per sender.
//   -- Currently-blocked check: messaging_blocked_at IS NOT NULL AND
//   --   (messaging_blocked_until IS NULL OR messaging_blocked_until > now()).
//   ALTER TABLE players ADD COLUMN IF NOT EXISTS messaging_blocked_at    TIMESTAMPTZ;
//   ALTER TABLE players ADD COLUMN IF NOT EXISTS messaging_blocked_until TIMESTAMPTZ;
//   ALTER TABLE players ADD COLUMN IF NOT EXISTS messaging_block_reason  TEXT;
//   ALTER TABLE players ADD COLUMN IF NOT EXISTS last_dm_spree_alert_at  DATE;
//
//   -- FIX-274: voter reliability tracking + recalibration history.
//   -- voter_trust_score: 0.0..1.0 — fraction of this voter's recalibration
//   --   contributions that have NOT been reversed by an admin. Default 1.0
//   --   (full trust until proven wrong). Used to:
//   --     1) downweight unreliable voters in the substantiation score
//   --     2) drive the voter-reliability dashboard
//   --     3) (future) ignore votes from voters whose trust drops below threshold
//   -- voter_total_votes: lifetime count of votes this player has cast that
//   --   contributed to an applied recalibration.
//   -- voter_reversed_votes: subset of voter_total_votes whose recalibration
//   --   was later reversed by admin. trust = 1 - (reversed / total).
//   ALTER TABLE players ADD COLUMN IF NOT EXISTS voter_trust_score      NUMERIC(4,3) NOT NULL DEFAULT 1.000;
//   ALTER TABLE players ADD COLUMN IF NOT EXISTS voter_total_votes      INTEGER      NOT NULL DEFAULT 0;
//   ALTER TABLE players ADD COLUMN IF NOT EXISTS voter_reversed_votes   INTEGER      NOT NULL DEFAULT 0;
//
//   -- Recalibration history — per-event record of what was applied, so the
//   -- admin can reverse a specific recalibration and the system can attribute
//   -- the reversal back to the voters who contributed.
//   --   subject_player_id: who got recalibrated
//   --   delta_ovr:         signed change applied to overall_rating
//   --   stat_changes:      JSONB array of {column, oldVal, newVal}
//   --   voter_ids:         JSONB array of voter player_ids who contributed
//   --   suspicion_flag:    snapshot of subject's flag at time of recal
//   --   movement_magnitude: the threshold tier the votes hit
//   --   substantiation_score: 0.0..1.0 score from the falsification check
//   --   status:           'applied' (live), 'reversed' (undone), 'pending' (queue)
//   --   reversed_at:      timestamp of reversal
//   --   reversed_by:      admin player_id who reversed it
//   CREATE TABLE IF NOT EXISTS rating_recalibration_history (
//     id                   SERIAL PRIMARY KEY,
//     subject_player_id    UUID    NOT NULL REFERENCES players(id) ON DELETE CASCADE,
//     delta_ovr            INTEGER NOT NULL,
//     stat_changes         JSONB   NOT NULL DEFAULT '[]'::jsonb,
//     voter_ids            JSONB   NOT NULL DEFAULT '[]'::jsonb,
//     suspicion_flag       TEXT,
//     movement_magnitude   INTEGER,
//     substantiation_score NUMERIC(4,3),
//     status               TEXT NOT NULL DEFAULT 'applied',
//     created_at           TIMESTAMPTZ NOT NULL DEFAULT NOW(),
//     reversed_at          TIMESTAMPTZ,
//     reversed_by          UUID REFERENCES players(id) ON DELETE SET NULL
//   );
//   CREATE INDEX IF NOT EXISTS idx_rrh_subject ON rating_recalibration_history(subject_player_id, created_at DESC);
//   CREATE INDEX IF NOT EXISTS idx_rrh_status  ON rating_recalibration_history(status, created_at DESC);
//
//   -- system_settings keys used by FIX-274 (no schema change; just runtime config):
//   --   'rating_auto_apply_enabled' = 'true' | 'false' (default 'false' → suggestions queue)
//   --   'rating_substantiation_strict' = 'true' | 'false' (default 'false' → warnings only)
//
//   -- FIX-275: self-correcting model — overcorrection detection + magnitude
//   -- damping + manual-admin edit tracking. Builds on FIX-274's history table.
//   --
//   -- 1) Add a `source` column so rating_recalibration_history can distinguish
//   --    system-driven recalibrations from admin manual stat-edits.
//   ALTER TABLE rating_recalibration_history
//     ADD COLUMN IF NOT EXISTS source TEXT NOT NULL DEFAULT 'system';
//   --    Allowed values: 'system', 'manual_admin', 'admin_reversal', 'admin_approved'.
//   --    The (NOT NULL DEFAULT 'system') backfills existing rows correctly —
//   --    every row that was pre-FIX-275 IS a system recalibration.
//   --
//   -- 2) Track the player's appearance counter AT the moment of the move so
//   --    the followup window can be measured in games-played, not days.
//   ALTER TABLE rating_recalibration_history
//     ADD COLUMN IF NOT EXISTS appearances_at_recal INTEGER;
//   --
//   -- 3) Correction-link table: when a later move (recalibration or manual
//   --    admin edit) goes in the OPPOSITE direction to a prior move within
//   --    the player's followup window, we record the link here. This is the
//   --    "this corrected that" relationship — drives the overcorrection-rate
//   --    metric + per-player stability + per-voter accuracy.
//   --    correction_magnitude: how much of the original was undone (in OVR points).
//   --                          partial (1 of 3 reversed) → 1.0. full reversal → original magnitude.
//   --    overcorrection_ratio: correction_magnitude / abs(original.delta_ovr). 1.0 = full reversal.
//   --                          >1.0 = the correction OVERSHOT the other way.
//   CREATE TABLE IF NOT EXISTS rating_correction_links (
//     id                     SERIAL PRIMARY KEY,
//     original_recal_id      INTEGER NOT NULL REFERENCES rating_recalibration_history(id) ON DELETE CASCADE,
//     correction_recal_id    INTEGER NOT NULL REFERENCES rating_recalibration_history(id) ON DELETE CASCADE,
//     subject_player_id      UUID    NOT NULL REFERENCES players(id) ON DELETE CASCADE,
//     games_between          INTEGER NOT NULL DEFAULT 0,
//     correction_magnitude   INTEGER NOT NULL,
//     overcorrection_ratio   NUMERIC(5,3) NOT NULL,
//     created_at             TIMESTAMPTZ NOT NULL DEFAULT NOW(),
//     UNIQUE (original_recal_id, correction_recal_id)
//   );
//   CREATE INDEX IF NOT EXISTS idx_rcl_subject  ON rating_correction_links(subject_player_id, created_at DESC);
//   CREATE INDEX IF NOT EXISTS idx_rcl_original ON rating_correction_links(original_recal_id);
//
//   -- 4) Per-player stability score: how often THIS player's recalibrations
//   --    end up being corrected. Used to dampen future moves on that player.
//   --    NULL = no recalibration history yet (full confidence). 1.0 = none
//   --    have been corrected. 0.0 = every single one was reversed.
//   ALTER TABLE players ADD COLUMN IF NOT EXISTS recalibration_stability NUMERIC(4,3);
//
//   -- 5) Per-voter accuracy score: like voter_trust_score but graded by the
//   --    MAGNITUDE of overcorrection rather than binary. A voter who
//   --    contributed to a "−3 then +2" recalibration scores worse than one
//   --    whose vote stuck cleanly. Computed cumulatively.
//   ALTER TABLE players ADD COLUMN IF NOT EXISTS voter_accuracy_score NUMERIC(4,3) NOT NULL DEFAULT 1.000;
//
//   -- system_settings keys used by FIX-275 (runtime config, no schema change):
//   --   'rating_overcorrection_damping_enabled' = 'true' | 'false' (default 'true')
//   --   'rating_global_damping_factor' = 1.0 (recomputed nightly based on
//   --                                         last-90d overcorrection rate)
//
//   -- Late-dropout protection: when a player self-drops within 2 hours of kick-off,
//   -- discipline points are auto-applied + the player can leave a reason. Admin can
//   -- review the reason and DELETE the record if the excuse is reasonable.
//   ALTER TABLE discipline_records ADD COLUMN IF NOT EXISTS notes TEXT;
//
//   -- Comms campaigns: send mass emails with claim links.
//   -- Two modes: 'game_signup' (claim → auto-register player into a specific game,
//   -- comped) and 'credit_grant' (claim → free credit added to balance).
//   CREATE TABLE IF NOT EXISTS comms_campaigns (
//     id              SERIAL PRIMARY KEY,
//     created_by      INTEGER REFERENCES players(id) ON DELETE SET NULL,
//     campaign_type   TEXT NOT NULL CHECK (campaign_type IN ('game_signup','credit_grant')),
//     subject         TEXT NOT NULL,
//     body_template   TEXT NOT NULL,                  -- supports {firstName} {claimUrl} {expiryDate}
//     gift_amount     NUMERIC(10,2),                  -- credit_grant mode: £ amount; null for game_signup
//     gift_game_id    INTEGER REFERENCES games(id) ON DELETE SET NULL, -- game_signup mode
//     expires_at      TIMESTAMP NOT NULL,
//     created_at      TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
//     recipient_count INTEGER DEFAULT 0,
//     claim_count     INTEGER DEFAULT 0
//   );
//   CREATE TABLE IF NOT EXISTS comms_recipients (
//     id                SERIAL PRIMARY KEY,
//     campaign_id       INTEGER NOT NULL REFERENCES comms_campaigns(id) ON DELETE CASCADE,
//     player_id         INTEGER REFERENCES players(id) ON DELETE SET NULL,
//     email_to          TEXT NOT NULL,
//     claim_token       TEXT NOT NULL UNIQUE,
//     email_sent_at     TIMESTAMP,
//     email_send_error  TEXT,
//     claimed_at        TIMESTAMP,
//     claim_outcome     TEXT,                         -- 'credited' | 'registered' | 'expired' | 'game_full' | 'duplicate'
//     created_at        TIMESTAMP DEFAULT CURRENT_TIMESTAMP
//   );
//   CREATE INDEX IF NOT EXISTS idx_comms_recipients_token ON comms_recipients(claim_token);
//   CREATE INDEX IF NOT EXISTS idx_comms_recipients_campaign ON comms_recipients(campaign_id);
//
//   CREATE TABLE IF NOT EXISTS player_favourite_series (
//     id          SERIAL PRIMARY KEY,
//     player_id   INTEGER NOT NULL REFERENCES players(id) ON DELETE CASCADE,
//     series_id   INTEGER NOT NULL REFERENCES game_series(id) ON DELETE CASCADE,
//     created_at  TIMESTAMPTZ DEFAULT NOW(),
//     UNIQUE (player_id, series_id)
//   );
//   CREATE INDEX IF NOT EXISTS idx_pfs_player ON player_favourite_series(player_id);
//   CREATE INDEX IF NOT EXISTS idx_pfs_series ON player_favourite_series(series_id);
//
// ═══════════════════════════════════════════════════════════════════════════
// GUEST REVAMP — per-game guest stats (Batch 8)
// ═══════════════════════════════════════════════════════════════════════════
//
//   ALTER TABLE game_guests ADD COLUMN IF NOT EXISTS relative_rating        INTEGER NULL;
//   ALTER TABLE game_guests ADD COLUMN IF NOT EXISTS position_classification TEXT NULL;
//   ALTER TABLE game_guests ADD COLUMN IF NOT EXISTS defending_rating  INTEGER DEFAULT 0;
//   ALTER TABLE game_guests ADD COLUMN IF NOT EXISTS strength_rating   INTEGER DEFAULT 0;
//   ALTER TABLE game_guests ADD COLUMN IF NOT EXISTS fitness_rating    INTEGER DEFAULT 0;
//   ALTER TABLE game_guests ADD COLUMN IF NOT EXISTS pace_rating       INTEGER DEFAULT 0;
//   ALTER TABLE game_guests ADD COLUMN IF NOT EXISTS shooting_rating   INTEGER DEFAULT 0;
//   ALTER TABLE game_guests ADD COLUMN IF NOT EXISTS assisting_rating  INTEGER DEFAULT 0;
//   ALTER TABLE game_guests ADD COLUMN IF NOT EXISTS decisions_rating  INTEGER DEFAULT 0;
//   ALTER TABLE game_guests ADD COLUMN IF NOT EXISTS goalkeeper_rating INTEGER DEFAULT 0;
//   ALTER TABLE game_guests ADD COLUMN IF NOT EXISTS is_admin_override BOOLEAN DEFAULT FALSE;
//   ALTER TABLE game_guests ADD COLUMN IF NOT EXISTS derived_from_parent_ovr INTEGER NULL;
//
// ═══════════════════════════════════════════════════════════════════════════
// BEEF SEMANTIC FLIP — wipe existing beef rows (Batch 8)
// ═══════════════════════════════════════════════════════════════════════════
// Legacy beef rows were entered under "keep apart" meaning. New semantic is
// "keep together". Wipe the table once before the algorithm flip takes effect.
// ONE-OFF — do NOT re-run on subsequent deploys (beef rows will accumulate
