// ════════════════════════════════════════════════════════════════════════════
// A4 DASHBOARD-V2 ENDPOINTS — Region slider + recent games (Mine/All)
// ════════════════════════════════════════════════════════════════════════════
// These are the canonical endpoints for the new dashboard. Existing dashboard
// endpoints (e.g. /api/games) remain untouched so the live dashboard keeps
// working until v2 is confirmed and replaces it.
//
// Region semantics: matches _PREFS_ALLOWED_LOCATIONS — Coventry, Birmingham,
// Leamington & Warwick, Nuneaton, Manchester. 'ALL' returns all regions
// (used as the brand-new-player default).
//
// Tier visibility: bronze=24h ahead, silver=7d, gold=28d, white/black=banned.
// Admin override: admins see everything regardless of tier.

// ── Helper: resolve player's effective region for the slider ────────────────
// Decision (A4): default to ALL regions if region_code is NULL/empty.
// region_code is the primary home region (single value, set in Preferences).
// preferred_locations is the multi-region preference list — we use it as a
// fallback only if region_code is unset (more permissive).
function _resolveSliderRegion(player, requestedRegion) {
    // Explicit override from query string takes priority (e.g. user picked from a region dropdown)
    if (requestedRegion && _PREFS_ALLOWED_LOCATIONS.has(requestedRegion)) {
        return { region: requestedRegion, source: 'requested' };
    }
    if (requestedRegion === 'ALL') {
        return { region: 'ALL', source: 'requested' };
    }
    // Player has a primary region set
    if (player.region_code && _PREFS_ALLOWED_LOCATIONS.has(player.region_code)) {
        return { region: player.region_code, source: 'profile' };
    }
    // Brand-new player: default to ALL regions
    return { region: 'ALL', source: 'default' };
}

// ── GET /api/dashboard/region-slider ────────────────────────────────────────
// Returns chronological games for a region, with both upcoming (next N) and
// recently-completed (last N). The frontend renders these as a single slider
// where left of the cursor = past games, right = upcoming.
//
// Query params:
//   ?region=Coventry|...|ALL    Override player's default region
//   ?upcoming=20                 How many upcoming games to fetch (default 20, max 50)
//   ?recent=20                   How many recently-completed games (default 20, max 50)
//
// Response:
//   {
//     region: 'Coventry' | 'ALL',
//     region_source: 'profile' | 'default' | 'requested',
//     tier_visibility_hours: 168,       // null if admin (no limit)
//     hit_tier_limit: false,            // true if upcoming was truncated by tier
//     games_completed: [...],           // descending date (most recent first)
//     games_upcoming: [...],            // ascending date (next first)
//   }
app.get('/api/dashboard/region-slider', authenticateToken, async (req, res) => {
    try {
        const playerRow = await pool.query(
            `SELECT region_code, reliability_tier
             FROM players WHERE id = $1`,
            [req.user.playerId]
        );
        const player = playerRow.rows[0] || {};
        const tier = player.reliability_tier || 'silver';
        const isAdmin = req.user.role === 'admin' || req.user.role === 'superadmin';

        // Resolve region (priority: explicit query > profile > default ALL)
        const requestedRegion = req.query.region ? String(req.query.region) : null;
        const { region, source: regionSource } = _resolveSliderRegion(player, requestedRegion);

        // Tier visibility window in hours
        let hoursAhead = 168; // silver default = 7 days
        if (tier === 'gold') hoursAhead = 28 * 24;       // 28 days
        if (tier === 'bronze') hoursAhead = 24;          // 1 day
        if (tier === 'white' || tier === 'black') hoursAhead = 0;
        // Admins bypass tier
        const effectiveHoursAhead = isAdmin ? null : hoursAhead;

        // Limits (clamped)
        const upcomingLimit = Math.min(50, Math.max(1, parseInt(req.query.upcoming) || 20));
        const recentLimit   = Math.min(50, Math.max(1, parseInt(req.query.recent)   || 20));

        // Region filter clause — 'ALL' = no filter
        const regionClause = (region === 'ALL') ? '' : 'AND v.region = $2';
        const baseParams   = (region === 'ALL') ? [req.user.playerId] : [req.user.playerId, region];

        // Exclusivity badge visibility — match /api/games behaviour
        let badgeFilter = '';
        if (!isAdmin) {
            // Check player's badges
            const badges = await pool.query(`
                SELECT b.name FROM player_badges pb
                JOIN badges b ON b.id = pb.badge_id
                WHERE pb.player_id = $1 AND b.name IN ('TF All Star','CLM','Misfits')`,
                [req.user.playerId]
            );
            const badgeNames = new Set(badges.rows.map(r => r.name));
            const exclusions = [];
            if (!badgeNames.has('TF All Star')) exclusions.push("(g.exclusivity IS NULL OR g.exclusivity != 'allstars')");
            if (!badgeNames.has('CLM'))         exclusions.push("(g.exclusivity IS NULL OR g.exclusivity != 'clm')");
            if (!badgeNames.has('Misfits'))     exclusions.push("(g.exclusivity IS NULL OR g.exclusivity != 'misfits')");
            badgeFilter = exclusions.length ? 'AND ' + exclusions.join(' AND ') : '';
        }

        // Tier window clause for upcoming
        const tierClause = (effectiveHoursAhead === null)
            ? ''
            : (effectiveHoursAhead === 0)
                ? 'AND 1 = 0'
                : `AND g.game_date <= CURRENT_TIMESTAMP + INTERVAL '${effectiveHoursAhead} hours'`;

        // Common SELECT fields (kept lean for slider — matches what game cards need)
        const selectFields = `
            g.id, g.game_url, g.game_date, g.game_status, g.format, g.cost_per_player,
            g.exclusivity, g.star_rating, g.star_rating_locked, g.team_selection_type,
            g.max_players, g.teams_generated,
            v.name AS venue_name, v.region AS venue_region,
            v.background_image_filename AS venue_background_image, v.photo_url AS venue_photo,
            ((SELECT COUNT(*) FROM registrations WHERE game_id = g.id AND status = 'confirmed')
             + (SELECT COUNT(*) FROM game_guests WHERE game_id = g.id)) AS current_players,
            ROUND((SELECT AVG(rating) FROM (
                       SELECT CASE WHEN UPPER(TRIM(r.position_preference)) = 'GK'
                                   THEN NULLIF(p.goalkeeper_rating, 0)
                                   ELSE p.overall_rating END AS rating
                       FROM registrations r JOIN players p ON p.id = r.player_id
                       WHERE r.game_id = g.id AND r.status IN ('confirmed', 'rsvp') /* FIX-315: include RSVPs in live_avg_ovr */
                       UNION ALL
                       SELECT CASE WHEN gg.position_classification = 'gk'
                                   THEN NULLIF(gg.goalkeeper_rating, 0)
                                   ELSE gg.overall_rating END AS rating
                       FROM game_guests gg WHERE gg.game_id = g.id
                   ) ratings WHERE rating IS NOT NULL)::numeric, 1) AS live_avg_ovr,
            EXISTS(SELECT 1 FROM registrations WHERE game_id = g.id AND player_id = $1) AS is_registered`;

        // Upcoming games — ascending (next first)
        const upcomingRows = await pool.query(`
            SELECT ${selectFields}
            FROM games g
            LEFT JOIN venues v ON v.id = g.venue_id
            WHERE g.game_status IN ('available','confirmed')
              AND g.game_date >= CURRENT_TIMESTAMP
              ${regionClause}
              ${tierClause}
              ${badgeFilter}
            ORDER BY g.game_date ASC
            LIMIT ${upcomingLimit}`,
            baseParams
        );

        // Determine if tier limited the upcoming count.
        // We re-query without the tier clause to count what would have been visible.
        // Cheap query (count only). Uses its own params array since this query only
        // references region (no player_id needed for a simple visible-count check).
        let hitTierLimit = false;
        if (!isAdmin && effectiveHoursAhead !== null && effectiveHoursAhead > 0) {
            const broaderRegionClause = (region === 'ALL') ? '' : 'AND v.region = $1';
            const broaderParams       = (region === 'ALL') ? [] : [region];
            const broaderCount = await pool.query(`
                SELECT COUNT(*) AS n
                FROM games g
                LEFT JOIN venues v ON v.id = g.venue_id
                WHERE g.game_status IN ('available','confirmed')
                  AND g.game_date >= CURRENT_TIMESTAMP
                  ${broaderRegionClause}
                  ${badgeFilter}`,
                broaderParams
            );
            const broader = parseInt(broaderCount.rows[0]?.n || 0);
            hitTierLimit = broader > upcomingRows.rows.length;
        }

        // Recently-completed games — descending (most recent first)
        // FIX-238: also include 'confirmed' games whose date passed but haven't
        // been marked completed (limbo state). Mirrors V2 timeline behaviour.
        const completedRows = await pool.query(`
            SELECT ${selectFields}
            FROM games g
            LEFT JOIN venues v ON v.id = g.venue_id
            WHERE g.game_date < CURRENT_TIMESTAMP
              AND g.game_status IN ('completed','confirmed')
              ${regionClause}
              ${badgeFilter}
            ORDER BY g.game_date DESC
            LIMIT ${recentLimit}`,
            baseParams
        );

        res.json({
            region,
            region_source: regionSource,
            tier,
            tier_visibility_hours: effectiveHoursAhead,
            hit_tier_limit: hitTierLimit,
            games_completed: completedRows.rows,
            games_upcoming: upcomingRows.rows,
        });
    } catch (error) {
        console.error('GET /api/dashboard/region-slider error:', error.message);
        res.status(500).json({ error: 'Failed to load region slider' });
    }
});


// ── GET /api/dashboard/recent-games?scope=mine|all ──────────────────────────
// Returns recently-completed games for the merged Recent/Completed carousel.
// scope=mine → only games this player participated in (default)
// scope=all  → site-wide recent completed games
//
// Response:
//   {
//     scope: 'mine' | 'all',
//     games: [...]
//   }
app.get('/api/dashboard/recent-games', authenticateToken, async (req, res) => {
    try {
        const scope = (req.query.scope === 'all') ? 'all' : 'mine';
        const limit = Math.min(20, Math.max(1, parseInt(req.query.limit) || 10));
        const isAdmin = req.user.role === 'admin' || req.user.role === 'superadmin';

        // Same exclusivity badge filter as the slider (only relevant for scope=all)
        let badgeFilter = '';
        if (!isAdmin && scope === 'all') {
            const badges = await pool.query(`
                SELECT b.name FROM player_badges pb
                JOIN badges b ON b.id = pb.badge_id
                WHERE pb.player_id = $1 AND b.name IN ('TF All Star','CLM','Misfits')`,
                [req.user.playerId]
            );
            const badgeNames = new Set(badges.rows.map(r => r.name));
            const exclusions = [];
            if (!badgeNames.has('TF All Star')) exclusions.push("(g.exclusivity IS NULL OR g.exclusivity != 'allstars')");
            if (!badgeNames.has('CLM'))         exclusions.push("(g.exclusivity IS NULL OR g.exclusivity != 'clm')");
            if (!badgeNames.has('Misfits'))     exclusions.push("(g.exclusivity IS NULL OR g.exclusivity != 'misfits')");
            badgeFilter = exclusions.length ? 'AND ' + exclusions.join(' AND ') : '';
        }

        const selectFields = `
            g.id, g.game_url, g.game_date, g.game_status, g.format,
            g.exclusivity, g.star_rating, g.team_selection_type,
            g.winning_team, g.motm_winner_id,
            v.name AS venue_name, v.region AS venue_region,
            v.background_image_filename AS venue_background_image, v.photo_url AS venue_photo,
            COALESCE(motm_p.alias, motm_p.full_name) AS motm_winner_name,
            EXISTS(SELECT 1 FROM registrations WHERE game_id = g.id AND player_id = $1) AS is_registered`;

        let result;
        if (scope === 'mine') {
            // Only games where current user has a confirmed registration
            result = await pool.query(`
                SELECT ${selectFields}
                FROM games g
                LEFT JOIN venues v ON v.id = g.venue_id
                LEFT JOIN players motm_p ON motm_p.id = g.motm_winner_id
                WHERE g.game_status = 'completed'
                  AND EXISTS(
                      SELECT 1 FROM registrations
                      WHERE game_id = g.id AND player_id = $1 AND status = 'confirmed'
                  )
                ORDER BY g.game_date DESC
                LIMIT ${limit}`,
                [req.user.playerId]
            );
        } else {
            // All recent completed games
            result = await pool.query(`
                SELECT ${selectFields}
                FROM games g
                LEFT JOIN venues v ON v.id = g.venue_id
                LEFT JOIN players motm_p ON motm_p.id = g.motm_winner_id
                WHERE g.game_status = 'completed'
                  ${badgeFilter}
                ORDER BY g.game_date DESC
                LIMIT ${limit}`,
                [req.user.playerId]
            );
        }

        res.json({ scope, games: result.rows });
    } catch (error) {
        console.error('GET /api/dashboard/recent-games error:', error.message);
        res.status(500).json({ error: 'Failed to load recent games' });
    }
});


// ── GET /api/dashboard/my-booked-games ──────────────────────────────────────
// Row 1 — MY BOOKED GAMES. Includes both confirmed signups AND backups
// (locked decision: A4 Row 1 = confirmed + waitlist/backup).
//
// Returns chronologically ascending (next game first). Excludes completed.
app.get('/api/dashboard/my-booked-games', authenticateToken, async (req, res) => {
    try {
        const limit = Math.min(20, Math.max(1, parseInt(req.query.limit) || 10));
        const result = await pool.query(`
            SELECT g.id, g.game_url, g.game_date, g.game_status, g.format,
                   g.cost_per_player, g.team_selection_type, g.star_rating, g.star_rating_locked,
                   g.max_players,
                   v.name AS venue_name, v.region AS venue_region,
                   v.background_image_filename AS venue_background_image, v.photo_url AS venue_photo,
                   r.status AS my_status,
                   r.backup_type AS my_backup_type,
                   ((SELECT COUNT(*) FROM registrations WHERE game_id = g.id AND status = 'confirmed')
                    + (SELECT COUNT(*) FROM game_guests WHERE game_id = g.id)) AS current_players,
                   ROUND((SELECT AVG(rating) FROM (
                              SELECT CASE WHEN UPPER(TRIM(r2.position_preference)) = 'GK'
                                          THEN NULLIF(p.goalkeeper_rating, 0)
                                          ELSE p.overall_rating END AS rating
                              FROM registrations r2 JOIN players p ON p.id = r2.player_id
                              WHERE r2.game_id = g.id AND r2.status = 'confirmed'
                              UNION ALL
                              SELECT CASE WHEN gg.position_classification = 'gk'
                                          THEN NULLIF(gg.goalkeeper_rating, 0)
                                          ELSE gg.overall_rating END AS rating
                              FROM game_guests gg WHERE gg.game_id = g.id
                          ) ratings WHERE rating IS NOT NULL)::numeric, 1) AS live_avg_ovr
            FROM registrations r
            JOIN games g ON g.id = r.game_id
            LEFT JOIN venues v ON v.id = g.venue_id
            WHERE r.player_id = $1
              AND r.status IN ('confirmed','backup')
              AND g.game_status IN ('available','confirmed')
              AND g.game_date >= CURRENT_TIMESTAMP
            ORDER BY g.game_date ASC
            LIMIT ${limit}`,
            [req.user.playerId]
        );

        res.json({ games: result.rows });
    } catch (error) {
        console.error('GET /api/dashboard/my-booked-games error:', error.message);
        res.status(500).json({ error: 'Failed to load booked games' });
    }
});


// ─────────────────────────────────────────────────────────────────────────────
// DASHBOARD V2 — Phase 1 endpoints (FIX-201, FIX-202, FIX-203)
//
// Spec: dashboard-redesign-v2.md (LOCKED 28 Apr 2026)
// Status: Phase 1 — endpoints only. Frontend dashboardV2 markup is NOT yet
//         wired; these endpoints are deployable today and exercise-able via
//         curl/devtools without affecting the live V1 dashboard.
// V1 endpoints (region-slider, recent-games, my-booked-games) remain alive
// during the transition and will be removed in a follow-up cleanup deploy
// after V2 has had ≥1 week of stable production use.
// ─────────────────────────────────────────────────────────────────────────────

// ── GET /api/dashboard/timeline (FIX-201) ────────────────────────────────────
// Replaces V1 region-slider for Dashboard V2. Returns ONE chronologically
// ordered list of games (past + upcoming) for the player's region, with
// frontend-friendly metadata for the new horizontal Timeline component.
//
// Query params:
//   ?region=Coventry|Birmingham|Manchester|Nuneaton|Leamington & Warwick|ALL
//          Override player's profile region for this request only (does not save)
//   ?search=<keyword>
//          Optional substring filter: matches venue name, format string, or
//          series name (case-insensitive). Empty/absent = no search filter.
//   ?past=20 ?upcoming=20
//          Window sizes (1..50). Defaults 20 each.
//
// Response shape:
//   {
//     region: 'Coventry' | 'ALL' | ...,
//     region_source: 'profile' | 'default' | 'requested',
//     search: '',                          // echoed back, lowercase, trimmed
//     tier_visibility_hours: 168 | null,   // null = admin (no limit)
//     hit_visibility_wall: false,          // true if upcoming was tier-truncated
//     centre_index: 5,                     // index in `games` of the next-future
//                                          // game (or last past if none ahead)
//     games: [ ...sorted ascending by game_date, past first then future... ]
//   }
//
// Frontend derives Timeline state from the response:
//   games.length === 0 + region_source === 'profile'   → "region launched!" card
//   games.length === 0 + region_source === 'default'   → "set your region" card
//   tier_visibility_hours === 0                        → "tier locked" card
//   hit_visibility_wall === true                       → "improve tier" upsell
//                                                        appended after last game
app.get('/api/dashboard/timeline', authenticateToken, async (req, res) => {
    try {
        // ── Player + tier resolution (mirrors V1 region-slider exactly) ──
        const playerRow = await pool.query(
            `SELECT region_code, reliability_tier
             FROM players WHERE id = $1`,
            [req.user.playerId]
        );
        const player  = playerRow.rows[0] || {};
        const tier    = player.reliability_tier || 'silver';
        const isAdmin = req.user.role === 'admin' || req.user.role === 'superadmin';

        // Region (priority: explicit query > profile > default ALL)
        const requestedRegion = req.query.region ? String(req.query.region) : null;
        const { region, source: regionSource } = _resolveSliderRegion(player, requestedRegion);

        // Search keyword — trimmed + lowercased; empty string treated as "no filter"
        const searchRaw = (req.query.search || '').toString().trim().toLowerCase();
        // Defensive cap: a 200-char "search" keyword is almost certainly junk/abuse.
        // Truncate rather than reject so the call still returns games.
        const search = searchRaw.slice(0, 200);

        // Tier visibility window in hours (mirrors V1)
        let hoursAhead = 168;                              // silver default = 7d
        if (tier === 'gold')   hoursAhead = 28 * 24;       // 28d
        if (tier === 'bronze') hoursAhead = 24;            // 1d
        if (tier === 'white' || tier === 'black') hoursAhead = 0;
        const effectiveHoursAhead = isAdmin ? null : hoursAhead;

        // Window sizes (clamped 1..50)
        const upcomingLimit = Math.min(50, Math.max(1, parseInt(req.query.upcoming) || 20));
        const pastLimit     = Math.min(50, Math.max(1, parseInt(req.query.past)     || 20));

        // ── Exclusivity badge filter (mirrors V1 region-slider exactly) ──
        let badgeFilter = '';
        if (!isAdmin) {
            const badges = await pool.query(`
                SELECT b.name FROM player_badges pb
                JOIN badges b ON b.id = pb.badge_id
                WHERE pb.player_id = $1 AND b.name IN ('TF All Star','CLM','Misfits')`,
                [req.user.playerId]
            );
            const badgeNames = new Set(badges.rows.map(r => r.name));
            const exclusions = [];
            if (!badgeNames.has('TF All Star')) exclusions.push("(g.exclusivity IS NULL OR g.exclusivity != 'allstars')");
            if (!badgeNames.has('CLM'))         exclusions.push("(g.exclusivity IS NULL OR g.exclusivity != 'clm')");
            if (!badgeNames.has('Misfits'))     exclusions.push("(g.exclusivity IS NULL OR g.exclusivity != 'misfits')");
            badgeFilter = exclusions.length ? 'AND ' + exclusions.join(' AND ') : '';
        }

        // ── Region clause: 'ALL' = no filter ──
        const regionClause = (region === 'ALL') ? '' : 'AND v.region = $2';
        const baseParams   = (region === 'ALL') ? [req.user.playerId] : [req.user.playerId, region];

        // ── Search clause: substring on venue.name / g.format / gs.series_name ──
        // Parameterised — never interpolated. NULL-safe via COALESCE so games
        // missing a series or format don't blow up the LOWER() call.
        const searchParam = search ? '%' + search + '%' : null;
        let searchClause = '';
        if (searchParam) {
            // Pushed as the LAST param; index depends on whether region is in or out.
            const idx = baseParams.length + 1;
            searchClause = `AND (
                COALESCE(LOWER(v.name), '')         LIKE $${idx} OR
                COALESCE(LOWER(g.format), '')       LIKE $${idx} OR
                COALESCE(LOWER(gs.series_name), '') LIKE $${idx}
            )`;
            baseParams.push(searchParam);
        }

        // ── Tier window clause for UPCOMING games ──
        const tierClause = (effectiveHoursAhead === null)
            ? ''
            : (effectiveHoursAhead === 0)
                ? 'AND 1 = 0'
                : `AND g.game_date <= CURRENT_TIMESTAMP + INTERVAL '${effectiveHoursAhead} hours'`;

        // ── Common SELECT — lean projection matching what the Timeline card needs ──
        const baseSelect = `
            g.id, g.game_url, g.game_date, g.game_status, g.format AS game_format,
            g.cost_per_player, g.early_bird_price, g.super_early_bird_price,
            g.max_players, g.star_rating, g.exclusivity,
            g.team_selection_type, g.tournament_name, g.external_opponent,
            g.teams_generated,
            g.series_id,              -- FIX-269: needed by dashboard FAV toggle (client matches against player_favourite_series)
            opp.logo_url AS opponent_logo_url,
            v.name AS venue_name, v.region AS region,
            v.background_image_filename AS venue_background_image,
            v.photo_url AS venue_photo,
            gs.series_name,
            TO_CHAR(g.game_date AT TIME ZONE 'Europe/London', 'HH24:MI') AS game_time,
            ((SELECT COUNT(*) FROM registrations WHERE game_id = g.id AND status = 'confirmed')
              + (SELECT COUNT(*) FROM game_guests WHERE game_id = g.id))         AS current_players,
            (SELECT status FROM registrations WHERE game_id = g.id AND player_id = $1 LIMIT 1)
                                                                                  AS my_status
        `;  /* Bug fix: vs_external/tournament games now show team logo not venue image (matches games modal) */

        // ── UPCOMING window (ascending by date, tier-limited for non-admins) ──
        const upcomingSql = `
            SELECT ${baseSelect}
            FROM games g
            LEFT JOIN venues v       ON v.id = g.venue_id
            LEFT JOIN game_series gs ON gs.id = g.series_id
            LEFT JOIN opponents opp ON opp.id = g.opponent_id
            WHERE g.game_status IN ('available','confirmed')
              AND g.game_date >= CURRENT_TIMESTAMP
              ${regionClause}
              ${searchClause}
              ${tierClause}
              ${badgeFilter}
            ORDER BY g.game_date ASC
            LIMIT ${upcomingLimit + 1}
        `;

        // ── PAST window (descending — most recent first; no tier limit) ──
        // FIX-238: include 'confirmed' games whose date has passed but haven't
        // been marked completed yet (limbo state — teams generated, game played,
        // results not yet entered). Frontend renders these with a "TEAMS READY"
        // badge so player can find them. Available games with past dates are
        // intentionally excluded — those never filled and would clutter.
        const pastSql = `
            SELECT ${baseSelect}
            FROM games g
            LEFT JOIN venues v       ON v.id = g.venue_id
            LEFT JOIN game_series gs ON gs.id = g.series_id
            LEFT JOIN opponents opp ON opp.id = g.opponent_id
            WHERE g.game_date < CURRENT_TIMESTAMP
              AND g.game_status IN ('completed','confirmed')
              ${regionClause}
              ${searchClause}
              ${badgeFilter}
            ORDER BY g.game_date DESC
            LIMIT ${pastLimit}
        `;

        const [upcomingRes, pastRes] = await Promise.all([
            pool.query(upcomingSql, baseParams),
            pool.query(pastSql,     baseParams),
        ]);

        // hit_visibility_wall: detected by fetching upcomingLimit+1; if we got
        // exactly that many AND we're not admin AND tier is non-zero, the wall
        // truncated us. Slice off the spare row before responding.
        const upcomingFull = upcomingRes.rows;
        let hitVisibilityWall = false;
        if (!isAdmin && effectiveHoursAhead !== null && effectiveHoursAhead > 0) {
            // We didn't get truncated by tier here (we cap with INTERVAL). Wall
            // detection: query a small probe outside the tier window — only run
            // if upcoming hit the LIMIT (cheap heuristic).
            if (upcomingFull.length > upcomingLimit) {
                hitVisibilityWall = true;
            } else {
                // Probe: does ANY game exist in this region BEYOND the tier window?
                const probeParams = [...baseParams];
                const probeRegion = (region === 'ALL') ? '' : 'AND v.region = $2';
                const probe = await pool.query(`
                    SELECT 1
                    FROM games g
                    LEFT JOIN venues v ON v.id = g.venue_id
                    WHERE g.game_status IN ('available','confirmed')
                      AND g.game_date >  CURRENT_TIMESTAMP + INTERVAL '${effectiveHoursAhead} hours'
                      ${probeRegion}
                      ${badgeFilter}
                    LIMIT 1
                `, probeParams.slice(0, region === 'ALL' ? 1 : 2));
                hitVisibilityWall = probe.rows.length > 0;
            }
        }
        const upcoming = upcomingFull.slice(0, upcomingLimit);

        // Stitch: past (reversed → ascending) THEN upcoming (already ascending)
        const pastAsc = pastRes.rows.slice().reverse();
        const games   = pastAsc.concat(upcoming);

        // centre_index = first future game's position; fallback to last past game
        // (or 0 if list is empty).
        let centreIndex = 0;
        if (games.length) {
            const firstFutureIdx = pastAsc.length;  // upcoming starts at this index
            centreIndex = (upcoming.length > 0) ? firstFutureIdx : (pastAsc.length - 1);
            if (centreIndex < 0) centreIndex = 0;
        }

        // FIX-217: resolve venue photo same as /api/games — admin-set bg image
        // → hardcoded venue map → legacy DB photo_url. Frontend uses venue_photo.
        const _venuePhotoMapV2 = {
            'Daimler Green - Astro':       'https://totalfooty.co.uk/assets/Daimler_Green.jpg',
            'Daimler Green - Grass':       'https://totalfooty.co.uk/assets/Daimler_Green_Grass.webp',
            'Daimler Green':               'https://totalfooty.co.uk/assets/Daimler_Green.jpg',
            'Daimler Green Community Centre': 'https://totalfooty.co.uk/assets/Daimler_Green.jpg',
            'Corpus Christi':              'https://totalfooty.co.uk/assets/Corpus_Christi.jpg',
            'War Memorial Park':           'https://totalfooty.co.uk/assets/war_memorial_park.jpg',
            'Memorial Park':               'https://totalfooty.co.uk/assets/war_memorial_park.jpg',
            'Powerleague':                 'https://totalfooty.co.uk/assets/Powerleague.jpeg',
            'Power League':                'https://totalfooty.co.uk/assets/Powerleague.jpeg',
            'Coventry Powerleague':        'https://totalfooty.co.uk/assets/Powerleague.jpeg',
            'Powerleague Coventry':        'https://totalfooty.co.uk/assets/Powerleague.jpeg',
            'Sidney Stringer':             'https://totalfooty.co.uk/assets/Sidney_Stringer_Academy.jpg',
            'Sidney Stringer Academy':     'https://totalfooty.co.uk/assets/Sidney_Stringer_Academy.jpg',
            'Nuneaton Academy':            'https://totalfooty.co.uk/assets/nuneaton_academy.webp',
            'Tudor Grange Academy':        'https://totalfooty.co.uk/assets/Tudor-Grange-pitch.webp',
            'Light Hall School'   :        'https://totalfooty.co.uk/assets/venues/light-hall-school.jpg',
        };
        for (const game of games) {
            // Bug fix: vs_external and tournament games show team/tournament image
            // on the dashboard, matching the games modal pattern (renderGameCard).
            // Without this override, V2 timeline cards show the venue photo for
            // games where the visual identity is the opponent (vs_external) or
            // the tournament branding.
            if (game.team_selection_type === 'vs_external' && game.opponent_logo_url) {
                game.venue_photo = game.opponent_logo_url;
            } else if (game.team_selection_type === 'tournament') {
                game.venue_photo = 'https://totalfooty.co.uk/assets/tfclogo%20v2.png';
            } else if (game.venue_background_image) {
                game.venue_photo = `https://totalfooty.co.uk/assets/venues/${game.venue_background_image}`;
            } else if (game.venue_name && _venuePhotoMapV2[game.venue_name]) {
                game.venue_photo = _venuePhotoMapV2[game.venue_name];
            }
            // else venue_photo stays as v.photo_url (or null)
        }

        res.json({
            region,
            region_source: regionSource,
            search,
            tier_visibility_hours: effectiveHoursAhead,
            hit_visibility_wall: hitVisibilityWall,
            centre_index: centreIndex,
            games,
        });
    } catch (error) {
        // FIX-237: rich diagnostic log — when a player hits this, we can grep
        // Render logs by player ID to see exactly what they sent + the SQL
        // error code. .stack first so the deepest cause is visible.
        console.error('GET /api/dashboard/timeline error:',
            'player=' + (req.user?.playerId || 'anon'),
            'region=' + (req.query?.region || '<auto>'),
            'search=' + (req.query?.search || ''),
            'msg=' + error.message,
            'code=' + (error.code || ''),
            error.stack ? '\n' + error.stack.split('\n').slice(0, 4).join('\n') : '');
        res.status(500).json({ error: 'Failed to load timeline' });
    }
});


// ── GET /api/dashboard/live-votes (FIX-202) ──────────────────────────────────
// Returns the player's most recent game with currently-OPEN voting (MOTM
// or TF Game Awards). Drives Slot A of Dashboard V2's right column.
//
// "Live" = game is completed, the voting window has not closed, the player
// was confirmed in the game, and (for MOTM) a winner has not yet been
// recorded. The player CAN have already voted — we still surface it so they
// can check the leaderboard / change their vote where supported.
//
// Response shape:
//   { has_live: false, vote: null }
//   { has_live: true, vote: {
//         game_id, game_url, game_date, day_label, venue_name,
//         vote_type: 'motm' | 'awards',
//         closes_at,                  // ISO timestamp
//         minutes_remaining,           // integer, clamped >= 0
//   }}
//
// Selection rule: most-recently-played qualifying game (ORDER BY game_date DESC).
// MOTM and Awards are returned as a unioned set; the most recent of either wins.
app.get('/api/dashboard/live-votes', authenticateToken, async (req, res) => {
    try {
        const playerId = req.user.playerId;

        // Pull both candidate sets in one query, mark vote_type, take the
        // most recent. We restrict to games where the player was on a team
        // (not just a backup who never played) — same "rostered" rule used
        // throughout the app for MOTM eligibility.
        const result = await pool.query(`
            WITH eligible_games AS (
                SELECT DISTINCT g.id, g.game_url, g.game_date, v.name AS venue_name
                FROM games g
                JOIN registrations r  ON r.game_id   = g.id AND r.status = 'confirmed'
                JOIN team_players tp  ON tp.player_id = r.player_id
                JOIN teams t          ON t.id = tp.team_id AND t.game_id = g.id
                LEFT JOIN venues v    ON v.id = g.venue_id
                WHERE r.player_id  = $1
                  AND g.game_status = 'completed'
            ),
            motm_open AS (
                SELECT eg.id, eg.game_url, eg.game_date, eg.venue_name,
                       'motm'::text                         AS vote_type,
                       g.motm_voting_ends                   AS closes_at
                FROM eligible_games eg
                JOIN games g ON g.id = eg.id
                WHERE g.motm_voting_ends > NOW()
                  AND g.motm_winner_id IS NULL
                  AND EXISTS (SELECT 1 FROM motm_nominees mn WHERE mn.game_id = g.id)
            ),
            awards_open AS (
                SELECT eg.id, eg.game_url, eg.game_date, eg.venue_name,
                       'awards'::text                       AS vote_type,
                       g.awards_close_at                    AS closes_at
                FROM eligible_games eg
                JOIN games g ON g.id = eg.id
                WHERE g.awards_open = TRUE
                  AND g.awards_close_at IS NOT NULL
                  AND g.awards_close_at > NOW()
            )
            SELECT * FROM motm_open
            UNION ALL
            SELECT * FROM awards_open
            ORDER BY game_date DESC
            LIMIT 1
        `, [playerId]);

        if (result.rows.length === 0) {
            return res.json({ has_live: false, vote: null });
        }

        const r        = result.rows[0];
        const closesAt = r.closes_at;
        const minutesRemaining = Math.max(0,
            Math.floor((new Date(closesAt).getTime() - Date.now()) / 60000)
        );
        const dayLabel = new Date(r.game_date).toLocaleDateString('en-GB', {
            weekday: 'short', day: 'numeric', month: 'short', timeZone: 'Europe/London'
        });

        res.json({
            has_live: true,
            vote: {
                game_id:           r.id,
                game_url:          r.game_url,
                game_date:         r.game_date,
                day_label:         dayLabel,
                venue_name:        r.venue_name,
                vote_type:         r.vote_type,
                closes_at:         closesAt,
                minutes_remaining: minutesRemaining,
            },
        });
    } catch (error) {
        console.error('GET /api/dashboard/live-votes error:', error.message);
        res.status(500).json({ error: 'Failed to load live votes' });
    }
});


// ── GET /api/dashboard/recent-awards (FIX-203) ───────────────────────────────
// Returns awards the player has WON in the last 3 days. Drives Slot B of
// Dashboard V2's right column. Source = game_awards table (server.js:15733
// confirmed schema: game_id, recipient_player_id, award_type, award_source,
// motm_value, vote_count, star_class, series_day, created_at).
//
// Window: 3 days. Tunable via the AWARDS_WINDOW_DAYS constant below.
//
// Response shape:
//   { has_recent: false, awards: [] }
//   { has_recent: true, awards: [
//       { game_id, game_url, game_date, day_label, venue_name,
//         award_type, vote_count, star_class, awarded_at }
//   ]}
//
// Sort: most recent created_at first.
const AWARDS_WINDOW_DAYS = 3;  // tunable — Dashboard V2 spec §4.2

app.get('/api/dashboard/recent-awards', authenticateToken, async (req, res) => {
    try {
        const result = await pool.query(`
            SELECT
                ga.game_id,
                g.game_url,
                g.game_date,
                v.name        AS venue_name,
                ga.award_type,
                ga.vote_count,
                ga.star_class,
                ga.created_at AS awarded_at
            FROM game_awards ga
            JOIN games g       ON g.id = ga.game_id
            LEFT JOIN venues v ON v.id = g.venue_id
            WHERE ga.recipient_player_id = $1
              AND ga.created_at >= NOW() - INTERVAL '${AWARDS_WINDOW_DAYS} days'
            ORDER BY ga.created_at DESC
            LIMIT 20
        `, [req.user.playerId]);

        const awards = result.rows.map(r => ({
            ...r,
            day_label: new Date(r.game_date).toLocaleDateString('en-GB', {
                weekday: 'short', day: 'numeric', month: 'short', timeZone: 'Europe/London'
            }),
        }));

        res.json({
            has_recent: awards.length > 0,
            awards,
        });
    } catch (error) {
        console.error('GET /api/dashboard/recent-awards error:', error.message);
        res.status(500).json({ error: 'Failed to load recent awards' });
    }
});


// POST /api/player/help-guide-seen — marks the dashboard help guide as viewed
// (used to prevent auto-launch of the tour on subsequent dashboard loads)
app.post('/api/player/help-guide-seen', authenticateToken, async (req, res) => {
    try {
        await pool.query(
            'UPDATE players SET has_seen_help_guide = TRUE WHERE id = $1',
            [req.user.playerId]
        );
        res.json({ success: true });
    } catch (error) {
        console.error('help-guide-seen error:', error.message);
        res.status(500).json({ error: 'Failed to save preference' });
    }
});

// Upload profile photo (base64)
app.post('/api/players/me/photo',
    authenticateToken,
    express.json({ limit: '5mb' }),
async (req, res) => {
    try {
        const { photoData } = req.body; // Base64 string
        
        if (!photoData) {
            return res.status(400).json({ error: 'No photo data provided' });
        }

        // FIX-015: Guard against huge base64 payloads
        if (photoData.length > 2_000_000) {
            return res.status(400).json({ error: 'Photo too large. Max ~1.5MB.' });
        }

        // FIX-046: Check MIME prefix first
        const VALID_PREFIXES = {
            'data:image/jpeg;base64,': { magic: [0xFF, 0xD8, 0xFF], label: 'JPEG' },
            'data:image/png;base64,':  { magic: [0x89, 0x50, 0x4E, 0x47], label: 'PNG' },
            'data:image/webp;base64,': { magic: [0x52, 0x49, 0x46, 0x46], label: 'WebP' },
        };
        const matchedPrefix = Object.keys(VALID_PREFIXES).find(p => photoData.startsWith(p));
        if (!matchedPrefix) {
            return res.status(400).json({ error: 'Invalid image format. Only JPEG, PNG, and WebP are allowed.' });
        }

        // SEC-027: Validate magic bytes — prevents polyglot files that pass MIME-prefix-only checks
        const b64Data = photoData.slice(matchedPrefix.length);
        const rawBytes = Buffer.from(b64Data, 'base64');
        const expectedMagic = VALID_PREFIXES[matchedPrefix].magic;
        const actualBytes = [...rawBytes.slice(0, expectedMagic.length)];
        const magicOk = expectedMagic.every((byte, i) => actualBytes[i] === byte);
        if (!magicOk) {
            return res.status(400).json({ error: 'File contents do not match declared image type.' });
        }
        
        await pool.query(
            'UPDATE players SET photo_url = $1 WHERE id = $2',
            [photoData, req.user.playerId]
        );
        
        setImmediate(() => auditLog(pool, req.user.playerId, 'photo_uploaded', req.user.playerId, 'Player updated profile photo'));
        res.json({ message: 'Photo uploaded successfully' });
    } catch (error) {
        console.error('Photo upload error:', error);
        res.status(500).json({ error: 'Upload failed' });
    }
});

// FIX-108: Admin-only photo upload for any player (used by player card graphic)
// Mirrors /api/players/me/photo validation exactly — MIME prefix + magic bytes.
app.post('/api/admin/players/:id/photo',
    authenticateToken, requireAdmin,
    express.json({ limit: '5mb' }),
async (req, res) => {
    try {
        const { id } = req.params;
        const { photoData } = req.body;

        if (!id || !/^[0-9a-f-]{36}$/.test(id)) return res.status(400).json({ error: 'Invalid player ID' });
        if (!photoData) return res.status(400).json({ error: 'No photo data provided' });
        if (photoData.length > 2_000_000) return res.status(400).json({ error: 'Photo too large. Max ~1.5MB.' });

        const VALID_PREFIXES = {
            'data:image/jpeg;base64,': { magic: [0xFF, 0xD8, 0xFF] },
            'data:image/png;base64,':  { magic: [0x89, 0x50, 0x4E, 0x47] },
            'data:image/webp;base64,': { magic: [0x52, 0x49, 0x46, 0x46] },
        };
        const matchedPrefix = Object.keys(VALID_PREFIXES).find(p => photoData.startsWith(p));
        if (!matchedPrefix) return res.status(400).json({ error: 'Invalid image format. JPEG, PNG, or WebP only.' });

        const b64Data = photoData.slice(matchedPrefix.length);
        const rawBytes = Buffer.from(b64Data, 'base64');
        const expectedMagic = VALID_PREFIXES[matchedPrefix].magic;
        const actualBytes = [...rawBytes.slice(0, expectedMagic.length)];
        if (!expectedMagic.every((byte, i) => actualBytes[i] === byte)) {
            return res.status(400).json({ error: 'File contents do not match declared image type.' });
        }

        const upd = await pool.query(
            'UPDATE players SET photo_url = $1 WHERE id = $2 RETURNING alias',
            [photoData, id]
        );
        if (upd.rowCount === 0) return res.status(404).json({ error: 'Player not found' });

        setImmediate(() => auditLog(pool, req.user.playerId, 'photo_uploaded', id,
            `Admin updated photo for ${upd.rows[0].alias}`));
        res.json({ success: true });
    } catch (error) {
        console.error('Admin photo upload error:', error);
        res.status(500).json({ error: 'Upload failed' });
    }
});


// ══════════════════════════════════════════════════════════════
// POST /api/players/me/coach-document
// Upload coaching license/certificate (base64) — stores in players.coach_license_doc
// ══════════════════════════════════════════════════════════════
app.post('/api/players/me/coach-document',
    authenticateToken,
    express.json({ limit: '5mb' }),
async (req, res) => {
    const { docData } = req.body;
    if (!docData) return res.status(400).json({ error: 'No document data provided' });
    if (docData.length > 3_000_000) return res.status(400).json({ error: 'Document too large. Max ~2MB.' });

    const DOC_PREFIXES = {
        'data:application/pdf;base64,':  { magic: [0x25, 0x50, 0x44, 0x46], label: 'PDF'  },
        'data:image/jpeg;base64,':       { magic: [0xFF, 0xD8, 0xFF],        label: 'JPEG' },
        'data:image/png;base64,':        { magic: [0x89, 0x50, 0x4E, 0x47],  label: 'PNG'  },
    };
    const matchedPrefix = Object.keys(DOC_PREFIXES).find(p => docData.startsWith(p));
    if (!matchedPrefix) return res.status(400).json({ error: 'Invalid format. PDF, JPEG or PNG only.' });

    const b64Data   = docData.slice(matchedPrefix.length);
    const rawBytes  = Buffer.from(b64Data, 'base64');
    const expected  = DOC_PREFIXES[matchedPrefix].magic;
    const actual    = [...rawBytes.slice(0, expected.length)];
    if (!expected.every((byte, i) => actual[i] === byte))
        return res.status(400).json({ error: 'File contents do not match declared type.' });

    try {
        await pool.query('UPDATE players SET coach_license_doc = $1 WHERE id = $2',
            [docData, req.user.playerId]);
        res.json({ success: true });
    } catch (e) {
        console.error('Coach document upload error:', e.message);
        res.status(500).json({ error: 'Upload failed' });
    }
});

// Superadmin: upload coach document for a specific player
app.post('/api/admin/players/:id/coach-document',
    authenticateToken, requireSuperAdmin,
    express.json({ limit: '5mb' }),
async (req, res) => {
    const { id } = req.params;
    const { docData } = req.body;
    if (!id || !/^[0-9a-f-]{36}$/.test(id)) return res.status(400).json({ error: 'Invalid player ID' });
    if (!docData) return res.status(400).json({ error: 'No document data provided' });
    if (docData.length > 3_000_000) return res.status(400).json({ error: 'Document too large. Max ~2MB.' });

    const DOC_PREFIXES = {
        'data:application/pdf;base64,':  { magic: [0x25, 0x50, 0x44, 0x46] },
        'data:image/jpeg;base64,':       { magic: [0xFF, 0xD8, 0xFF]        },
        'data:image/png;base64,':        { magic: [0x89, 0x50, 0x4E, 0x47] },
    };
    const matchedPrefix = Object.keys(DOC_PREFIXES).find(p => docData.startsWith(p));
    if (!matchedPrefix) return res.status(400).json({ error: 'Invalid format. PDF, JPEG or PNG only.' });

    const b64     = docData.slice(matchedPrefix.length);
    const raw     = Buffer.from(b64, 'base64');
    const exp     = DOC_PREFIXES[matchedPrefix].magic;
    if (!exp.every((byte, i) => raw[i] === byte))
        return res.status(400).json({ error: 'File contents do not match declared type.' });

    try {
        await pool.query('UPDATE players SET coach_license_doc = $1 WHERE id = $2', [docData, id]);
        res.json({ success: true });
    } catch (e) {
        console.error('Admin coach document upload error:', e.message);
        res.status(500).json({ error: 'Upload failed' });
    }
});

