// POST — create venue
app.post('/api/admin/venues', authenticateToken, requireAdmin, async (req, res) => {
    try {
        const v = validateVenuePayload(req.body);
        if (!v.ok) return res.status(v.status).json({ error: v.error });

        // HEAD-check the image (if provided) before write — catches typos early.
        // Tri-state: true = exists, false = confirmed 404, null = uncertain.
        // We only block on confirmed 404; uncertain results pass through with a
        // server log. This avoids blocking saves due to transient network issues.
        if (v.data.background_image_filename) {
            const exists = await checkVenueImageExists(v.data.background_image_filename);
            if (exists === false) {
                return res.status(400).json({
                    error: `Image file '${v.data.background_image_filename}' not found at /assets/venues/. Upload it to Namecheap first, then save.`
                });
            }
            if (exists === null) {
                console.warn(`[venue create] image existence check inconclusive for ${v.data.background_image_filename} — allowing save`);
            }
        }

        const cols = [
            'name','address','region','postcode','pitch_location','pitch_name',
            'facilities','notes','special_instructions','parking_pin','pitch_pin',
            'boot_type','pitch_type','availability_rule','coaching_suitable','coaching_cost_per_hour',
            'pay_and_play_coach_hourly','pay_and_play_player_hourly',
            'default_pitch_cost','default_max_players','default_format','default_position_type',
            'background_image_filename'
        ];
        const placeholders = cols.map((_, i) => `$${i + 1}`).join(', ');
        const values = cols.map(c => v.data[c]);
        const result = await pool.query(
            `INSERT INTO venues (${cols.join(', ')}) VALUES (${placeholders}) RETURNING id, name`,
            values
        ).catch(async (err) => {
            // Pre-migration: some new cols missing. Strip them and retry once.
            if (err.code === '42703') {
                const baseCols = ['name','address','region','postcode','pitch_location','pitch_name',
                                  'facilities','notes','special_instructions','parking_pin','pitch_pin',
                                  'boot_type','availability_rule','coaching_suitable','coaching_cost_per_hour',
                                  'pay_and_play_coach_hourly','pay_and_play_player_hourly'];
                const ph = baseCols.map((_, i) => `$${i + 1}`).join(', ');
                const vals = baseCols.map(c => v.data[c]);
                return await pool.query(
                    `INSERT INTO venues (${baseCols.join(', ')}) VALUES (${ph}) RETURNING id, name`,
                    vals
                );
            }
            throw err;
        });

        const newVenue = result.rows[0];
        setImmediate(() => auditLog(pool, req.user.playerId, 'venue_created', newVenue.id,
            `Created venue "${newVenue.name}"`).catch(() => {}));

        res.json({ ok: true, id: newVenue.id, name: newVenue.name });
    } catch (error) {
        console.error('Create venue error:', error);
        res.status(500).json({ error: 'Failed to create venue', detail: error.message });
    }
});

// PUT — update venue
app.put('/api/admin/venues/:id', authenticateToken, requireAdmin, async (req, res) => {
    try {
        const { id } = req.params;
        if (!isValidUuid(id)) return res.status(400).json({ error: 'Invalid venue id' });

        const exists = await pool.query('SELECT id FROM venues WHERE id = $1', [id]);
        if (!exists.rows.length) return res.status(404).json({ error: 'Venue not found' });

        const v = validateVenuePayload(req.body);
        if (!v.ok) return res.status(v.status).json({ error: v.error });

        // HEAD-check on image if provided. Same tri-state logic as POST —
        // only block on confirmed 404, allow uncertain through.
        if (v.data.background_image_filename) {
            const fileOk = await checkVenueImageExists(v.data.background_image_filename);
            if (fileOk === false) {
                return res.status(400).json({
                    error: `Image file '${v.data.background_image_filename}' not found at /assets/venues/. Upload it to Namecheap first, then save.`
                });
            }
            if (fileOk === null) {
                console.warn(`[venue update ${id}] image existence check inconclusive for ${v.data.background_image_filename} — allowing save`);
            }
        }

        const cols = [
            'name','address','region','postcode','pitch_location','pitch_name',
            'facilities','notes','special_instructions','parking_pin','pitch_pin',
            'boot_type','pitch_type','availability_rule','coaching_suitable','coaching_cost_per_hour',
            'pay_and_play_coach_hourly','pay_and_play_player_hourly',
            'default_pitch_cost','default_max_players','default_format','default_position_type',
            'background_image_filename'
        ];
        const setClause = cols.map((c, i) => `${c} = $${i + 1}`).join(', ');
        const values = [...cols.map(c => v.data[c]), id];
        await pool.query(
            `UPDATE venues SET ${setClause} WHERE id = $${cols.length + 1}`,
            values
        ).catch(async (err) => {
            if (err.code === '42703') {
                // Pre-migration — drop new columns and retry
                const baseCols = ['name','address','region','postcode','pitch_location','pitch_name',
                                  'facilities','notes','special_instructions','parking_pin','pitch_pin',
                                  'boot_type','availability_rule','coaching_suitable','coaching_cost_per_hour',
                                  'pay_and_play_coach_hourly','pay_and_play_player_hourly'];
                const setClauseLite = baseCols.map((c, i) => `${c} = $${i + 1}`).join(', ');
                const valsLite = [...baseCols.map(c => v.data[c]), id];
                return await pool.query(
                    `UPDATE venues SET ${setClauseLite} WHERE id = $${baseCols.length + 1}`,
                    valsLite
                );
            }
            throw err;
        });

        setImmediate(() => auditLog(pool, req.user.playerId, 'venue_updated', id,
            `Updated venue "${v.data.name}"`).catch(() => {}));

        res.json({ ok: true, id });
    } catch (error) {
        console.error('Update venue error:', error);
        res.status(500).json({ error: 'Failed to update venue', detail: error.message });
    }
});

// DELETE — soft-delete (sets is_active=false). Hard-delete avoided to preserve
// historical games' venue references.
app.delete('/api/admin/venues/:id', authenticateToken, requireAdmin, async (req, res) => {
    try {
        const { id } = req.params;
        if (!isValidUuid(id)) return res.status(400).json({ error: 'Invalid venue id' });

        const r = await pool.query('SELECT name FROM venues WHERE id = $1', [id]);
        if (!r.rows.length) return res.status(404).json({ error: 'Venue not found' });

        await pool.query('UPDATE venues SET is_active = FALSE WHERE id = $1', [id])
            .catch(err => {
                if (err.code === '42703') {
                    // Pre-migration — column doesn't exist. We can't soft-delete cleanly.
                    // Reject rather than risk a hard delete.
                    throw Object.assign(new Error('is_active column missing — run p5-migration.sql first'), { code: 'MIGRATION_NEEDED' });
                }
                throw err;
            });

        setImmediate(() => auditLog(pool, req.user.playerId, 'venue_archived', id,
            `Archived venue "${r.rows[0].name}" (soft-delete)`).catch(() => {}));

        res.json({ ok: true });
    } catch (error) {
        if (error.code === 'MIGRATION_NEEDED') {
            return res.status(503).json({ error: error.message });
        }
        console.error('Delete venue error:', error);
        res.status(500).json({ error: 'Failed to delete venue' });
    }
});

// POST — restore archived venue
app.post('/api/admin/venues/:id/restore', authenticateToken, requireAdmin, async (req, res) => {
    try {
        const { id } = req.params;
        if (!isValidUuid(id)) return res.status(400).json({ error: 'Invalid venue id' });
        const r = await pool.query('SELECT name FROM venues WHERE id = $1', [id]);
        if (!r.rows.length) return res.status(404).json({ error: 'Venue not found' });

        await pool.query('UPDATE venues SET is_active = TRUE WHERE id = $1', [id])
            .catch(err => {
                if (err.code === '42703') throw Object.assign(new Error('is_active column missing — run p5-migration.sql first'), { code: 'MIGRATION_NEEDED' });
                throw err;
            });

        setImmediate(() => auditLog(pool, req.user.playerId, 'venue_restored', id,
            `Restored venue "${r.rows[0].name}"`).catch(() => {}));
        res.json({ ok: true });
    } catch (error) {
        if (error.code === 'MIGRATION_NEEDED') return res.status(503).json({ error: error.message });
        console.error('Restore venue error:', error);
        res.status(500).json({ error: 'Failed to restore venue' });
    }
});


// ==========================================
// GAMES API
// ==========================================

app.get('/api/games', authenticateToken, async (req, res) => {
    try {
        const playerResult = await pool.query(
            'SELECT reliability_tier, overall_rating, goalkeeper_rating FROM players WHERE id = $1',
            [req.user.playerId]
        );
        
        const tier      = playerResult.rows[0]?.reliability_tier || 'silver';
        const playerOvr = parseInt(playerResult.rows[0]?.overall_rating    ?? 0);
        const playerGk  = parseInt(playerResult.rows[0]?.goalkeeper_rating ?? 0);
        
        // Check if player has TF All Star badge
        const allStarBadgeResult = await pool.query(`
            SELECT 1 FROM player_badges pb
            JOIN badges b ON b.id = pb.badge_id
            WHERE pb.player_id = $1 AND b.name = 'TF All Star'
        `, [req.user.playerId]);
        
        const hasAllStarBadge = allStarBadgeResult.rows.length > 0;
        
        // Check if player has CLM badge
        const clmBadgeResult = await pool.query(`
            SELECT 1 FROM player_badges pb
            JOIN badges b ON b.id = pb.badge_id
            WHERE pb.player_id = $1 AND b.name = 'CLM'
        `, [req.user.playerId]);
        
        const hasCLMBadge = clmBadgeResult.rows.length > 0;
        
        // Check if player has Misfits badge
        const misfitsBadgeResult = await pool.query(`
            SELECT 1 FROM player_badges pb
            JOIN badges b ON b.id = pb.badge_id
            WHERE pb.player_id = $1 AND b.name = 'Misfits'
        `, [req.user.playerId]);
        
        const hasMisfitsBadge = misfitsBadgeResult.rows.length > 0;
        
        // Tier-based visibility (exact requirements)
        let hoursAhead = 168; // silver default (168 hours = 7 days)
        if (tier === 'gold') hoursAhead = 28 * 24; // 28 days
        if (tier === 'bronze') hoursAhead = 24; // 24 hours
        if (tier === 'white' || tier === 'black') hoursAhead = 0; // banned - no games visible
        
        const isAdmin = req.user.role === 'admin' || req.user.role === 'superadmin';

        // FIX-319 (ROW Day 3): Coventry hard-wall / discovery firewall.
        // Admins see every game regardless of tenant. Non-admins see only:
        //   - TF root games (g.tenant_id IS NULL) IF their show_tf_root_games = TRUE
        //   - Games from tenants where they've toggled show_in_dashboard = TRUE
        // For existing TF players (no player_tenants rows, default TRUE) this
        // resolves to "all games where tenant_id IS NULL" — identical to today.
        const visScope = await getVisibleTenantContext(req.user.playerId);

        const result = await pool.query(`
            SELECT g.*, v.name as venue_name, v.address as venue_address, v.region as venue_region, v.special_instructions as venue_special_instructions, v.notes as venue_notes, v.pitch_location as venue_pitch_location,
                   v.background_image_filename AS venue_background_image, v.photo_url AS venue_photo,
                   g.teams_generated,
                   gs.series_name,
                   g.format as game_format,
                   TO_CHAR(g.game_date AT TIME ZONE 'Europe/London', 'HH24:MI') as game_time,
                   ((SELECT COUNT(*) FROM registrations WHERE game_id = g.id AND status IN ('confirmed', 'rsvp')) + (SELECT COUNT(*) FROM game_guests WHERE game_id = g.id)) as current_players,
                   ROUND((SELECT AVG(rating) FROM (
                       SELECT CASE WHEN UPPER(TRIM(r.position_preference)) = 'GK'
                                   THEN NULLIF(p.goalkeeper_rating, 0)
                                   ELSE p.overall_rating END AS rating
                       FROM registrations r JOIN players p ON p.id = r.player_id
                       WHERE r.game_id = g.id AND r.status IN ('confirmed', 'rsvp') /* FIX-315: include RSVPs in live_avg_ovr */
                       UNION ALL
                       SELECT CASE WHEN gg.position_classification = 'gk'
                                   THEN NULLIF(gg.goalkeeper_rating, 0)
                                   ELSE gg.overall_rating END AS rating
                       FROM game_guests gg WHERE gg.game_id = g.id
                   ) ratings WHERE rating IS NOT NULL)::numeric, 1) as live_avg_ovr,
                   COALESCE((SELECT COUNT(*) FROM registrations r JOIN players p ON p.id = r.player_id WHERE r.game_id = g.id AND r.status = 'confirmed' AND p.is_organiser = true)::int, 0) as confirmed_organiser_count,
                   (SELECT COUNT(*) FROM registrations WHERE game_id = g.id AND status = 'backup') as backup_count,
                   EXISTS(SELECT 1 FROM registrations WHERE game_id = g.id AND player_id = $1) as is_registered,
                   (SELECT status FROM registrations WHERE game_id = g.id AND player_id = $1 LIMIT 1) as registration_status,
                   (SELECT backup_type FROM registrations WHERE game_id = g.id AND player_id = $1 LIMIT 1) as my_backup_type,
                   -- P2.3: amount paid by current user (drives drop-out "you'll lose £X" dialog)
                   COALESCE((SELECT amount_paid      FROM registrations WHERE game_id = g.id AND player_id = $1 LIMIT 1), 0) as my_amount_paid,
                   COALESCE((SELECT amount_paid_free FROM registrations WHERE game_id = g.id AND player_id = $1 LIMIT 1), 0) as my_amount_paid_free,
                   motm_p.alias as motm_winner_alias, motm_p.full_name as motm_winner_name,
                   opp_list.logo_url AS opponent_logo_url, opp_list.star_rating AS opponent_star_rating
            FROM games g
            LEFT JOIN venues v ON v.id = g.venue_id
            LEFT JOIN game_series gs ON gs.id = g.series_id
            LEFT JOIN players motm_p ON motm_p.id = g.motm_winner_id
            LEFT JOIN opponents opp_list ON opp_list.id = g.opponent_id
            WHERE (
                (g.game_status = 'available' AND g.game_date >= CURRENT_TIMESTAMP)
                OR (g.game_status = 'confirmed')
                OR (g.game_status = 'completed' AND (
                    ${isAdmin ? "(g.game_date >= NOW() - INTERVAL '30 days')" : 'EXISTS(SELECT 1 FROM registrations WHERE game_id = g.id AND player_id = $1)'}
                ))
            )
            ${isAdmin ? '' : hoursAhead > 0 ? 'AND g.game_date <= CURRENT_TIMESTAMP + INTERVAL \'' + hoursAhead + ' hours\'' : 'AND 1 = 0'}
            AND g.game_status != 'cancelled'
            ${!isAdmin && !hasAllStarBadge ? "AND (g.exclusivity IS NULL OR g.exclusivity != 'allstars')" : ''}
            ${!isAdmin && !hasCLMBadge ? "AND (g.exclusivity IS NULL OR g.exclusivity != 'clm')" : ''}
            ${!isAdmin && !hasMisfitsBadge ? "AND (g.exclusivity IS NULL OR g.exclusivity != 'misfits')" : ''}
            AND ($2 = TRUE OR (g.tenant_id IS NULL AND $3 = TRUE) OR g.tenant_id = ANY($4::uuid[]) OR ($5 = TRUE AND g.tenant_id IS NOT NULL))
            ORDER BY g.game_date DESC
        `, [req.user.playerId, isAdmin, visScope.includeTfRoot, visScope.tenantIds, visScope.includeAllPublicTenants]);
        
        // Map venue names to their photo URLs
        const venuePhotoMap = {
            'Daimler Green - Astro': 'https://totalfooty.co.uk/assets/Daimler_Green.jpg',
            'Daimler Green - Grass': 'https://totalfooty.co.uk/assets/Daimler_Green_Grass.webp',
            'Daimler Green': 'https://totalfooty.co.uk/assets/Daimler_Green.jpg',
            'Daimler Green Community Centre': 'https://totalfooty.co.uk/assets/Daimler_Green.jpg',
            'Corpus Christi': 'https://totalfooty.co.uk/assets/Corpus_Christi.jpg',
            'War Memorial Park': 'https://totalfooty.co.uk/assets/war_memorial_park.jpg',
            'Memorial Park': 'https://totalfooty.co.uk/assets/war_memorial_park.jpg',
            'Powerleague': 'https://totalfooty.co.uk/assets/Powerleague.jpeg',
            'Power League': 'https://totalfooty.co.uk/assets/Powerleague.jpeg',
            'Coventry Powerleague': 'https://totalfooty.co.uk/assets/Powerleague.jpeg',
            'Powerleague Coventry': 'https://totalfooty.co.uk/assets/Powerleague.jpeg',
            'Sidney Stringer': 'https://totalfooty.co.uk/assets/Sidney_Stringer_Academy.jpg',
            'Sidney Stringer Academy': 'https://totalfooty.co.uk/assets/Sidney_Stringer_Academy.jpg',
                'Nuneaton Academy':        'https://totalfooty.co.uk/assets/nuneaton_academy.webp',
                'Tudor Grange Academy':     'https://totalfooty.co.uk/assets/Tudor-Grange-pitch.webp',
                'Light Hall School'   :     'https://totalfooty.co.uk/assets/venues/light-hall-school.jpg',
        };
        
        // Resolve venue hero photo: admin-set background_image_filename -> hardcoded map -> legacy DB photo_url
        const gamesWithPhotos = result.rows.map(game => {
            // Bug fix: vs_external/tournament games show team logo, matching the
            // games modal renderGameCard logic. V1 dashboard tiles (TONIGHT,
            // IM-PLAYING, RECENT) read g.venue_photo directly without their own
            // override, so the override has to live here for them to render
            // correctly. The games list itself doesn't break because
            // renderGameCard already chooses the right backgroundImage based on
            // team_selection_type — but venue_photo carrying the right value is
            // also fine for that path.
            if (game.team_selection_type === 'vs_external' && game.opponent_logo_url) {
                game.venue_photo = game.opponent_logo_url;
            } else if (game.team_selection_type === 'tournament') {
                game.venue_photo = 'https://totalfooty.co.uk/assets/tfclogo%20v2.png';
            } else if (game.venue_background_image) {
                game.venue_photo = `https://totalfooty.co.uk/assets/venues/${game.venue_background_image}`;
            } else if (game.venue_name && venuePhotoMap[game.venue_name]) {
                game.venue_photo = venuePhotoMap[game.venue_name];
            }
            // Attach effective price tier for frontend bird display
            const { price: _ep, tier: _pt } = getEffectivePrice(game);
            game.effective_price = _ep;
            game.pricing_tier    = _pt;
            return game;
        });
        

        // Visibility-only filter — admins see all games regardless.
        // Completed games always shown (history must never disappear).
        // Player passes if: overall_rating >= minOvr OR goalkeeper_rating >= minGk.
        // Registration is never blocked — only visibility is affected.
        const visibleGames = isAdmin
            ? gamesWithPhotos
            : gamesWithPhotos.filter(game => {
                if (game.game_status === 'completed') return true;
                const { minOvr, minGk } = effectiveMinRating(game);
                return playerOvr >= minOvr || (minGk > 0 && playerGk >= minGk);
            });

        res.json(visibleGames);
    } catch (error) {
        console.error('Error fetching games:', error);
        res.status(500).json({ error: 'Failed to fetch games' });
    }
});

// Get completed games
app.get('/api/games/completed', authenticateToken, async (req, res) => {
    try {
        // FIX-074: Add pagination and replace correlated subqueries with JOIN aggregation
        const limit = Math.min(parseInt(req.query.limit) || 500, 1000);
        const offset = Math.max(parseInt(req.query.offset) || 0, 0);

        // Admins/superadmins see ALL completed games; regular players see only their own
        const isAdmin = req.user.role === 'admin' || req.user.role === 'superadmin';
        const playerFilter = isAdmin ? '' : `AND EXISTS (
                SELECT 1 FROM registrations r2
                WHERE r2.game_id = g.id AND r2.player_id = $3 AND r2.status = 'confirmed'
              )`;

        // FIX-319 (ROW Day 3): Coventry hard-wall / discovery firewall on completed games.
        // Same semantics as /api/games — admins bypass, others scope by visible tenants.
        const visScope = await getVisibleTenantContext(req.user.playerId);

        const result = await pool.query(`
            SELECT g.*, v.name as venue_name,
                   v.background_image_filename AS venue_background_image, v.photo_url AS venue_photo,
                   COALESCE(rc.confirmed_count, 0) + COALESCE(gc.guest_count, 0) AS current_players,
                   p.full_name as motm_winner_name,
                   p.alias as motm_winner_alias,
                   gs.series_name,
                   opp_comp.logo_url AS opponent_logo_url, opp_comp.star_rating AS opponent_star_rating,
                   -- Player's result for this game (NULL if not a participant — avoids showing LOSS for admin-only view)
                   CASE
                     WHEN NOT EXISTS (
                       SELECT 1 FROM registrations r_part
                       WHERE r_part.game_id = g.id AND r_part.player_id = $3 AND r_part.status = 'confirmed'
                     ) THEN NULL
                     WHEN g.winning_team IS NULL OR g.winning_team = '' THEN 'draw'
                     -- vs_external: all confirmed TF players win when winning_team = red
                     WHEN g.team_selection_type = 'vs_external' AND LOWER(g.winning_team) = 'red' THEN 'win'
                     WHEN g.team_selection_type = 'vs_external' AND LOWER(g.winning_team) = 'blue' THEN 'loss'
                     WHEN EXISTS (
                       SELECT 1 FROM team_players tp2
                       JOIN teams t2 ON t2.id = tp2.team_id
                       WHERE tp2.player_id = $3 AND t2.game_id = g.id
                         AND LOWER(t2.team_name) = LOWER(g.winning_team)
                     ) THEN 'win'
                     ELSE 'loss'
                   END AS my_result,
                   -- Awards this player won in this game
                   (SELECT json_agg(json_build_object('award_type', ga.award_type))
                    FROM game_awards ga
                    WHERE ga.game_id = g.id AND ga.recipient_player_id = $3) AS my_awards
            FROM games g
            LEFT JOIN venues v ON v.id = g.venue_id
            LEFT JOIN players p ON p.id = g.motm_winner_id
            LEFT JOIN game_series gs ON gs.id = g.series_id
            LEFT JOIN opponents opp_comp ON opp_comp.id = g.opponent_id
            LEFT JOIN (
                SELECT game_id, COUNT(*) AS confirmed_count
                FROM registrations WHERE status = 'confirmed'
                GROUP BY game_id
            ) rc ON rc.game_id = g.id
            LEFT JOIN (
                SELECT game_id, COUNT(*) AS guest_count
                FROM game_guests GROUP BY game_id
            ) gc ON gc.game_id = g.id
            WHERE g.game_status = 'completed'
              ${playerFilter}
              AND ($4 = TRUE OR (g.tenant_id IS NULL AND $5 = TRUE) OR g.tenant_id = ANY($6::uuid[]) OR ($7 = TRUE AND g.tenant_id IS NOT NULL))
            ORDER BY g.game_date DESC
            LIMIT $1 OFFSET $2
        `, [limit, offset, req.user.playerId, isAdmin, visScope.includeTfRoot, visScope.tenantIds, visScope.includeAllPublicTenants]);
        
        // Map venue names to their photo URLs
        const venuePhotoMap = {
            'Daimler Green - Astro': 'https://totalfooty.co.uk/assets/Daimler_Green.jpg',
            'Daimler Green - Grass': 'https://totalfooty.co.uk/assets/Daimler_Green_Grass.webp',
            'Daimler Green': 'https://totalfooty.co.uk/assets/Daimler_Green.jpg',
            'Daimler Green Community Centre': 'https://totalfooty.co.uk/assets/Daimler_Green.jpg',
            'Corpus Christi': 'https://totalfooty.co.uk/assets/Corpus_Christi.jpg',
            'War Memorial Park': 'https://totalfooty.co.uk/assets/war_memorial_park.jpg',
            'Memorial Park': 'https://totalfooty.co.uk/assets/war_memorial_park.jpg',
            'Powerleague': 'https://totalfooty.co.uk/assets/Powerleague.jpeg',
            'Power League': 'https://totalfooty.co.uk/assets/Powerleague.jpeg',
            'Coventry Powerleague': 'https://totalfooty.co.uk/assets/Powerleague.jpeg',
            'Powerleague Coventry': 'https://totalfooty.co.uk/assets/Powerleague.jpeg',
            'Sidney Stringer': 'https://totalfooty.co.uk/assets/Sidney_Stringer_Academy.jpg',
            'Sidney Stringer Academy': 'https://totalfooty.co.uk/assets/Sidney_Stringer_Academy.jpg',
                'Nuneaton Academy':        'https://totalfooty.co.uk/assets/nuneaton_academy.webp',
                'Tudor Grange Academy':     'https://totalfooty.co.uk/assets/Tudor-Grange-pitch.webp',
                'Light Hall School'   :     'https://totalfooty.co.uk/assets/venues/light-hall-school.jpg',
        };
        
        // Format the response
        const games = result.rows.map(game => {
            const { price: _ep, tier: _pt } = getEffectivePrice(game);
            return {
                ...game,
                motm_winner_name: game.motm_winner_alias || game.motm_winner_name,
                venue_photo: game.venue_background_image
                    ? `https://totalfooty.co.uk/assets/venues/${game.venue_background_image}`
                    : (game.venue_name && venuePhotoMap[game.venue_name] ? venuePhotoMap[game.venue_name] : (game.venue_photo || null)),
                game_time: new Date(game.game_date).toLocaleTimeString('en-GB', { hour: '2-digit', minute: '2-digit' }),
                game_day: new Date(game.game_date).toLocaleDateString('en-US', { weekday: 'long' }),
                effective_price: _ep,
                pricing_tier:    _pt,
            };
        });
        
        res.json(games);
    } catch (error) {
        console.error('Get completed games error:', error);
        res.status(500).json({ error: 'Failed to get completed games' });
    }
});

// GET /api/games/needing-refs — games with refs_required > 0 and unfilled slots
// Used by referee badge holders in "Ref mode"
app.get('/api/games/needing-refs', authenticateToken, async (req, res) => {
    try {
        // Verify player has Referee badge
        const badgeCheck = await pool.query(
            `SELECT 1 FROM player_badges pb JOIN badges b ON b.id = pb.badge_id
             WHERE pb.player_id = $1 AND b.name = 'Referee'`,
            [req.user.playerId]
        );
        if (!badgeCheck.rows.length) {
            return res.status(403).json({ error: 'Referee badge required' });
        }

        // FIX-319 (ROW Day 3): scope ref-eligible games to player's visible tenants.
        const visScope = await getVisibleTenantContext(req.user.playerId);

        const result = await pool.query(`
            SELECT g.id, g.game_url, g.game_date, g.format, g.refs_required,
                   g.ref_pay, g.game_status,
                   v.name AS venue_name,
                   (SELECT COUNT(*) FROM game_referees gr
                    WHERE gr.game_id = g.id AND gr.status = 'confirmed') AS confirmed_refs,
                   (SELECT COUNT(*) FROM game_referees gr
                    WHERE gr.game_id = g.id AND gr.player_id = $1) AS my_application,
                   (SELECT status FROM game_referees gr
                    WHERE gr.game_id = g.id AND gr.player_id = $1 LIMIT 1) AS my_status,
                   EXISTS(SELECT 1 FROM registrations r
                          WHERE r.game_id = g.id AND r.player_id = $1
                          AND r.status = 'confirmed') AS also_playing
            FROM games g
            LEFT JOIN venues v ON v.id = g.venue_id
            WHERE g.refs_required > 0
              AND g.game_status IN ('available','confirmed')
              AND g.game_date >= NOW()
              -- FIX-319 (ROW Day 3): refs only see games from their visible tenants.
              -- FIX-335 Phase 4.1: cross-tenant discovery extends this to any
              -- active tenant when the player opts in via show_cross_tenant_games.
              AND ((g.tenant_id IS NULL AND $2 = TRUE) OR g.tenant_id = ANY($3::uuid[]) OR ($4 = TRUE AND g.tenant_id IS NOT NULL))
            ORDER BY g.game_date ASC
        `, [req.user.playerId, visScope.includeTfRoot, visScope.tenantIds, visScope.includeAllPublicTenants]);

        res.json(result.rows);
    } catch (error) {
        console.error('Needing refs error:', error);
        res.status(500).json({ error: 'Failed to fetch games needing referees' });
    }
});

app.get('/api/games/:id', authenticateToken, async (req, res) => {
    try {
        // Reject malformed UUIDs cleanly (truncated URLs, bots, bad clients)
        // so Postgres doesn't throw 22P02 and spam the Render error logs.
        if (!isValidUuid(req.params.id)) return res.status(400).json({ error: 'Invalid game id' });
        const gameResult = await pool.query(`
            SELECT g.*, v.name as venue_name, v.address as venue_address, v.region as venue_region, v.special_instructions as venue_special_instructions, v.notes as venue_notes, v.pitch_location as venue_pitch_location,
                   v.background_image_filename AS venue_background_image, v.photo_url AS venue_photo,
                   g.early_bird_price, g.super_early_bird_price,
                   opp_pub.logo_url AS opponent_logo_url, opp_pub.star_rating AS opponent_star_rating, opp_pub.social_instagram AS opponent_social_instagram, opp_pub.social_twitter AS opponent_social_twitter, opp_pub.social_website AS opponent_social_website,
                   gs.series_name,
                   g.format as game_format,
                   TO_CHAR(g.game_date AT TIME ZONE 'Europe/London', 'HH24:MI') as game_time,
                   ((SELECT COUNT(*) FROM registrations WHERE game_id = g.id AND status IN ('confirmed', 'rsvp')) + (SELECT COUNT(*) FROM game_guests WHERE game_id = g.id)) as current_players,
                   ROUND((SELECT AVG(rating) FROM (
                       SELECT CASE WHEN UPPER(TRIM(r.position_preference)) = 'GK'
                                   THEN NULLIF(p.goalkeeper_rating, 0)
                                   ELSE p.overall_rating END AS rating
                       FROM registrations r JOIN players p ON p.id = r.player_id
                       WHERE r.game_id = g.id AND r.status IN ('confirmed', 'rsvp') /* FIX-315: include RSVPs in live_avg_ovr */
                       UNION ALL
                       SELECT CASE WHEN gg.position_classification = 'gk'
                                   THEN NULLIF(gg.goalkeeper_rating, 0)
                                   ELSE gg.overall_rating END AS rating
                       FROM game_guests gg WHERE gg.game_id = g.id
                   ) ratings WHERE rating IS NOT NULL)::numeric, 1) as live_avg_ovr,
                   (SELECT COUNT(*) FROM registrations WHERE game_id = g.id AND status IN ('confirmed', 'rsvp') AND UPPER(TRIM(position_preference)) = 'GK') as gk_count /* FIX-315 */,
                   COALESCE((SELECT COUNT(*) FROM registrations r JOIN players p ON p.id = r.player_id WHERE r.game_id = g.id AND r.status = 'confirmed' AND p.is_organiser = true)::int, 0) as confirmed_organiser_count,
                   (SELECT status FROM registrations WHERE game_id = g.id AND player_id = $2 LIMIT 1) as registration_status,
                   (SELECT backup_type FROM registrations WHERE game_id = g.id AND player_id = $2 LIMIT 1) as my_backup_type,
                   -- P2.3: amount paid by current user (drives drop-out penalty dialog in game.html)
                   COALESCE((SELECT amount_paid      FROM registrations WHERE game_id = g.id AND player_id = $2 LIMIT 1), 0) as my_amount_paid,
                   COALESCE((SELECT amount_paid_free FROM registrations WHERE game_id = g.id AND player_id = $2 LIMIT 1), 0) as my_amount_paid_free,
                   -- FIX-315: RSVP system state.
                   (SELECT COUNT(*) FROM registrations WHERE game_id = g.id AND status = 'rsvp') as rsvp_count,
                   (SELECT COUNT(*) FROM registrations WHERE game_id = g.id AND status = 'backup' AND backup_type = 'confirmed_backup') as confirmed_backup_count,
                   (SELECT COUNT(*) FROM registrations WHERE game_id = g.id AND status = 'bumped') as bumped_count,
                   (SELECT rsvp_deadline FROM registrations WHERE game_id = g.id AND player_id = $2 AND status = 'rsvp' LIMIT 1) as my_rsvp_deadline,
                   g.accelerator_fired_at,
                   g.accelerator_fired_by_player_id
            FROM games g
            LEFT JOIN venues v ON v.id = g.venue_id
            LEFT JOIN game_series gs ON gs.id = g.series_id
            LEFT JOIN opponents opp_pub ON opp_pub.id = g.opponent_id
            WHERE g.id = $1
        `, [req.params.id, req.user.playerId]);
        
        if (gameResult.rows.length === 0) {
            return res.status(404).json({ error: 'Game not found' });
        }
        
        const game = gameResult.rows[0];

        // FIX-067: Enforce exclusivity — non-admins cannot access CLM/allstars games without the badge
        const isAdminUser = req.user.role === 'admin' || req.user.role === 'superadmin';
        if (!isAdminUser && game.exclusivity === 'clm') {
            const hasCLM = await pool.query(
                `SELECT 1 FROM player_badges pb JOIN badges b ON pb.badge_id = b.id WHERE pb.player_id = $1 AND b.name = 'CLM'`,
                [req.user.playerId]
            );
            if (!hasCLM.rows.length) return res.status(403).json({ error: 'Access denied' });
        }
        if (!isAdminUser && game.exclusivity === 'allstars') {
            const hasAllstars = await pool.query(
                `SELECT 1 FROM player_badges pb JOIN badges b ON pb.badge_id = b.id WHERE pb.player_id = $1 AND b.name = 'Allstars'`,
                [req.user.playerId]
            );
            if (!hasAllstars.rows.length) return res.status(403).json({ error: 'Access denied' });
        }

        game.max_gk_slots = game.team_selection_type === 'vs_external' ? 1 : game.team_selection_type === 'tournament' ? (game.tournament_team_count || 4) : 2;
        game.gk_count = parseInt(game.gk_count) || 0;
        
        // Get registered players (confirmed)
        const playersResult = await pool.query(`
            SELECT p.id, p.full_name, p.alias, p.squad_number, p.reliability_tier, 
                   r.position_preference, r.status
            FROM registrations r
            JOIN players p ON p.id = r.player_id
            WHERE r.game_id = $1 AND r.status = 'confirmed'
            ORDER BY r.registered_at
        `, [req.params.id]);
        
        game.registered_players = playersResult.rows;
        
        // Get backup players
        const backupsResult = await pool.query(`
            SELECT p.id, p.full_name, p.alias, p.squad_number,
                   r.backup_type, r.position_preference, r.registered_at
            FROM registrations r
            JOIN players p ON p.id = r.player_id
            WHERE r.game_id = $1 AND r.status = 'backup'
            ORDER BY 
                CASE r.backup_type 
                    WHEN 'confirmed_backup' THEN 1 
                    WHEN 'gk_backup' THEN 2 
                    ELSE 3 
                END,
                r.registered_at ASC
        `, [req.params.id]);
        
        game.backup_players = backupsResult.rows;

        // ORGANISER-003: Add confirmed organiser count for client-side capacity calculation
        if (game.requires_organiser) {
            const orgCount = await pool.query(`
                SELECT COUNT(*) AS cnt FROM registrations r
                JOIN players p ON p.id = r.player_id
                WHERE r.game_id = $1 AND r.status = 'confirmed' AND p.is_organiser = true
            `, [req.params.id]);
            game.confirmed_organiser_count = parseInt(orgCount.rows[0].cnt) || 0;
        } else {
            game.confirmed_organiser_count = 0;
        }

        // ORGANISER-COMP: Expose current comp count + availability flag so the player-facing
        // game modal can show the correct "ORGANISER SIGN UP" button (free) vs the regular
        // paid signup button. Comp cap is 6 per game (matches /register endpoint logic).
        // The flag is only truthy if the current user is actually an organiser AND a comp slot
        // is still available on this game.
        const compCountRow = await pool.query(
            "SELECT COUNT(*) AS cnt FROM registrations WHERE game_id = $1 AND is_comped = TRUE",
            [req.params.id]
        );
        const compCount = parseInt(compCountRow.rows[0].cnt) || 0;
        game.comp_count = compCount;
        // FIX-329 (ROW Day 15): tenant-aware comp_cap (was hardcoded 6).
        // For TF root (tenant_id NULL) helper returns 6 → identical behaviour.
        const _fix329Allowance = await _fix329GetAllowance(game.tenant_id);
        game.comp_cap = _fix329Allowance.per_game;
        game.comp_discount_pct = _fix329Allowance.pct_discount;
        // Only compute eligibility for the calling user — avoids leaking organiser status
        const callerCheck = await pool.query(
            'SELECT is_organiser FROM players WHERE id = $1', [req.user.playerId]
        );
        const callerIsOrganiser = !!callerCheck.rows[0]?.is_organiser;
        // Eligibility: allowance enabled + per-game cap not reached.
        // Weekly cap is NOT checked here (cheap GET); /register enforces it
        // authoritatively at registration time.
        game.organiser_comp_available = callerIsOrganiser
            && _fix329Allowance.enabled
            && compCount < _fix329Allowance.per_game;
        
        // Map venue names to their photo URLs
        const venuePhotoMap = {
            'Daimler Green - Astro': 'https://totalfooty.co.uk/assets/Daimler_Green.jpg',
            'Daimler Green - Grass': 'https://totalfooty.co.uk/assets/Daimler_Green_Grass.webp',
            'Daimler Green': 'https://totalfooty.co.uk/assets/Daimler_Green.jpg',
            'Daimler Green Community Centre': 'https://totalfooty.co.uk/assets/Daimler_Green.jpg',
            'Corpus Christi': 'https://totalfooty.co.uk/assets/Corpus_Christi.jpg',
            'War Memorial Park': 'https://totalfooty.co.uk/assets/war_memorial_park.jpg',
            'Memorial Park': 'https://totalfooty.co.uk/assets/war_memorial_park.jpg',
            'Powerleague': 'https://totalfooty.co.uk/assets/Powerleague.jpeg',
            'Power League': 'https://totalfooty.co.uk/assets/Powerleague.jpeg',
            'Coventry Powerleague': 'https://totalfooty.co.uk/assets/Powerleague.jpeg',
            'Powerleague Coventry': 'https://totalfooty.co.uk/assets/Powerleague.jpeg',
            'Sidney Stringer': 'https://totalfooty.co.uk/assets/Sidney_Stringer_Academy.jpg',
            'Sidney Stringer Academy': 'https://totalfooty.co.uk/assets/Sidney_Stringer_Academy.jpg',
                'Nuneaton Academy':        'https://totalfooty.co.uk/assets/nuneaton_academy.webp',
                'Tudor Grange Academy':     'https://totalfooty.co.uk/assets/Tudor-Grange-pitch.webp',
                'Light Hall School'   :     'https://totalfooty.co.uk/assets/venues/light-hall-school.jpg',
        };
        
        // Resolve venue hero photo: admin-set background_image_filename -> hardcoded map -> legacy DB photo_url
        if (game.venue_background_image) {
            game.venue_photo = `https://totalfooty.co.uk/assets/venues/${game.venue_background_image}`;
        } else if (game.venue_name && venuePhotoMap[game.venue_name]) {
            game.venue_photo = venuePhotoMap[game.venue_name];
        }
        
        // Check if current user has guest(s) on this game
        if (req.user && req.user.playerId) {
            try {
                const guestCheck = await pool.query(
                    'SELECT id, guest_name, guest_number, overall_rating FROM game_guests WHERE game_id = $1 AND invited_by = $2 ORDER BY guest_number ASC',
                    [req.params.id, req.user.playerId]
                );
                game.my_guests = guestCheck.rows;
                game.my_guest = guestCheck.rows.length > 0 ? guestCheck.rows[0] : null;
            } catch (guestErr) {
                game.my_guests = [];
                game.my_guest = null;
            }
        }
        
        // For tournament games, add per-team signup counts so UI can show slots remaining
        if (game.team_selection_type === 'tournament' && game.tournament_team_count) {
            try {
                const teamCountsResult = await pool.query(`
                    SELECT tournament_team_preference, COUNT(*) as count
                    FROM registrations
                    WHERE game_id = $1 AND status = 'confirmed' AND tournament_team_preference IS NOT NULL
                    GROUP BY tournament_team_preference
                `, [req.params.id]);
                game.tournament_team_counts = {};
                teamCountsResult.rows.forEach(r => {
                    game.tournament_team_counts[r.tournament_team_preference] = parseInt(r.count);
                });
                game.tournament_team_max = Math.floor(parseInt(game.max_players) / parseInt(game.tournament_team_count));
            } catch (e) {
                game.tournament_team_counts = {};
                game.tournament_team_max = null;
            }
        }
        
        // FIX-03: server-side boolean so frontend never needs to re-derive from team_selection_type string
        game.show_pair_avoid = !['draft_memory', 'vs_external'].includes((game.team_selection_type || '').trim().toLowerCase()) && !game.is_venue_clash && !game.venue_clash_team1_name;

        // Attach effective pricing so frontend signup modal always has the right cost
        const _ep = getEffectivePrice(game);
        game.effective_price = _ep.price;
        game.pricing_tier    = _ep.tier;
        // Ensure numeric types for fields the modal uses
        game.max_players      = parseInt(game.max_players) || 0;
        game.current_players  = parseInt(game.current_players) || 0;
        game.cost_per_player  = parseFloat(game.cost_per_player) || 0;

        res.json(game);
    } catch (error) {
        console.error('Error fetching game:', error);
        res.status(500).json({ error: 'Failed to fetch game' });
    }
});

