// ═══════════════════════════════════════════════════════════════════════════
// A2 — Guest invite token endpoints
//
// Token is auto-created when host adds a guest. Two endpoints:
//   GET  /api/guest-invite/:token        — landing page metadata (public)
//   POST /api/guest-invite/:token/claim  — friend claims (authenticated)
//
// Cashback to host is paid out separately by the game-completion hook;
// these endpoints just mark state.
// ═══════════════════════════════════════════════════════════════════════════

const A2_CASHBACK_AMOUNT = 2.00;

// A2-A61: Pay £2 cashback to hosts whose guest invite tokens were claimed by NEW users.
// Reusable helper called from BOTH /complete (standard) AND /finalise-tournament endpoints.
// Runs in setImmediate-style async loop with per-token transactions for isolation.
// Idempotent: only acts on tokens with cashback_status = 'new_user_pending'.
async function _a2PayPendingCashbacks(gameId) {
    try {
        const pending = await pool.query(
            `SELECT t.token, t.host_player_id, t.guest_name
               FROM guest_invite_tokens t
              WHERE t.game_id = $1
                AND t.cashback_status = 'new_user_pending'
              LIMIT 100`,
            [gameId]
        );
        for (const tok of pending.rows) {
            const cbClient = await pool.connect();
            try {
                await cbClient.query('BEGIN');
                const lockRes = await cbClient.query(
                    `SELECT cashback_status FROM guest_invite_tokens WHERE token = $1 FOR UPDATE`,
                    [tok.token]
                );
                if (lockRes.rows[0]?.cashback_status !== 'new_user_pending') {
                    await cbClient.query('ROLLBACK');
                    continue;
                }
                // FIX-410i (audit v2): £2 guest-conversion cashback REMOVED. Guest
                // conversions now earn STANDARD RAF (host linked as referred_by at
                // claim/signup; RAF suppression lifted). No payment here — just retire
                // the token so it doesn't linger as 'new_user_pending'.
                await cbClient.query(
                    `UPDATE guest_invite_tokens SET cashback_status = 'superseded_raf' WHERE token = $1`,
                    [tok.token]
                );
                await cbClient.query('COMMIT');
                console.log(`A2: guest-conversion cashback superseded by RAF for token ${tok.token.substring(0,8)}... (game ${gameId})`);
            } catch (e) {
                await cbClient.query('ROLLBACK').catch(() => {});
                console.error(`✗ A2: Cashback failed for token ${tok.token.substring(0,8)}... game ${gameId}:`, e.message);
            } finally {
                cbClient.release();
            }
        }
    } catch (e) {
        // Pre-migration: table missing → 42P01. Caught here, game completion unaffected.
        console.error('A2 cashback batch error (non-fatal):', e.message);
    }
}

// Landing endpoint — anyone can call (rate-limited).
// Returns: host name, guest name, game info, claim status.
// Does NOT trigger any state change.
app.get('/api/guest-invite/:token', publicEndpointLimiter, async (req, res) => {
    try {
        const { token } = req.params;
        if (!token || !/^[a-f0-9]{32}$/.test(token)) {
            return res.status(400).json({ valid: false, error: 'Invalid token format' });
        }

        const r = await pool.query(`
            SELECT
                t.token,
                t.guest_name,
                t.claimed_by_player_id,
                t.claimed_at,
                p.alias        AS host_alias,
                p.full_name    AS host_full_name,
                g.id           AS game_id,
                g.game_date,
                g.game_status,
                v.name         AS venue_name
            FROM guest_invite_tokens t
            JOIN players p ON p.id = t.host_player_id
            JOIN games   g ON g.id = t.game_id
            LEFT JOIN venues v ON v.id = g.venue_id
            WHERE t.token = $1
        `, [token]);

        if (r.rows.length === 0) {
            return res.status(404).json({ valid: false, error: 'Invite not found' });
        }
        const row = r.rows[0];

        return res.json({
            valid: !row.claimed_by_player_id,
            already_claimed: !!row.claimed_by_player_id,
            host: {
                alias: row.host_alias || row.host_full_name,
                full_name: row.host_full_name
            },
            guest_name: row.guest_name,
            game: {
                id:          row.game_id,
                game_date:   row.game_date,
                game_status: row.game_status,
                venue_name:  row.venue_name
            }
        });
    } catch (e) {
        console.error('guest-invite/get:', e);
        return res.status(500).json({ valid: false, error: 'Failed to load invite' });
    }
});

// Claim endpoint — friend (authenticated) claims their guest record.
// Two paths:
//   1. Friend just signed up (brand new account): mark claim, set
//      claim_was_new_user=TRUE, set cashback_status='new_user_pending'.
//      Cashback fires on game completion.
//   2. Friend was already a TF member: mark claim, set
//      claim_was_new_user=FALSE, set cashback_status='existing_user'.
//      Game result/awards still flow into their stats normally; OVR unchanged.
//
// Stat inheritance for NEW users happens at signup time, not here. The
// signup endpoint reads guest_invite token from the URL param and copies
// stats over before this claim endpoint is hit.
app.post('/api/guest-invite/:token/claim', authenticateToken, async (req, res) => {
    const { token } = req.params;
    const friendId = req.user.playerId;
    if (!token || !/^[a-f0-9]{32}$/.test(token)) {
        return res.status(400).json({ error: 'Invalid token format' });
    }
    const client = await pool.connect();
    try {
        await client.query('BEGIN');

        // Lock token row
        const tRes = await client.query(
            `SELECT * FROM guest_invite_tokens WHERE token = $1 FOR UPDATE`,
            [token]
        );
        if (tRes.rows.length === 0) {
            await client.query('ROLLBACK');
            return res.status(404).json({ error: 'Invite not found' });
        }
        const t = tRes.rows[0];
        if (t.claimed_by_player_id) {
            // A2-A85: if THIS user already claimed it (e.g. via signup auto-claim),
            // return success with game info so the confirmation modal still shows.
            // Other users → 400 (truly already claimed by someone else).
            if (t.claimed_by_player_id === friendId) {
                await client.query('ROLLBACK');
                // Fetch game info for the same response shape as a fresh claim
                const gRes = await pool.query(
                    `SELECT g.game_date, g.game_status, v.name AS venue_name,
                            p.alias AS host_alias, p.full_name AS host_full_name
                       FROM games g
                       LEFT JOIN venues v ON v.id = g.venue_id
                       JOIN players p ON p.id = $1
                      WHERE g.id = $2`,
                    [t.host_player_id, t.game_id]
                );
                const g = gRes.rows[0] || {};
                const hostName = g.host_alias || g.host_full_name || 'host';
                return res.json({
                    success: true,
                    already_claimed_by_self: true,
                    game_id: t.game_id,
                    game_date: g.game_date,
                    game_status: g.game_status,
                    venue_name: g.venue_name,
                    host_alias: hostName,
                    is_new_user: t.claim_was_new_user,
                    cashback_status: t.cashback_status,
                    message: `Already linked to ${hostName}.`
                });
            }
            await client.query('ROLLBACK');
            return res.status(400).json({ error: 'This invite has already been claimed' });
        }
        if (friendId === t.host_player_id) {
            await client.query('ROLLBACK');
            return res.status(400).json({ error: "You can't claim your own invite" });
        }

        // Determine if friend was a brand new account (signed_up_via_guest_invite=TRUE)
        // or an existing user. The signup endpoint sets the flag on new accounts only.
        // A2-A56: SAVEPOINT around column read so pre-migration `42703` doesn't poison
        // the parent transaction. If column missing → treat friend as existing user
        // (so cashback won't fire — safe default).
        let isNewUser = false;
        try {
            await client.query('SAVEPOINT a2_col_check');
            const fpRes = await client.query(
                `SELECT signed_up_via_guest_invite FROM players WHERE id = $1`,
                [friendId]
            );
            isNewUser = !!fpRes.rows[0]?.signed_up_via_guest_invite;
            await client.query('RELEASE SAVEPOINT a2_col_check');
        } catch (e) {
            try { await client.query('ROLLBACK TO SAVEPOINT a2_col_check'); } catch (_) {}
            try { await client.query('RELEASE SAVEPOINT a2_col_check'); } catch (_) {}
            if (e.code === '42703') {
                console.warn('[A2 claim] signed_up_via_guest_invite column missing — treating as existing user (safe default).');
                isNewUser = false;
            } else {
                throw e;  // unexpected error → bubble up
            }
        }

        // Determine cashback status:
        //   - If admin invite: stays 'admin_invite' (host didn't pay, no cashback)
        //   - If new user:     'new_user_pending' (cashback fires on game completion)
        //   - If existing:     'existing_user' (no cashback ever)
        let newCashbackStatus;
        if (t.cashback_status === 'admin_invite') {
            newCashbackStatus = 'admin_invite';
        } else if (isNewUser) {
            newCashbackStatus = 'superseded_raf'; // FIX-410i: guest conversions now earn standard RAF
        } else {
            newCashbackStatus = 'existing_user';
        }

        await client.query(
            `UPDATE guest_invite_tokens
                SET claimed_by_player_id = $1,
                    claimed_at = NOW(),
                    claim_was_new_user = $2,
                    cashback_status = $3
              WHERE token = $4`,
            [friendId, isNewUser, newCashbackStatus, token]
        );

        // FIX-410i: link the host as referrer so the conversion earns STANDARD RAF
        // (welcome + per-game per the tenant's RAF controls). New user, not self, not already referred.
        if (isNewUser && String(t.host_player_id) !== String(friendId)) {
            await client.query(`UPDATE players SET referred_by = $1 WHERE id = $2 AND referred_by IS NULL`, [t.host_player_id, friendId]);
        }

        await client.query('COMMIT');

        // A2-A34: audit log fires AFTER commit on a separate connection (pool, not client).
        // Inside-transaction logging risks aborting the whole claim if the audit insert
        // fails — and the token update is the source of truth, audit is bookkeeping.
        setImmediate(() => {
            gameAuditLog(pool, t.game_id, null, 'guest_invite_claimed',
                `Token: ${token.substring(0, 8)}... | Guest: ${t.guest_name} | Claimed by: ${friendId} | New user: ${isNewUser} | Cashback: ${newCashbackStatus}`)
                .catch(() => { /* non-critical */ });
        });

        // Fetch game info for the confirmation message
        const gRes = await pool.query(
            `SELECT g.game_date, g.game_status, v.name AS venue_name,
                    p.alias AS host_alias, p.full_name AS host_full_name
               FROM games g
               LEFT JOIN venues v ON v.id = g.venue_id
               JOIN players p ON p.id = $1
              WHERE g.id = $2`,
            [t.host_player_id, t.game_id]
        );
        const g = gRes.rows[0] || {};
        const hostName = g.host_alias || g.host_full_name || 'host';

        return res.json({
            success: true,
            game_id: t.game_id,
            game_date: g.game_date,
            game_status: g.game_status,
            venue_name: g.venue_name,
            host_alias: hostName,
            is_new_user: isNewUser,
            cashback_status: newCashbackStatus,
            message: `You've been signed up by ${hostName}.`
        });
    } catch (e) {
        await client.query('ROLLBACK').catch(() => {});
        console.error('guest-invite/claim:', e);
        return res.status(500).json({ error: 'Failed to claim invite' });
    } finally {
        client.release();
    }
});

// Remove +1 guest from a game (with refund)
app.delete('/api/games/:id/remove-guest', authenticateToken, async (req, res) => {
    const client = await pool.connect();
    try {
        const gameId = req.params.id;
        const playerId = req.user.playerId;
        const { guestId } = req.body;

        await client.query('BEGIN');

        // Check game isn't locked or teams generated
        const gameCheck = await client.query(
            'SELECT player_editing_locked, teams_generated, team_selection_type FROM games WHERE id = $1 FOR UPDATE',
            [gameId]
        );
        // Admins bypass the lock — they shouldn't be blocked by their own edit session
        const isAdminRemovingGuest = req.user.role === 'admin' || req.user.role === 'superadmin';
        if (gameCheck.rows[0]?.player_editing_locked && !isAdminRemovingGuest) {
            await client.query('ROLLBACK');
            // FIX-357: preempt
            const _preempt = await _recordSignupIntent(req.params.id, req.user.playerId, 'guest_remove');
            return res.status(423).json(_preempt);
        }
        if (gameCheck.rows[0]?.teams_generated && gameCheck.rows[0]?.team_selection_type !== 'draft_memory') {
            await client.query('ROLLBACK');
            return res.status(400).json({ error: 'Cannot remove guest - teams already generated.' });
        }

        // Find and delete the specific guest.
        // Admins can remove any guest regardless of who invited them — no invited_by filter.
        // Non-admins can only remove their own guests.
        let guestResult;
        if (guestId) {
            if (isAdminRemovingGuest) {
                guestResult = await client.query(
                    'DELETE FROM game_guests WHERE id = $1 AND game_id = $2 RETURNING guest_name, amount_paid, amount_paid_free, guest_number, invited_by',
                    [guestId, gameId]
                );
            } else {
                guestResult = await client.query(
                    'DELETE FROM game_guests WHERE id = $1 AND game_id = $2 AND invited_by = $3 RETURNING guest_name, amount_paid, amount_paid_free, guest_number, invited_by',
                    [guestId, gameId, playerId]
                );
            }
        } else {
            // Fallback: remove the last-added guest for this player (non-admin only path)
            guestResult = await client.query(
                'DELETE FROM game_guests WHERE id = (SELECT id FROM game_guests WHERE game_id = $1 AND invited_by = $2 ORDER BY guest_number DESC LIMIT 1) RETURNING guest_name, amount_paid, amount_paid_free, guest_number, invited_by',
                [gameId, playerId]
            );
        }

        if (guestResult.rows.length === 0) {
            await client.query('ROLLBACK');
            client.release();
            return res.status(404).json({ error: 'No guest found for this game' });
        }

        const guest = guestResult.rows[0];
        const refundAmt = parseFloat(guest.amount_paid || 0);
        // Always refund the original inviter, not the admin doing the removal
        const refundTargetId = guest.invited_by || playerId;

        // Lock the refund target's credits row before updating
        await client.query('SELECT id FROM credits WHERE player_id = $1 FOR UPDATE', [refundTargetId]);

        // Refund the inviting player — split real + free bucket restoration.
        const refundFreeAmt = parseFloat(guest.amount_paid_free ?? 0);
        if (refundAmt > 0) {
            await client.query(
                'UPDATE credits SET balance = balance + $1 WHERE player_id = $2',
                [refundAmt, refundTargetId]
            );
            await recordCreditTransaction(client, refundTargetId, refundAmt, 'refund', `Guest (${guest.guest_name}) removed - refund`);
        }
        if (refundFreeAmt > 0) {
            await client.query(
                'UPDATE credits SET free_credit_balance = free_credit_balance + $1, last_updated = CURRENT_TIMESTAMP WHERE player_id = $2',
                [refundFreeAmt, refundTargetId]
            );
            await recordCreditTransaction(client, refundTargetId, refundFreeAmt, 'free_credit', `Guest (${guest.guest_name}) removed - free credit restored`);
        }

        // Re-number remaining guests for the original inviter so numbers stay sequential
        const remaining = await client.query(
            'SELECT id FROM game_guests WHERE game_id = $1 AND invited_by = $2 ORDER BY guest_number ASC',
            [gameId, refundTargetId]
        );
        for (let i = 0; i < remaining.rows.length; i++) {
            await client.query(
                'UPDATE game_guests SET guest_number = $1 WHERE id = $2',
                [i + 1, remaining.rows[i].id]
            );
        }

        await client.query('COMMIT');

        // FIX-235: guest left → squad-avg shifts (especially if GK), recalc dynamic star.
        reviewDynamicStarRating(pool, gameId).catch(() => {});

        res.json({
            message: `${guest.guest_name} removed. £${refundAmt.toFixed(2)} refunded to your balance.`
        });
        setImmediate(() => gameAuditLog(pool, req.body.gameId || req.params.id, null, 'guest_removed',
            `Guest: ${guest.guest_name} | Host: Player ${req.user.playerId} | Refunded: £${refundAmt.toFixed(2)}`));
    } catch (error) {
        await client.query('ROLLBACK').catch(() => {});
        console.error('Remove guest error:', error);
        res.status(500).json({ error: 'Failed to remove guest' });
    } finally {
        client.release();
    }
});

// ── Batch 8 — Guest stat admin override + reset endpoints ─────────────
// PATCH /api/games/:gameId/guests/:guestId/stats
// Admin-only manual edit of a guest's derived stats. Server recomputes
// overall_rating from the 7 outfield stats (or goalkeeper_rating for GK
// guests) and flags is_admin_override = TRUE so the reset button un-greys.
// FIX-249: reverted to requireGameManager (admin/superadmin/CLM admin/
// organiser-of-this-game). User clarified organisers SHOULD be able to
// edit stats. Per-game scope still enforced via requireGameManager's
// organiser-must-be-confirmed-for-this-game check.
app.patch('/api/games/:gameId/guests/:guestId/stats', authenticateToken, requireGameManager, async (req, res) => {
    try {
        const { gameId, guestId } = req.params;
        const {
            defending_rating, strength_rating, fitness_rating,
            pace_rating, shooting_rating, assisting_rating, decisions_rating,
            goalkeeper_rating
        } = req.body;

        // Validate 0..20 for each outfield stat, 0..99 for goalkeeper
        const outfieldKeys = {
            defending_rating, strength_rating, fitness_rating,
            pace_rating, shooting_rating, assisting_rating, decisions_rating
        };
        for (const [k, v] of Object.entries(outfieldKeys)) {
            const n = parseInt(v);
            if (!Number.isFinite(n) || n < 0 || n > 20) {
                return res.status(400).json({ error: `${k} must be an integer 0..20` });
            }
        }
        const gk = parseInt(goalkeeper_rating || 0);
        if (!Number.isFinite(gk) || gk < 0 || gk > 99) {
            return res.status(400).json({ error: 'goalkeeper_rating must be an integer 0..99' });
        }

        // Load the guest to determine classification + previous values
        const existing = await pool.query(
            `SELECT position_classification, defending_rating, strength_rating, fitness_rating,
                    pace_rating, shooting_rating, assisting_rating, decisions_rating,
                    goalkeeper_rating, overall_rating
             FROM game_guests WHERE id = $1 AND game_id = $2`,
            [guestId, gameId]
        );
        if (existing.rows.length === 0) {
            return res.status(404).json({ error: 'Guest not found' });
        }
        const before = existing.rows[0];

        // Recompute overall server-side (never trust client's overall_rating)
        const isGk = before.position_classification === 'gk';
        const newOverall = isGk
            ? gk
            : (parseInt(defending_rating) + parseInt(strength_rating) + parseInt(fitness_rating) +
               parseInt(pace_rating) + parseInt(shooting_rating) + parseInt(assisting_rating) +
               parseInt(decisions_rating));

        await pool.query(
            `UPDATE game_guests SET
                defending_rating = $1, strength_rating = $2, fitness_rating = $3,
                pace_rating = $4, shooting_rating = $5, assisting_rating = $6, decisions_rating = $7,
                goalkeeper_rating = $8, overall_rating = $9, is_admin_override = TRUE
             WHERE id = $10 AND game_id = $11`,
            [parseInt(defending_rating), parseInt(strength_rating), parseInt(fitness_rating),
             parseInt(pace_rating), parseInt(shooting_rating), parseInt(assisting_rating), parseInt(decisions_rating),
             gk, newOverall, guestId, gameId]
        );

        // FIX-235: guest's OVR/GK changed → squad-avg shifts, recalc dynamic star.
        reviewDynamicStarRating(pool, gameId).catch(() => {});

        await gameAuditLog(pool, gameId, req.user.playerId, 'guest_stats_overridden', JSON.stringify({
            guest_id: guestId,
            before: {
                def: before.defending_rating, str: before.strength_rating, fit: before.fitness_rating,
                pac: before.pace_rating, sht: before.shooting_rating, ast: before.assisting_rating,
                dec: before.decisions_rating, gk: before.goalkeeper_rating, overall: before.overall_rating
            },
            after: {
                def: parseInt(defending_rating), str: parseInt(strength_rating), fit: parseInt(fitness_rating),
                pac: parseInt(pace_rating), sht: parseInt(shooting_rating), ast: parseInt(assisting_rating),
                dec: parseInt(decisions_rating), gk, overall: newOverall
            }
        }));

        res.json({ success: true, overall_rating: newOverall, is_admin_override: true });
    } catch (error) {
        console.error('Guest stats override error:', error);
        res.status(500).json({ error: 'Failed to update guest stats' });
    }
});

// POST /api/games/:gameId/guests/:guestId/reset-stats
// Re-runs derivation from current parent stats + stored relative_rating +
// position_classification. Clears is_admin_override and refreshes
// derived_from_parent_ovr to the parent's current overall.
// FIX-249: reverted to requireGameManager for parity with the PATCH stats
// endpoint. Organisers of this game can reset overrides on their guests.
app.post('/api/games/:gameId/guests/:guestId/reset-stats', authenticateToken, requireGameManager, async (req, res) => {
    try {
        const { gameId, guestId } = req.params;

        const guestResult = await pool.query(
            `SELECT gg.invited_by, gg.relative_rating, gg.position_classification
             FROM game_guests gg
             WHERE gg.id = $1 AND gg.game_id = $2`,
            [guestId, gameId]
        );
        if (guestResult.rows.length === 0) {
            return res.status(404).json({ error: 'Guest not found' });
        }
        const { invited_by, relative_rating, position_classification } = guestResult.rows[0];

        const parentResult = await pool.query(
            `SELECT overall_rating, defending_rating, strength_rating, fitness_rating,
                    pace_rating, decisions_rating, assisting_rating, shooting_rating,
                    goalkeeper_rating
             FROM players WHERE id = $1`,
            [invited_by]
        );
        if (parentResult.rows.length === 0) {
            return res.status(404).json({ error: 'Parent player not found' });
        }
        const parent = parentResult.rows[0];

        const delta = parseInt(relative_rating) || 0;
        const derived = deriveGuestStats(parent, delta, position_classification || 'midfielder');

        const parentOverall = (parent.overall_rating != null)
            ? parseInt(parent.overall_rating)
            : (parseInt(parent.defending_rating || 0) + parseInt(parent.strength_rating || 0) +
               parseInt(parent.fitness_rating || 0)   + parseInt(parent.pace_rating || 0) +
               parseInt(parent.decisions_rating || 0) + parseInt(parent.assisting_rating || 0) +
               parseInt(parent.shooting_rating || 0));

        await pool.query(
            `UPDATE game_guests SET
                defending_rating = $1, strength_rating = $2, fitness_rating = $3,
                pace_rating = $4, shooting_rating = $5, assisting_rating = $6, decisions_rating = $7,
                goalkeeper_rating = $8, overall_rating = $9,
                is_admin_override = FALSE, derived_from_parent_ovr = $10
             WHERE id = $11 AND game_id = $12`,
            [derived.defending_rating, derived.strength_rating, derived.fitness_rating,
             derived.pace_rating, derived.shooting_rating, derived.assisting_rating, derived.decisions_rating,
             derived.goalkeeper_rating, derived.overall_rating,
             parentOverall, guestId, gameId]
        );

        // FIX-235: guest's OVR/GK changed → squad-avg shifts, recalc dynamic star.
        reviewDynamicStarRating(pool, gameId).catch(() => {});

        await gameAuditLog(pool, gameId, req.user.playerId, 'guest_stats_reset', JSON.stringify({
            guest_id: guestId, delta, position_classification, new_overall: derived.overall_rating
        }));

        res.json({
            success: true,
            overall_rating: derived.overall_rating,
            is_admin_override: false,
            derived_from_parent_ovr: parentOverall,
            stats: derived
        });
    } catch (error) {
        console.error('Guest stats reset error:', error);
        res.status(500).json({ error: 'Failed to reset guest stats' });
    }
});

// DELETE /api/games/:gameId/remove-my-registration/:registrationId
// Allows the player who signed up a friend to remove them (without game lock).
// Only works if the calling player is the registered_by_player_id on the registration.
// FIX-315 wrapper note: this endpoint already deletes a registration row owned
// by the caller. RSVP rows have no payment to refund, so the existing flow
// handles them cleanly — the row is deleted and no money moves. No change.
app.delete('/api/games/:gameId/remove-my-registration/:registrationId', authenticateToken, async (req, res) => {
    const client = await pool.connect();
    try {
        const { gameId, registrationId } = req.params;
        const playerId = req.user.playerId;

        await client.query('BEGIN');

        // Fetch the registration — must belong to this game and be registered by this player
        const regResult = await client.query(
            `SELECT r.id, r.player_id, r.status, r.amount_paid, r.amount_paid_free, r.registered_by_player_id,
                    p.alias, p.full_name,
                    g.game_status, g.teams_generated, g.team_selection_type, g.player_editing_locked
             FROM registrations r
             JOIN players p ON p.id = r.player_id
             JOIN games g ON g.id = $1
             WHERE r.id = $2 AND r.game_id = $1`,
            [gameId, registrationId]
        );

        if (regResult.rows.length === 0) {
            await client.query('ROLLBACK');
            client.release();
            return res.status(404).json({ error: 'Registration not found' });
        }

        const reg = regResult.rows[0];

        // Ensure the calling player was the one who registered this person
        if (reg.registered_by_player_id !== playerId) {
            await client.query('ROLLBACK');
            client.release();
            return res.status(403).json({ error: 'You can only remove players you personally signed up' });
        }

        // Block if game is past completion
        if (!['available', 'confirmed'].includes(reg.game_status)) {
            await client.query('ROLLBACK');
            client.release();
            return res.status(400).json({ error: 'Cannot remove player from a completed or cancelled game' });
        }

        // Block if teams generated (same rule as admin endpoint for safety)
        // EXCEPTION: draft_memory games flip teams_generated=true on each draft save
        // but stay open (teams_confirmed=false, game_status='available') — so a friend
        // you just registered can still be un-registered while the draft is in progress.
        if (reg.teams_generated && reg.team_selection_type !== 'draft_memory') {
            await client.query('ROLLBACK');
            client.release();
            return res.status(400).json({ error: 'Cannot remove a player after teams have been generated. Ask an admin.' });
        }

        const playerName = reg.alias || reg.full_name;
        const refundAmt = parseFloat(reg.amount_paid || 0);
        const refundFreeAmt = parseFloat(reg.amount_paid_free || 0);

        // Delete the registration
        await client.query('DELETE FROM registrations WHERE id = $1', [registrationId]);

        // Refund whoever paid (the registering player) — both real and free portions
        if (refundAmt > 0) {
            await client.query(
                'UPDATE credits SET balance = balance + $1 WHERE player_id = $2',
                [refundAmt, playerId]
            );
            await recordCreditTransaction(client, playerId, refundAmt, 'refund', `Removed ${playerName} from game`);
        }
        if (refundFreeAmt > 0) {
            // Free-credit refund → free_credit_balance bucket (not real balance).
            await client.query(
                'UPDATE credits SET free_credit_balance = free_credit_balance + $1, last_updated = CURRENT_TIMESTAMP WHERE player_id = $2',
                [refundFreeAmt, playerId]
            );
            await recordCreditTransaction(client, playerId, refundFreeAmt, 'free_credit', `Free credit restored — removed ${playerName} from game`);
        }

        await client.query('COMMIT');

        const totalRefund = refundAmt + refundFreeAmt;
        res.json({
            message: `${playerName} has been removed.${totalRefund > 0 ? ` £${totalRefund.toFixed(2)} refunded to your balance.` : ''}`
        });
        setImmediate(() => gameAuditLog(pool, gameId, null, 'player_removed',
            `Player: ${playerName} removed by registering player ${playerId} | Refunded: £${totalRefund.toFixed(2)}`));

    } catch (error) {
        await client.query('ROLLBACK').catch(() => {});
        console.error('Remove my registration error:', error);
        res.status(500).json({ error: 'Failed to remove player' });
    } finally {
        client.release();
    }
});

// POST /api/games/:id/register-friend
// A confirmed player signs up another registered player for the same game.
// Credits are deducted from the registering player. Friend's tier window applies.
// If the registering player holds the exclusivity badge, the friend is exempt from that check.

// POST /api/games/:id/claim-spot — first-come-first-served spot claim for normal backups
// Atomic: only one player can claim the open spot. Returns 409 if spot already taken.
app.post('/api/games/:id/claim-spot', authenticateToken, registrationLimiter, async (req, res) => {
    const client = await pool.connect();
    try {
        const gameId = req.params.id;
        const playerId = req.user.playerId;

        await client.query('BEGIN');

        // Block banned players from claiming spots
        const claimTierCheck = await client.query(
            'SELECT reliability_tier FROM players WHERE id = $1', [playerId]
        );
        const claimTier = claimTierCheck.rows[0]?.reliability_tier;
        if (claimTier === 'white') {
            await client.query('ROLLBACK');
            return res.status(403).json({ error: 'You are currently serving a 1-week signup ban and cannot claim spots.' });
        }
        if (claimTier === 'black') {
            await client.query('ROLLBACK');
            return res.status(403).json({ error: 'Your account has been suspended. Please contact an admin.' });
        }

        // Verify player is a normal_backup for this game.
        // is_comped retrieved so a comped organiser claim doesn't get charged
        // (FIX: previously claim-spot called applyGameFee unconditionally).
        const regCheck = await client.query(
            `SELECT id, position_preference, is_comped FROM registrations
             WHERE game_id = $1 AND player_id = $2 AND status = 'backup' AND backup_type = 'normal_backup'
             FOR UPDATE`,
            [gameId, playerId]
        );
        if (regCheck.rows.length === 0) {
            await client.query('ROLLBACK');
            return res.status(400).json({ error: 'You are not on the normal backup list for this game' });
        }

        // Check if there is actually a confirmed spot available (atomic).
        // Include early_bird_price, super_early_bird_price, game_date so we can compute
        // effective price for the charge below (bug fixed web47 — was always charging full cost).
        const game = await client.query(
            `SELECT g.cost_per_player, g.max_players,
                    g.early_bird_price, g.super_early_bird_price, g.game_date,
                    ((SELECT COUNT(*) FROM registrations WHERE game_id = g.id AND status = 'confirmed')
                     + (SELECT COUNT(*) FROM game_guests WHERE game_id = g.id)) AS current_players
             FROM games g WHERE g.id = $1`,
            [gameId]
        );
        if (!game.rows.length) {
            await client.query('ROLLBACK');
            return res.status(404).json({ error: 'Game not found' });
        }
        const { cost_per_player, max_players, current_players } = game.rows[0];
        if (parseInt(current_players) >= parseInt(max_players)) {
            await client.query('ROLLBACK');
            return res.status(409).json({ error: `Sorry — that spot was just claimed. You're still on backup.` });
        }

        // Check credits — at effective price (honours EB tiers).
        const { price: cost } = getEffectivePrice(game.rows[0]);
        // Option B: affordability = regular balance + free_credit_balance.
        const creditRes = await client.query(
            `SELECT COALESCE(balance, 0) + COALESCE(free_credit_balance, 0) AS total_available
               FROM credits WHERE player_id = $1`,
            [playerId]
        );
        const balance = parseFloat(creditRes.rows[0]?.total_available || 0);
        if (balance < cost) {
            await client.query('ROLLBACK');
            return res.status(400).json({
                error: `Insufficient credits. You need £${cost.toFixed(2)} but have £${balance.toFixed(2)}.`,
                code: 'INSUFFICIENT_CREDITS'
            });
        }

        // Claim the spot — promote to confirmed (amount_paid gets updated after the charge
        // so it correctly reflects the real-balance portion, matching the pattern used by
        // self-registration / admin-add / Wonderful auto-register).
        await client.query(
            `UPDATE registrations SET status = 'confirmed', backup_type = NULL WHERE id = $1`,
            [regCheck.rows[0].id]
        );

        // FIX-169: BFFs/Rivals auto-fill — fires for the just-confirmed player.
        // Game-mode + cap + override guards are inside the helper.
        await applyBffRivalAutoFill(client, playerId, gameId, regCheck.rows[0].id);

        // Charge credits at effective price; applyGameFee consumes free credits first and
        // returns realCharged + freeCharged (the portions actually debited).
        // FIX: skip charge entirely if this player is comped (organiser sat on
        // normal_backup with is_comped=TRUE on their reg row). The amount_paid /
        // amount_paid_free UPDATE below is also skipped — registration retains
        // its 0/0/comped state through promotion, which keeps drop-out refund
        // logic at line ~10673 (gated on !wasComped) consistent.
        const _claimWasComped = !!regCheck.rows[0].is_comped;
        let realCharged = 0;
        let freeCharged = 0;
        if (cost > 0 && !_claimWasComped) {
            const chargeResult = await applyGameFee(client, playerId, cost, `Claimed open spot — game ${gameId}`);
            realCharged = chargeResult.realCharged;
            freeCharged = chargeResult.freeCharged || 0;
            // Record both real-balance and free-credit portions — enables exact drop-out refund.
            await client.query(
                'UPDATE registrations SET amount_paid = $1, amount_paid_free = $2 WHERE id = $3',
                [realCharged, freeCharged, regCheck.rows[0].id]
            );
        }

        // In-app notification confirmation — comp-aware so organisers don't see
        // a "deducted" message that contradicts their actual balance.
        const _claimMsg = _claimWasComped
            ? 'You claimed the open spot — covered by the GAFFA, no charge. See you on the pitch!'
            : `You claimed the open spot! £${cost.toFixed(2)} deducted. See you on the pitch!`;
        await client.query(
            `INSERT INTO notifications (player_id, type, message, game_id) VALUES ($1, 'backup_promoted', $2, $3)`,
            [playerId, _claimMsg, gameId]
        );

        await client.query('COMMIT');

        // Push to confirmed player
        const gameData = await getGameDataForNotification(gameId);
        sendNotification('backup_promoted', playerId, gameData).catch(() => {});

        // Audit
        setImmediate(() => gameAuditLog(pool, gameId, playerId, 'spot_claimed',
            `Player claimed open spot via race mechanic`).catch(() => {}));

        // DYNSTAR: waitlist → confirmed promotion changes avg OVR — trigger review
        reviewDynamicStarRating(pool, gameId).catch(() => {});

        res.json({ success: true, message: `Spot claimed! You're in.` });
    } catch (e) {
        await client.query('ROLLBACK');
        console.error('Claim spot error:', e.message);
        res.status(500).json({ error: 'Failed to claim spot' });
    } finally {
        client.release();
    }
});

app.post('/api/games/:id/register-friend', authenticateToken, async (req, res) => {
    const client = await pool.connect();
    try {
        const { friendPlayerId, position, backupType, tournamentTeamPreference } = req.body;
        const gameId = req.params.id;
        const registeringPlayerId = req.user.playerId;

        // Validate friend ID first — no point doing any other work if it's missing
        // or self-referential.
        if (!friendPlayerId) {
            return res.status(400).json({ error: 'friendPlayerId is required' });
        }
        if (String(friendPlayerId) === String(registeringPlayerId)) {
            return res.status(400).json({ error: 'You cannot sign yourself up via this route' });
        }

        // Audit fix May 2026: position required for friend sign-ups too. Falls back
        // to the FRIEND's saved defaults (not the registering player's) — it's their game.
        // Runs AFTER the friendPlayerId validation above so we never hit the DB with a
        // bad ID.
        let positionValue;
        if (!position) {
            const _fpos = await _resolvePositionForSignup(pool, friendPlayerId, req.body);
            if (_fpos.error) return res.status(400).json({
                error: "Your friend hasn't set a default position. Open their profile or pass a position explicitly.",
                code: 'POSITION_REQUIRED'
            });
            positionValue = _fpos.positionValue;
        } else {
            positionValue = position;
        }

        await client.query('BEGIN');

        // Block if friend is already a confirmed referee for this game
        const friendRefConflict = await client.query(
            `SELECT 1 FROM game_referees WHERE game_id = $1 AND player_id = $2 AND status = 'confirmed'`,
            [req.params.id, friendPlayerId]
        );
        if (friendRefConflict.rows.length > 0) {
            await client.query('ROLLBACK');
            return res.status(400).json({ error: 'This player is already confirmed as a referee for this game' });
        }

        // Lock game row to prevent race conditions
        // IMPORTANT: early_bird_price + super_early_bird_price are required for getEffectivePrice()
        // below — without them it silently falls back to standard price (bug fixed web47).
        const gameLock = await client.query(`
            SELECT max_players, cost_per_player, exclusivity,
                   player_editing_locked, team_selection_type, position_type, tournament_team_count,
                   series_id, game_status, game_date, star_rating, min_rating_enabled,
                   early_bird_price, super_early_bird_price
            FROM games WHERE id = $1 FOR UPDATE
        `, [gameId]);

        if (gameLock.rows.length === 0) {
            await client.query('ROLLBACK');
            return res.status(404).json({ error: 'Game not found' });
        }

        const game = gameLock.rows[0];

        if (!['available', 'confirmed'].includes(game.game_status)) {
            await client.query('ROLLBACK');
            return res.status(400).json({ error: 'This game is no longer accepting registrations' });
        }

        if (game.player_editing_locked) {
            await client.query('ROLLBACK');
            // FIX-357: preempt
            const _preempt = await _recordSignupIntent(req.params.id, req.user.playerId, 'register_friend');
            return res.status(423).json(_preempt);
        }

        // Registering player must be confirmed in this game
        const myReg = await client.query(
            "SELECT id FROM registrations WHERE game_id = $1 AND player_id = $2 AND status = 'confirmed'",
            [gameId, registeringPlayerId]
        );
        if (myReg.rows.length === 0) {
            await client.query('ROLLBACK');
            return res.status(403).json({ error: 'You must be confirmed in this game to sign up a friend' });
        }

        // Fetch friend details
        const friendResult = await client.query(
            'SELECT id, alias, full_name, reliability_tier, overall_rating FROM players WHERE id = $1',
            [friendPlayerId]
        );
        if (friendResult.rows.length === 0) {
            await client.query('ROLLBACK');
            return res.status(404).json({ error: 'Player not found' });
        }
        const friend = friendResult.rows[0];
        const friendName = friend.alias || friend.full_name;

        // Banned tiers cannot be registered
        if (friend.reliability_tier === 'white' || friend.reliability_tier === 'black') {
            await client.query('ROLLBACK');
            return res.status(403).json({ error: `${friendName} is not eligible to register for games` });
        }

        // Friend must not already be registered (any status)
        const existingReg = await client.query(
            'SELECT id FROM registrations WHERE game_id = $1 AND player_id = $2',
            [gameId, friendPlayerId]
        );
        if (existingReg.rows.length > 0) {
            await client.query('ROLLBACK');
            return res.status(400).json({ error: `${friendName} is already registered for this game` });
        }

        // Tier timing window — apply the FRIEND's tier, as if they registered themselves
        const friendTier = friend.reliability_tier || 'silver';
        let hoursAhead = 168; // silver (7 days)
        if (friendTier === 'gold') hoursAhead = 28 * 24;
        if (friendTier === 'bronze') hoursAhead = 24;

        const windowCheck = await client.query(
            `SELECT 1 FROM games WHERE id = $1 AND game_date <= CURRENT_TIMESTAMP + ($2 || ' hours')::INTERVAL`,
            [gameId, hoursAhead.toString()]
        );
        if (windowCheck.rows.length === 0) {
            const tierLabel = friendTier.charAt(0).toUpperCase() + friendTier.slice(1);
            await client.query('ROLLBACK');
            return res.status(403).json({ error: `This game isn't open for ${friendName}'s tier (${tierLabel}) yet` });
        }

        // Min-rating is visibility-only — friend registration is never blocked by rating.

        // Exclusivity badge checks:
        // If the REGISTERING player holds the badge, the friend is exempt — they are vouching for them.
        // If neither holds the badge, registration is blocked.
        if (game.exclusivity === 'allstars') {
            const regBadge = await client.query(`
                SELECT 1 FROM player_badges pb JOIN badges b ON b.id = pb.badge_id
                WHERE pb.player_id = $1 AND b.name = 'TF All Star'
            `, [registeringPlayerId]);
            if (regBadge.rows.length === 0) {
                const friendBadge = await client.query(`
                    SELECT 1 FROM player_badges pb JOIN badges b ON b.id = pb.badge_id
                    WHERE pb.player_id = $1 AND b.name = 'TF All Star'
                `, [friendPlayerId]);
                if (friendBadge.rows.length === 0) {
                    await client.query('ROLLBACK');
                    return res.status(403).json({ error: `This is an All Star game. Neither you nor ${friendName} has the required badge.` });
                }
            }
        }

        if (game.exclusivity === 'clm') {
            const regBadge = await client.query(`
                SELECT 1 FROM player_badges pb JOIN badges b ON b.id = pb.badge_id
                WHERE pb.player_id = $1 AND b.name = 'CLM'
            `, [registeringPlayerId]);
            if (regBadge.rows.length === 0) {
                const friendBadge = await client.query(`
                    SELECT 1 FROM player_badges pb JOIN badges b ON b.id = pb.badge_id
                    WHERE pb.player_id = $1 AND b.name = 'CLM'
                `, [friendPlayerId]);
                if (friendBadge.rows.length === 0) {
                    await client.query('ROLLBACK');
                    return res.status(403).json({ error: `This is a CLM exclusive game. Neither you nor ${friendName} has the required badge.` });
                }
            }
        }

        if (game.exclusivity === 'misfits') {
            const regBadge = await client.query(`
                SELECT 1 FROM player_badges pb JOIN badges b ON b.id = pb.badge_id
                WHERE pb.player_id = $1 AND b.name = 'Misfits'
            `, [registeringPlayerId]);
            if (regBadge.rows.length === 0) {
                const friendBadge = await client.query(`
                    SELECT 1 FROM player_badges pb JOIN badges b ON b.id = pb.badge_id
                    WHERE pb.player_id = $1 AND b.name = 'Misfits'
                `, [friendPlayerId]);
                if (friendBadge.rows.length === 0) {
                    await client.query('ROLLBACK');
                    return res.status(403).json({ error: `This is a Misfits game. Neither you nor ${friendName} has the required badge.` });
                }
            }
        }

        // Current player count
        const countResult = await client.query(
            "SELECT (SELECT COUNT(*) FROM registrations WHERE game_id = $1 AND status IN ('confirmed', 'rsvp')) + (SELECT COUNT(*) FROM game_guests WHERE game_id = $1) AS current_players",
            [gameId]
        );
        const currentPlayers = parseInt(countResult.rows[0].current_players);
        const isFull = currentPlayers >= parseInt(game.max_players);

        // GK slot check
        const isGKOnly = positionValue.trim().toUpperCase() === 'GK';
        if (!isFull && isGKOnly) {
            const maxGKSlots = game.team_selection_type === 'vs_external' ? 1 : game.team_selection_type === 'tournament' ? (game.tournament_team_count || 4) : 2;
            const gkCount = await client.query(`
                SELECT COUNT(*) as gk_count FROM registrations
                WHERE game_id = $1 AND status IN ('confirmed', 'rsvp') /* FIX-315 */ AND UPPER(TRIM(position_preference)) = 'GK'
            `, [gameId]);
            if (parseInt(gkCount.rows[0].gk_count) >= maxGKSlots) {
                await client.query('ROLLBACK');
                return res.status(409).json({ error: `GK spots are full. Please choose a different position for ${friendName}.` });
            }
        }

        // Determine status and handle credit deduction from REGISTERING PLAYER
        let status, regBackupType = null, friendRealCharged = 0, friendFreeCharged = 0;

        if (isFull) {
            if (!backupType || !['normal_backup', 'confirmed_backup', 'gk_backup'].includes(backupType)) {
                await client.query('ROLLBACK');
                return res.status(400).json({
                    error: 'game_full',
                    message: 'Game is full. Please choose a backup option for your friend.',
                    currentPlayers,
                    maxPlayers: parseInt(game.max_players)
                });
            }
            if (backupType === 'gk_backup' && !isGKOnly) {
                await client.query('ROLLBACK');
                return res.status(400).json({ error: 'GK Backup requires GK as the only selected position.' });
            }
            status = 'backup';
            regBackupType = backupType;

            if (backupType === 'confirmed_backup') {
                // Effective price honours early-bird / super-early-bird tiers.
                // Using cost_per_player here blocked players whose balance covered the EB
                // price but not full price (bug fixed web47).
                const { price: effectivePrice, tier: priceTier } = getEffectivePrice(game);
                const creditResult = await client.query(
                    `SELECT COALESCE(balance, 0) + COALESCE(free_credit_balance, 0) AS total_available
                       FROM credits WHERE player_id = $1`,
                    [registeringPlayerId]
                );
                if (creditResult.rows.length === 0 || Math.round(parseFloat(creditResult.rows[0].total_available) * 100) < Math.round(effectivePrice * 100)) {
                    await client.query('ROLLBACK');
                    return res.status(400).json({ error: 'Insufficient credits for confirmed backup' });
                }
                const { realCharged, freeCharged } = await applyGameFee(client, registeringPlayerId, effectivePrice, `Confirmed backup for ${friendName} in game ${gameId} (${priceTier} pricing)`);
                friendRealCharged = realCharged;
                friendFreeCharged = freeCharged || 0;
            }
        } else {
            status = 'confirmed';
            // Effective price honours early-bird / super-early-bird tiers (bug fixed web47).
            const { price: effectivePrice, tier: priceTier } = getEffectivePrice(game);
            const creditResult = await client.query(
                `SELECT COALESCE(balance, 0) + COALESCE(free_credit_balance, 0) AS total_available
                   FROM credits WHERE player_id = $1`,
                [registeringPlayerId]
            );
            if (creditResult.rows.length === 0 || Math.round(parseFloat(creditResult.rows[0].total_available) * 100) < Math.round(effectivePrice * 100)) {
                await client.query('ROLLBACK');
                return res.status(400).json({ error: 'Insufficient credits' });
            }
            const { realCharged, freeCharged } = await applyGameFee(client, registeringPlayerId, effectivePrice, `Registration for ${friendName} in game ${gameId} (${priceTier} pricing)`);
            friendRealCharged = realCharged;
            friendFreeCharged = freeCharged || 0;
        }

        // Insert registration under friend's player_id, recording who paid.
        // amount_paid stores the REAL-BALANCE portion (not total) — same semantics as every
        // other registration path. Free-credit portion is refunded separately on dropout.
        // chargedPriceForDisplay is the full effective price; used only for notifications
        // that show the player what was deducted in total.
        const chargedPrice = friendRealCharged; // → amount_paid
        const chargedPriceForDisplay = (status === 'confirmed' || regBackupType === 'confirmed_backup')
            ? getEffectivePrice(game).price
            : 0;
        // FIX-173: capture friend's reg id so we can apply BFFs/Rivals auto-fill if confirmed.
        const friendRegResult = await client.query(
            `INSERT INTO registrations (game_id, player_id, status, position_preference, backup_type, amount_paid, amount_paid_free, registered_by_player_id, tournament_team_preference)
             VALUES ($1, $2, $3, $4, $5, $6, $7, $8, $9) RETURNING id`,
            [
                gameId, friendPlayerId, status, positionValue, regBackupType,
                chargedPrice,
                friendFreeCharged,
                registeringPlayerId,
                tournamentTeamPreference || null
            ]
        );
        const friendRegId = friendRegResult.rows[0].id;

        // FIX-173: BFFs/Rivals auto-fill — only if friend was confirmed (not backup).
        if (status === 'confirmed') {
            await applyBffRivalAutoFill(client, friendPlayerId, gameId, friendRegId);
        }

        await client.query('COMMIT');

        let message;
        if (status === 'confirmed') {
            message = `${friendName} has been registered! £${chargedPriceForDisplay.toFixed(2)} deducted from your balance.`;
        } else if (regBackupType === 'confirmed_backup') {
            message = `${friendName} has been added to the confirmed backup list. £${chargedPriceForDisplay.toFixed(2)} deducted from your balance.`;
        } else {
            message = `${friendName} has been added to the backup list.`;
        }

        res.json({ message, status, backupType: regBackupType });

        // Non-critical: notify friend and registering player, and send emails — fires after response
        setImmediate(async () => {
            try {
                // Fetch names and emails for both players
                const regPlayerResult = await pool.query(
                    'SELECT p.alias, p.full_name, u.email FROM players p JOIN users u ON u.id = p.user_id WHERE p.id = $1',
                    [registeringPlayerId]
                );
                const friendEmailResult = await pool.query(
                    'SELECT p.alias, p.full_name, u.email FROM players p JOIN users u ON u.id = p.user_id WHERE p.id = $1',
                    [friendPlayerId]
                );
                const regName = regPlayerResult.rows[0]?.alias || regPlayerResult.rows[0]?.full_name || 'A teammate';
                const regEmail = regPlayerResult.rows[0]?.email;
                const friendFullName = friendEmailResult.rows[0]?.full_name || friendName;
                const friendEmail = friendEmailResult.rows[0]?.email;

                const gameData = await getGameDataForNotification(gameId);
                const gameDate = gameData.game_date || gameData.day || 'upcoming game';
                const venue = gameData.venue || 'the venue';
                const gameUrl = `https://totalfooty.co.uk/game.html?url=${gameData.game_url || ''}`;

                // Push notification to friend
                const notifType = status === 'confirmed' ? 'game_registered' : 'backup_added';
                const friendNotifMsg = status === 'confirmed'
                    ? `${regName} has signed you up for ${gameDate} at ${venue}!`
                    : `${regName} has put you on the backup list for ${gameDate} at ${venue}.`;
                await pool.query(
                    'INSERT INTO notifications (player_id, type, message, game_id) VALUES ($1, $2, $3, $4)',
                    [friendPlayerId, notifType, friendNotifMsg, gameId]
                );
                await sendNotification(notifType, friendPlayerId, gameData);

                // Push notification to registering player
                const regNotifMsg = status === 'confirmed'
                    ? `You signed up ${friendName} for ${gameDate} at ${venue}. £${chargedPriceForDisplay.toFixed(2)} deducted.`
                    : `You added ${friendName} to the backup list for ${gameDate} at ${venue}.`;
                await pool.query(
                    'INSERT INTO notifications (player_id, type, message, game_id) VALUES ($1, $2, $3, $4)',
                    [registeringPlayerId, 'friend_registered', regNotifMsg, gameId]
                );

                // Email to friend
                if (friendEmail) {
                    const friendEmailBody = status === 'confirmed'
                        ? `<p style="color:#888;font-size:14px;margin:0 0 8px;">Hi ${friendFullName},</p>
                           <p style="color:#888;font-size:14px;margin:0 0 20px;"><strong style="color:#fff;">${regName}</strong> has signed you up for a game on TotalFooty!</p>
                           <table style="width:100%;border-collapse:collapse;font-size:15px;color:#ccc;margin-bottom:20px;">
                               <tr><td style="padding:6px 0;color:#888;width:80px;">Date</td><td style="font-weight:900;">${gameDate}</td></tr>
                               <tr><td style="padding:6px 0;color:#888;">Venue</td><td style="font-weight:900;">${venue}</td></tr>
                               <tr><td style="padding:6px 0;color:#888;">Status</td><td style="font-weight:900;color:#00ff41;">✅ Confirmed</td></tr>
                           </table>
                           <a href="${gameUrl}" style="display:inline-block;background:#fff;color:#000;padding:14px 28px;border-radius:4px;font-weight:bold;font-size:13px;letter-spacing:2px;text-decoration:none;">VIEW GAME</a>`
                        : `<p style="color:#888;font-size:14px;margin:0 0 8px;">Hi ${friendFullName},</p>
                           <p style="color:#888;font-size:14px;margin:0 0 20px;"><strong style="color:#fff;">${regName}</strong> has added you to the backup list for a game on TotalFooty.</p>
                           <table style="width:100%;border-collapse:collapse;font-size:15px;color:#ccc;margin-bottom:20px;">
                               <tr><td style="padding:6px 0;color:#888;width:80px;">Date</td><td style="font-weight:900;">${gameDate}</td></tr>
                               <tr><td style="padding:6px 0;color:#888;">Venue</td><td style="font-weight:900;">${venue}</td></tr>
                               <tr><td style="padding:6px 0;color:#888;">Status</td><td style="font-weight:900;color:#FFA500;">⏳ Backup</td></tr>
                           </table>
                           <a href="${gameUrl}" style="display:inline-block;background:#fff;color:#000;padding:14px 28px;border-radius:4px;font-weight:bold;font-size:13px;letter-spacing:2px;text-decoration:none;">VIEW GAME</a>`;

                    await emailTransporter.sendMail({
                        from: '"TotalFooty" <totalfooty19@gmail.com>',
                        to: friendEmail,
                        subject: `⚽ ${(regName || '').replace(/[\r\n]/g, '')} signed you up — TotalFooty`,
                        html: `<div style="background:#0d0d0d;padding:40px;font-family:Arial,sans-serif;max-width:520px;margin:0 auto;">
                            <img src="https://totalfooty.co.uk/assets/logo.png" width="80" style="margin-bottom:24px"/>
                            <h2 style="color:#fff;font-size:20px;letter-spacing:2px;margin-bottom:20px;">YOU'VE BEEN SIGNED UP</h2>
                            ${friendEmailBody}
                            <p style="color:#333;font-size:11px;margin-top:32px;letter-spacing:1px;">TOTALFOOTY — COVENTRY FOOTBALL COMMUNITY</p>
                        </div>`
                    }).catch(e => console.error('Friend registration email to friend failed (non-critical):', e.message));
                }

                // Email 3 (receipt to registering player) removed — unnecessary

                // Audit: add-friend registration
                try {
                    const friendRegType = status === 'backup'
                        ? (regBackupType === 'confirmed_backup' ? 'confirmed backup' : regBackupType === 'gk_backup' ? 'GK backup' : 'backup')
                        : 'standard';
                    await registrationEvent(pool, gameId, friendPlayerId,
                        status === 'backup' ? 'backup_joined' : 'signed_up',
                        `Signed up by ${regName} | ${friendRegType}`);
                    await gameAuditLog(pool, gameId, null,
                        status === 'backup' ? 'player_backup_joined' : 'player_signed_up',
                        `${friendFullName} (${friendPlayerId}) | ${friendRegType} | Added by ${regName} (${registeringPlayerId})`);
                } catch (e) { /* non-critical */ }

                // Superadmin notify: player added another player
                try {
                    const isTournament = (await pool.query('SELECT team_selection_type FROM games WHERE id = $1', [gameId])).rows[0]?.team_selection_type === 'tournament';
                    await notifyAdmin(
                        `👥 Player Added by ${regName}`,
                        [
                            ['Added by', regName],
                            ['Added player', friendFullName],
                            ['Status', status === 'confirmed' ? 'Confirmed' : 'Backup'],
                            ['Game', (gameData.day || '') + ' ' + (gameData.time || '')],
                            ['Venue', gameData.venue || ''],
                            ['Tournament', isTournament ? 'Yes' : 'No'],
                        ]
                    );
                } catch (e) { /* non-critical */ }
            } catch (e) {
                console.error('Friend registration notification failed (non-critical):', e.message);
            }
            // DYNSTAR: review star rating on every confirmed friend sign-up
            if (status === 'confirmed') await reviewDynamicStarRating(pool, gameId);
            // RAF: trigger 50p game credit for referrer if the friend being registered was referred
            if (status === 'confirmed') await triggerRafGameCredit(friendPlayerId);
        });

    } catch (error) {
        await client.query('ROLLBACK');
        console.error('Register friend error:', error);
        res.status(500).json({ error: 'Registration failed' });
    } finally {
        client.release();
    }
});

// Check GK slot availability for a game
app.get('/api/games/:id/gk-slots', authenticateToken, async (req, res) => {
    try {
        const gameId = req.params.id;
        
        const result = await pool.query(`
            SELECT g.team_selection_type, g.tournament_team_count,
                   COUNT(r.id) FILTER (WHERE r.status IN ('confirmed', 'rsvp') AND UPPER(TRIM(r.position_preference)) = 'GK' /* FIX-315 */) as gk_count
            FROM games g
            LEFT JOIN registrations r ON r.game_id = g.id
            WHERE g.id = $1
            GROUP BY g.id
        `, [gameId]);
        
        if (result.rows.length === 0) {
            return res.status(404).json({ error: 'Game not found' });
        }
        
        const maxGKSlots = result.rows[0].team_selection_type === 'vs_external' ? 1 : result.rows[0].team_selection_type === 'tournament' ? (result.rows[0].tournament_team_count || 4) : 2;
        const currentGKs = parseInt(result.rows[0].gk_count) || 0;
        
        res.json({ 
            maxGKSlots, 
            currentGKs, 
            slotsAvailable: maxGKSlots - currentGKs 
        });
    } catch (error) {
        console.error('GK slots check error:', error);
        res.status(500).json({ error: 'Failed to check GK slots' });
    }
});

// Get backup queue for a game
app.get('/api/games/:id/backups', authenticateToken, async (req, res) => {
    try {
        const gameId = req.params.id;
        
        const result = await pool.query(`
            SELECT r.id, r.player_id, r.backup_type, r.position_preference, r.registered_at,
                   p.full_name, p.alias, p.squad_number
            FROM registrations r
            JOIN players p ON p.id = r.player_id
            WHERE r.game_id = $1 AND r.status = 'backup'
            ORDER BY 
                CASE r.backup_type 
                    WHEN 'confirmed_backup' THEN 1 
                    WHEN 'gk_backup' THEN 2 
                    ELSE 3 
                END,
                r.registered_at ASC
        `, [gameId]);
        
        res.json(result.rows);
    } catch (error) {
        console.error('Get backups error:', error);
        res.status(500).json({ error: 'Failed to get backup queue' });
    }
});



