// GET /api/admin/players/stats-list — player list for dropdown (id, alias, full_name only)
app.get('/api/admin/players/stats-list', authenticateToken, requireAdmin, async (req, res) => {
    try {
        const result = await pool.query(`
            SELECT p.id, p.alias, p.full_name, p.squad_number
            FROM players p
            ORDER BY COALESCE(p.alias, p.full_name)
        `);
        res.json(result.rows);
    } catch (error) {
        res.status(500).json({ error: 'Failed to load players' });
    }
});

// GET /api/admin/players/analysis
// Manage Players → Analysis tab data source. Computes W/D/L/MOTM on-the-fly from
// STANDARD games only (team_selection_type in ('normal','standard') or NULL) — excludes
// draft_memory / vs_external / tournament, where overall_rating isn't used for team gen.
//
// A player only counts for a game if they were actually rostered onto a team for it
// (team_players JOIN, not LEFT JOIN). Confirmed backups/unrostered players don't
// get appearances or results — matches how human admin thinks about "games played".
//
// Query params:
//   sinceLastOverallChange=1  — restrict counts to games on-or-after the player's
//                                most recent player_stat_history row where
//                                overall_rating actually changed. Players with no
//                                overall change ever fall through to lifetime counts.
//
// last_delta is the signed integer change in overall at that most recent change
// (e.g. +3 or -2). NULL when the player has no recorded overall change — frontend
// renders a dash in the LAST Δ column.
app.get('/api/admin/players/analysis', authenticateToken, requireAdmin, async (req, res) => {
    try {
        const sinceFlag = req.query.sinceLastOverallChange;
        const since = (sinceFlag === '1' || sinceFlag === 'true' || sinceFlag === true);

        // excludeUnfair toggle: when true, RAW apps/wins/draws/losses/motm drop games where
        // admin explicitly marked teams uneven on the balance slider (score IS NOT NULL
        // AND <> 0). NULL-scored games stay in regardless — the toggle is specifically
        // about removing known-uneven results, not the separate "not a fair reflection"
        // or legacy cases.
        //
        // Per GAFFA: an unfair game is USEFUL data (it signals that some players are
        // rated wrong — that's why the sum-of-overalls came out even but the result
        // didn't). The toggle lets admin see the record without that noise; the DYN OVR
        // arrow column uses the slider data intelligently, independent of this toggle.
        const exclFlag = req.query.excludeUnfair;
        const excludeUnfair = (exclFlag === '1' || exclFlag === 'true' || exclFlag === true);

        const result = await pool.query(`
            WITH
            -- all completed standard games
            standard_games AS (
                SELECT id, game_date, motm_winner_id, winning_team, team_balance_score
                FROM games
                WHERE game_status = 'completed'
                  AND COALESCE(team_selection_type, 'standard') IN ('normal', 'standard')
            ),
            -- each row's overall augmented with the previous row's overall
            history_augmented AS (
                SELECT
                    player_id,
                    created_at,
                    overall_rating,
                    LAG(overall_rating) OVER (PARTITION BY player_id ORDER BY created_at) AS prev_overall
                FROM player_stat_history
                WHERE overall_rating IS NOT NULL
            ),
            -- most recent *actual* overall change per player (rows where overall changed)
            last_changes AS (
                SELECT DISTINCT ON (player_id)
                    player_id,
                    created_at AS last_change_at,
                    (overall_rating - prev_overall) AS last_delta
                FROM history_augmented
                WHERE prev_overall IS NOT NULL
                  AND overall_rating <> prev_overall
                ORDER BY player_id, created_at DESC
            ),
            -- one row per (player, game) where the player was rostered onto a team.
            -- INNER JOIN on team_players/teams enforces "backups don't count" rule.
            player_results AS (
                SELECT
                    r.player_id,
                    sg.id          AS game_id,
                    sg.game_date,
                    sg.winning_team,
                    sg.motm_winner_id,
                    sg.team_balance_score,
                    t.team_name
                FROM registrations r
                JOIN standard_games sg ON sg.id = r.game_id
                JOIN team_players tp   ON tp.player_id = r.player_id
                JOIN teams t           ON t.id = tp.team_id AND t.game_id = sg.id
                WHERE r.status = 'confirmed'
            ),
            -- aggregate per player; respect the "since last overall change" cutoff when $1 is true.
            --
            -- Raw counts honour the excludeUnfair toggle ($2): when ticked, games admin flagged
            -- as uneven on the balance slider (score IS NOT NULL AND <> 0) are dropped. NULL-
            -- scored games stay in — the toggle is about filtering known-uneven games only.
            --
            -- DYN OVR notches are computed separately below, independent of the toggle.
            -- Per GAFFA: unfair games are a USEFUL signal that some players are mis-rated
            -- — the dynamic arrow uses them directly.
            agg AS (
                SELECT
                    pr.player_id,
                    COUNT(*) FILTER (
                        WHERE $2::boolean = false
                           OR pr.team_balance_score IS NULL
                           OR pr.team_balance_score = 0
                    ) AS apps,
                    COUNT(*) FILTER (
                        WHERE ($2::boolean = false
                               OR pr.team_balance_score IS NULL
                               OR pr.team_balance_score = 0)
                          AND pr.winning_team IS NOT NULL
                          AND LOWER(pr.winning_team) <> 'draw'
                          AND LOWER(pr.winning_team) = LOWER(pr.team_name)
                    ) AS wins,
                    COUNT(*) FILTER (
                        WHERE ($2::boolean = false
                               OR pr.team_balance_score IS NULL
                               OR pr.team_balance_score = 0)
                          AND LOWER(pr.winning_team) = 'draw'
                    ) AS draws,
                    COUNT(*) FILTER (
                        WHERE ($2::boolean = false
                               OR pr.team_balance_score IS NULL
                               OR pr.team_balance_score = 0)
                          AND pr.winning_team IS NOT NULL
                          AND LOWER(pr.winning_team) <> 'draw'
                          AND LOWER(pr.winning_team) <> LOWER(pr.team_name)
                    ) AS losses,
                    COUNT(*) FILTER (
                        WHERE ($2::boolean = false
                               OR pr.team_balance_score IS NULL
                               OR pr.team_balance_score = 0)
                          AND pr.motm_winner_id = pr.player_id
                    ) AS motm,
                    -- DYN OVR notches (v2, 2026-04-24 — GAFFA-simplified rule):
                    --   Unfair game (score != 0, not NULL):
                    --     Win  → +|score|  (any win in an unfair game = underrated signal)
                    --     Loss → -|score|  (any loss in an unfair game = overrated signal)
                    --     Draw → 0         (draws skipped entirely per GAFFA)
                    --   Balanced game (score = 0) or excluded game (score NULL) → 0
                    --
                    -- Notches accumulate linearly. Frontend converts to arrow angle at 9° per
                    -- notch, clamped to [0°, 180°]. Players' arrows can swing back toward
                    -- yellow if subsequent games go the other way. Admin OVR change resets
                    -- the baseline (see 'Since last overall change' toggle) to put the
                    -- arrow back near horizontal after a rating adjustment.
                    COALESCE(SUM(
                        CASE
                            WHEN pr.team_balance_score IS NULL
                              OR pr.team_balance_score = 0
                              OR pr.winning_team IS NULL
                              OR LOWER(pr.winning_team) = 'draw'
                                THEN 0::numeric
                            WHEN LOWER(pr.winning_team) = LOWER(pr.team_name) THEN
                                ABS(pr.team_balance_score)::numeric   -- WIN: +|score|
                            ELSE
                                -ABS(pr.team_balance_score)::numeric  -- LOSS: -|score|
                        END
                    ), 0::numeric) AS dyn_ovr_notches,
                    -- Sample-size indicator: unfair games that contributed to the signal.
                    -- Balanced games don't count (they contribute 0 notches), so this counts only
                    -- games with score != 0. Frontend greys the arrow at low counts.
                    COUNT(*) FILTER (
                        WHERE pr.team_balance_score IS NOT NULL
                          AND pr.team_balance_score <> 0
                    ) AS unfair_games
                FROM player_results pr
                LEFT JOIN last_changes lc ON lc.player_id = pr.player_id
                WHERE $1::boolean = false
                   OR lc.last_change_at IS NULL
                   OR pr.game_date >= lc.last_change_at
                GROUP BY pr.player_id
            )
            SELECT
                p.id, p.alias, p.full_name, p.squad_number,
                p.reliability_tier,
                -- GK override (2026-04-24): for goalkeepers, the "overall" shown in Analysis
                -- is their goalkeeper_rating, not outfield overall_rating. Mirrors the swap
                -- applied in generate-teams, lineup builder, and other admin surfaces. Falls
                -- back to overall_rating if GK has no goalkeeper_rating set (shouldn't happen
                -- in practice but avoids nulls).
                CASE WHEN p.position = 'goalkeeper' AND p.goalkeeper_rating IS NOT NULL
                     THEN p.goalkeeper_rating
                     ELSE p.overall_rating
                END                             AS overall_rating,
                (p.position = 'goalkeeper')     AS is_gk,
                COALESCE(a.apps, 0)             AS apps,
                COALESCE(a.wins, 0)             AS wins,
                COALESCE(a.draws, 0)            AS draws,
                COALESCE(a.losses, 0)           AS losses,
                COALESCE(a.motm, 0)             AS motm,
                COALESCE(a.dyn_ovr_notches, 0)  AS dyn_ovr_notches,
                COALESCE(a.unfair_games, 0)     AS unfair_games,
                lc.last_delta,
                lc.last_change_at
            FROM players p
            LEFT JOIN agg a           ON a.player_id = p.id
            LEFT JOIN last_changes lc ON lc.player_id = p.id
            ORDER BY p.squad_number NULLS LAST, p.full_name
        `, [since, excludeUnfair]);

        res.json({
            players: result.rows,
            sinceLastOverallChange: since,
            excludeUnfair
        });
    } catch (error) {
        console.error('Players analysis error:', error);
        res.status(500).json({ error: 'Failed to load analysis data' });
    }
});

// GET /api/admin/players/performance
// Powers the Manage Players → Performance tab. Returns per-player apps/wins/win%
// bucketed by the OVR the player held when each game was played — "pre post-game
// wizard changes". A rating change inserted at time T applies from T forward; games
// played before T are counted at the PREVIOUS rating.
//
// Scope (Web54, 2026-04-24): STANDARD games only — no tournaments, externals, draft memory,
// or venue clashes. Of those, only games NOT explicitly marked unfair feed the grid.
// The admin_marked_unfair BOOLEAN column (added in a migration) distinguishes deliberate
// ticks from pre-slider legacy NULLs — both got backfilled to TRUE so pre-slider data
// stays out of the performance signal.
//
// For GKs, current_ovr and rating buckets are driven by goalkeeper_rating instead of
// overall_rating (same pattern as Analysis tab).
app.get('/api/admin/players/performance', authenticateToken, requireAdmin, async (req, res) => {
    try {
        // Filter toggles from frontend. Defaults match the original "filter out bad data"
        // behaviour: standard-only games AND unfair games excluded. Admin can untick a
        // toggle to widen the dataset (e.g. include tournaments, or include legacy
        // NULL-score games marked unfair).
        //
        // filter_non_standard=true  → restrict to standard, non-venue-clash games
        // filter_unfair=true        → exclude games where admin_marked_unfair = TRUE
        const filterNonStandard = req.query.filter_non_standard !== 'false';
        const filterUnfair      = req.query.filter_unfair      !== 'false';

        const result = await pool.query(`
            WITH
            eligible_games AS (
                SELECT id, game_date, winning_team, team_balance_score
                FROM games
                WHERE game_status = 'completed'
                  -- $1 = filterNonStandard: when true, restrict to standard, non-venue-clash games
                  AND (NOT $1::boolean OR COALESCE(team_selection_type, 'standard') IN ('normal', 'standard'))
                  AND (NOT $1::boolean OR COALESCE(is_venue_clash, false) = false)
                  -- $2 = filterUnfair: when true, exclude games admin marked unfair
                  AND (NOT $2::boolean OR COALESCE(admin_marked_unfair, false) = false)
            ),
            -- Player + game pairs where they were rostered onto a team.
            -- Same "backups don't count" rule used elsewhere in this session.
            player_games AS (
                SELECT
                    r.player_id,
                    eg.id                 AS game_id,
                    eg.game_date,
                    eg.winning_team,
                    eg.team_balance_score,
                    LOWER(t.team_name)    AS team_name_lower
                FROM registrations r
                JOIN eligible_games eg ON eg.id = r.game_id
                JOIN team_players tp   ON tp.player_id = r.player_id
                JOIN teams t           ON t.id = tp.team_id AND t.game_id = eg.id
                WHERE r.status = 'confirmed'
            ),
            -- Compute rating periods per player. Each player_stat_history row at T with
            -- rating H means "starting at T, the player had H". Period [T, next_T) carries
            -- that rating. First row gets an additional synthetic retroactive period
            -- [epoch, T) with the same rating — best-guess for games before any recorded
            -- history entry.
            --
            -- GK players: use goalkeeper_rating column from history instead of overall_rating.
            -- If player_stat_history doesn't track GK rating explicitly, fall back to overall.
            --
            -- Implementation note: avoid ORDER BY inside UNION arms (caused parse failures
            -- in the previous version — the alias 'psh' from one arm isn't visible to the
            -- UNION as a whole). Use ROW_NUMBER for the "earliest row per player" subselect.
            rating_periods AS (
                SELECT * FROM (
                    -- Forward periods: one per history row, ending at next change (or 2099)
                    SELECT
                        psh.player_id,
                        -- FIX-164: cast to int. player_stat_history.overall_rating and
                        -- goalkeeper_rating are NUMERIC(4,1) — without this cast,
                        -- json_object_agg() downstream produces keys like "88.0" instead
                        -- of "88", which the frontend cannot match (it iterates 75-99
                        -- as integers). Result was a near-empty grid for every player
                        -- with rating history. The no-history fallback arm (further
                        -- below) reads from players.overall_rating which is INTEGER,
                        -- so it was unaffected — that's why some players (Danny etc)
                        -- showed data while everyone with psh rows showed blank.
                        COALESCE(
                            CASE WHEN p.position = 'goalkeeper' THEN psh.goalkeeper_rating END,
                            psh.overall_rating
                        )::int AS ovr_in_period,
                        psh.created_at AS period_start,
                        COALESCE(
                            LEAD(psh.created_at) OVER (PARTITION BY psh.player_id ORDER BY psh.created_at),
                            '2099-01-01'::timestamp
                        ) AS period_end
                    FROM player_stat_history psh
                    JOIN players p ON p.id = psh.player_id
                    WHERE COALESCE(
                        CASE WHEN p.position = 'goalkeeper' THEN psh.goalkeeper_rating END,
                        psh.overall_rating
                    ) IS NOT NULL

                    UNION ALL

                    -- Retroactive period: each player's earliest rating, applied [epoch → first_at)
                    SELECT
                        player_id,
                        ovr_in_period,
                        '1970-01-01'::timestamp AS period_start,
                        first_at                AS period_end
                    FROM (
                        SELECT
                            psh.player_id,
                            -- FIX-164: cast to int (see forward arm comment above)
                            COALESCE(
                                CASE WHEN p.position = 'goalkeeper' THEN psh.goalkeeper_rating END,
                                psh.overall_rating
                            )::int AS ovr_in_period,
                            psh.created_at AS first_at,
                            ROW_NUMBER() OVER (PARTITION BY psh.player_id ORDER BY psh.created_at ASC) AS rn
                        FROM player_stat_history psh
                        JOIN players p ON p.id = psh.player_id
                        WHERE COALESCE(
                            CASE WHEN p.position = 'goalkeeper' THEN psh.goalkeeper_rating END,
                            psh.overall_rating
                        ) IS NOT NULL
                    ) earliest
                    WHERE rn = 1

                    UNION ALL

                    -- BUG-PERF-01: No-history fallback. Players with zero usable
                    -- player_stat_history rows (never recalibrated since signup)
                    -- got NO rating_periods row → ovr_at_game was always NULL →
                    -- filtered out of agg → empty per_ovr → blank grid row even
                    -- though they had played games. Catch-all period using their
                    -- CURRENT rating (from players table) spans all time so every
                    -- played game gets attributed.
                    SELECT
                        p.id AS player_id,
                        COALESCE(
                            CASE WHEN p.position = 'goalkeeper' THEN p.goalkeeper_rating END,
                            p.overall_rating
                        ) AS ovr_in_period,
                        '1970-01-01'::timestamp AS period_start,
                        '2099-01-01'::timestamp AS period_end
                    FROM players p
                    WHERE COALESCE(
                        CASE WHEN p.position = 'goalkeeper' THEN p.goalkeeper_rating END,
                        p.overall_rating
                    ) IS NOT NULL
                    AND NOT EXISTS (
                        SELECT 1
                        FROM player_stat_history psh2
                        WHERE psh2.player_id = p.id
                          AND COALESCE(
                              CASE WHEN p.position = 'goalkeeper' THEN psh2.goalkeeper_rating END,
                              psh2.overall_rating
                          ) IS NOT NULL
                    )
                ) all_periods
            ),
            -- Assign each player-game to the rating that was in effect when they played.
            -- Strict inequality on period_end handles the "same instant as wizard change"
            -- edge case correctly: a game played at exactly T is attributed to the OLD
            -- rating (the period that ended at T), not the new one (which starts at T).
            games_with_rating AS (
                SELECT
                    pg.player_id,
                    pg.winning_team,
                    pg.team_name_lower,
                    pg.team_balance_score,
                    rp.ovr_in_period AS ovr_at_game
                FROM player_games pg
                LEFT JOIN rating_periods rp
                    ON rp.player_id     = pg.player_id
                   AND pg.game_date     >= rp.period_start
                   AND pg.game_date     <  rp.period_end
            ),
            -- Aggregate per (player, rating). Wins via case-insensitive team_name match.
            agg AS (
                SELECT
                    player_id,
                    ovr_at_game,
                    COUNT(*)                                                            AS apps,
                    COUNT(*) FILTER (WHERE winning_team IS NOT NULL
                                       AND LOWER(winning_team) <> 'draw'
                                       AND LOWER(winning_team) = team_name_lower)       AS wins,
                    COUNT(*) FILTER (WHERE team_balance_score IS NOT NULL)               AS fair_apps
                FROM games_with_rating
                WHERE ovr_at_game IS NOT NULL
                GROUP BY player_id, ovr_at_game
            ),
            -- Build per-player JSON object keyed by rating, in a single pass (not per-player subquery)
            per_player_json AS (
                SELECT
                    player_id,
                    json_object_agg(
                        ovr_at_game::text,
                        json_build_object('apps', apps, 'wins', wins, 'fair_apps', fair_apps)
                    ) AS per_ovr
                FROM agg
                GROUP BY player_id
            )
            SELECT
                p.id, p.alias, p.full_name, p.squad_number,
                -- GK override: current_ovr is goalkeeper_rating for goalkeepers
                CASE WHEN p.position = 'goalkeeper' AND p.goalkeeper_rating IS NOT NULL
                     THEN p.goalkeeper_rating
                     ELSE p.overall_rating
                END                               AS current_ovr,
                (p.position = 'goalkeeper')       AS is_gk,
                COALESCE(pj.per_ovr, '{}'::json)  AS per_ovr
            FROM players p
            LEFT JOIN per_player_json pj ON pj.player_id = p.id
            ORDER BY
                CASE WHEN p.position = 'goalkeeper' AND p.goalkeeper_rating IS NOT NULL
                     THEN p.goalkeeper_rating
                     ELSE p.overall_rating
                END DESC NULLS LAST,
                p.squad_number NULLS LAST, p.full_name
        `, [filterNonStandard, filterUnfair]);

        res.json({
            players: result.rows,
            filters: { filter_non_standard: filterNonStandard, filter_unfair: filterUnfair }
        });
    } catch (error) {
        console.error('Players performance error:', error);
        // Surface the actual DB error to the admin caller — this is a superadmin-only
        // endpoint, no PII leak risk, and saves a round-trip of "what does the server log say?"
        res.status(500).json({
            error: 'Failed to load performance data',
            detail: error.message,
            hint: error.code ? `pg code ${error.code}` : undefined
        });
    }
});

// GET /api/admin/players/:id/stats-graph
// Returns per-overall-rating data points: for each distinct overall rating the player
// held, calculate Win% and MOTM% across all completed games played at that rating.
app.get('/api/admin/players/:id/stats-graph', authenticateToken, requireAdmin, async (req, res) => {
    try {
        const { id } = req.params;

        // 1. Build rating timeline: each period = (overall_rating, from_date, to_date)
        //    player_stat_history records each time rating changed
        const historyResult = await pool.query(`
            SELECT overall_rating, created_at
            FROM player_stat_history
            WHERE player_id = $1 AND overall_rating IS NOT NULL
            ORDER BY created_at ASC
        `, [id]);

        // Also get the player's current overall rating as the latest period
        const currentResult = await pool.query(
            'SELECT overall_rating, created_at FROM players WHERE id = $1',
            [id]
        );
        const current = currentResult.rows[0];

        // Build periods array
        const historyRows = historyResult.rows;
        const periods = [];

        // Add a synthetic "before first history entry" period using current rating if no history
        if (historyRows.length === 0) {
            if (current && current.overall_rating) {
                periods.push({
                    rating: parseFloat(current.overall_rating),
                    from: new Date('2020-01-01'),
                    to: new Date('2099-01-01')
                });
            }
        } else {
            // First period: from beginning of time to first history entry
            // (player had this rating before the first recorded change)
            periods.push({
                rating: parseFloat(historyRows[0].overall_rating),
                from: new Date('2020-01-01'),
                to: new Date(historyRows[0].created_at)
            });
            // Middle periods
            for (let i = 1; i < historyRows.length; i++) {
                periods.push({
                    rating: parseFloat(historyRows[i].overall_rating),
                    from: new Date(historyRows[i - 1].created_at),
                    to: new Date(historyRows[i].created_at)
                });
            }
            // Final period: last change to now
            periods.push({
                rating: parseFloat(current?.overall_rating || historyRows[historyRows.length - 1].overall_rating),
                from: new Date(historyRows[historyRows.length - 1].created_at),
                to: new Date('2099-01-01')
            });
        }

        // 2. For each period, get completed games the player appeared in and calculate stats
        const grouped = {}; // keyed by rating

        for (const period of periods) {
            const gamesResult = await pool.query(`
                SELECT
                    g.id,
                    g.game_date,
                    g.motm_winner_id,
                    g.winning_team,
                    t.team_name
                FROM registrations r
                JOIN games g ON g.id = r.game_id
                LEFT JOIN team_players tp ON tp.player_id = r.player_id
                LEFT JOIN teams t ON t.id = tp.team_id AND t.game_id = g.id
                WHERE r.player_id = $1
                  AND r.status = 'confirmed'
                  AND g.game_status = 'completed'
                  AND g.game_date >= $2
                  AND g.game_date < $3
            `, [id, period.from.toISOString(), period.to.toISOString()]);

            const rKey = period.rating;
            if (!grouped[rKey]) grouped[rKey] = { appearances: 0, wins: 0, motms: 0 };

            for (const g of gamesResult.rows) {
                grouped[rKey].appearances++;
                if (g.winning_team && g.team_name &&
                    g.winning_team.toLowerCase() === g.team_name.toLowerCase()) {
                    grouped[rKey].wins++;
                }
                if (parseInt(g.motm_winner_id) === parseInt(id)) {
                    grouped[rKey].motms++;
                }
            }
        }

        // 3. Build output — only include rating bands with at least 1 appearance
        const dataPoints = Object.entries(grouped)
            .filter(([, v]) => v.appearances > 0)
            .map(([rating, v]) => ({
                rating: parseFloat(rating),
                appearances: v.appearances,
                wins: v.wins,
                motms: v.motms,
                win_pct: v.appearances > 0 ? Math.round((v.wins / v.appearances) * 1000) / 10 : 0,
                motm_pct: v.appearances > 0 ? Math.round((v.motms / v.appearances) * 1000) / 10 : 0
            }))
            .sort((a, b) => a.rating - b.rating);

        res.json(dataPoints);
    } catch (error) {
        console.error('Stats graph error:', error);
        res.status(500).json({ error: 'Failed to load stats graph' });
    }
});

// GET /api/admin/audit/player/:id — full audit history for a player
app.get('/api/admin/audit/player/:id', authenticateToken, requireAdmin, async (req, res) => {
    try {
        const { id } = req.params;

        // 1. Balance history
        // FIX-102: Added ct.balance_before, ct.balance_after — were missing from SELECT,
        // causing audit.html to always render null for before→after balance arrows.
        const balance = await pool.query(`
            SELECT ct.created_at, ct.amount, ct.type, ct.description,
                   ct.balance_before, ct.balance_after,
                   p.alias as admin_alias, p.full_name as admin_name
            FROM credit_transactions ct
            LEFT JOIN users u ON u.id = ct.admin_id
            LEFT JOIN players p ON p.user_id = u.id
            WHERE ct.player_id = $1
            ORDER BY ct.created_at DESC
        `, [id]);

        // 2. Stat history
        const stats = await pool.query(`
            SELECT psh.created_at, psh.overall_rating, psh.defending_rating, psh.strength_rating,
                   psh.fitness_rating, psh.pace_rating, psh.decisions_rating,
                   psh.assisting_rating, psh.shooting_rating, psh.goalkeeper_rating,
                   psh.reliability_tier, p.alias as changed_by_alias, p.full_name as changed_by_name
            FROM player_stat_history psh
            LEFT JOIN players p ON p.id = psh.changed_by
            WHERE psh.player_id = $1
            ORDER BY psh.created_at DESC
        `, [id]);

        // 2b. Enrich each stat history row with "games at previous overall" context.
        // For every row where overall_rating actually changed vs the prior entry, we
        // count this player's STANDARD completed games that fall in the window
        // [prev.created_at, this.created_at) and classify W/D/L. Rendered in audit.html
        // under each stat row as:
        //   "12 games at 82: 7W/3D/2L, 58% win rate"
        //
        // Rules (confirmed with GAFFA):
        //   • Standard games only (team_selection_type in ('normal','standard') or NULL)
        //   • Player must be rostered onto a team — backups/unrostered don't count
        //   • Draw = winning_team literal 'draw'; win/loss by case-insensitive team_name match
        //   • First-ever history entry has no "previous overall" → no enrichment line
        //
        // Single query for the player's game history, then sliced per-row in JS. At typical
        // volume (tens of history rows × low-hundreds of games) this is trivially cheap
        // versus N correlated subqueries in SQL.
        const playerGames = await pool.query(`
            SELECT g.game_date,
                   LOWER(g.winning_team) AS winning_team,
                   LOWER(t.team_name)    AS team_name
            FROM registrations r
            JOIN games g        ON g.id = r.game_id
            JOIN team_players tp ON tp.player_id = r.player_id
            JOIN teams t        ON t.id = tp.team_id AND t.game_id = g.id
            WHERE r.player_id = $1
              AND r.status = 'confirmed'
              AND g.game_status = 'completed'
              AND COALESCE(g.team_selection_type, 'standard') IN ('normal', 'standard')
            ORDER BY g.game_date ASC
        `, [id]);

        const pg = playerGames.rows; // ASC by game_date
        const statsRows = stats.rows; // DESC by created_at
        for (let i = 0; i < statsRows.length; i++) {
            const r    = statsRows[i];
            const prev = statsRows[i + 1] || null; // next-oldest history row = "before" state

            // Only enrich when overall actually changed vs previous entry.
            // parseInt guards against numeric/string comparison mismatches from pg driver.
            const prevOvr = prev ? (prev.overall_rating != null ? parseInt(prev.overall_rating) : null) : null;
            const curOvr  = r.overall_rating != null ? parseInt(r.overall_rating) : null;

            if (prev == null || prevOvr == null || curOvr == null || prevOvr === curOvr) {
                r.old_overall   = null;
                r.apps_at_old   = null;
                r.wins_at_old   = null;
                r.draws_at_old  = null;
                r.losses_at_old = null;
                r.win_pct_at_old = null;
                continue;
            }

            const fromTs = new Date(prev.created_at).getTime();
            const toTs   = new Date(r.created_at).getTime();
            let apps = 0, wins = 0, draws = 0, losses = 0;
            for (const g of pg) {
                const gTs = new Date(g.game_date).getTime();
                if (gTs < fromTs || gTs >= toTs) continue;
                apps++;
                if (g.winning_team === 'draw') { draws++; continue; }
                if (g.winning_team && g.team_name && g.winning_team === g.team_name) { wins++; continue; }
                if (g.winning_team && g.team_name) { losses++; }
                // NULL winning_team or missing team_name: counted in apps but not classified
            }

            r.old_overall    = prevOvr;
            r.apps_at_old    = apps;
            r.wins_at_old    = wins;
            r.draws_at_old   = draws;
            r.losses_at_old  = losses;
            r.win_pct_at_old = apps > 0 ? Math.round((wins / apps) * 1000) / 10 : null;
        }

        // 3. Registration events (sign up / drop out)
        const regEvents = await pool.query(`
            SELECT re.created_at, re.event_type, re.detail,
                   g.game_date, g.format, g.game_url, v.name as venue_name
            FROM registration_events re
            JOIN games g ON g.id = re.game_id
            LEFT JOIN venues v ON v.id = g.venue_id
            WHERE re.player_id = $1
            ORDER BY re.created_at DESC
        `, [id]);

        // 3b. Current pair/avoid preferences for this player (upcoming games only)
        const regPreferences = await pool.query(`
            SELECT
                r.game_id,
                g.game_date,
                g.game_url,
                v.name AS venue_name,
                rp.preference_type,
                COALESCE(tp.alias, tp.full_name) AS target_name
            FROM registrations r
            JOIN games g ON g.id = r.game_id
            LEFT JOIN venues v ON v.id = g.venue_id
            JOIN registration_preferences rp ON rp.registration_id = r.id
            JOIN players tp ON tp.id = rp.target_player_id
            WHERE r.player_id = $1
              AND g.game_status NOT IN ('completed', 'cancelled')
            ORDER BY g.game_date ASC, rp.preference_type, tp.alias, tp.full_name
        `, [id]);

        // 4. MOTM received
        const motmReceived = await pool.query(`
            SELECT g.game_date, g.format, g.game_url, v.name as venue_name,
                   g.motm_winner_id
            FROM games g
            LEFT JOIN venues v ON v.id = g.venue_id
            WHERE g.motm_winner_id = $1 AND g.game_status = 'completed'
            ORDER BY g.game_date DESC
        `, [id]);

        // 5. MOTM votes cast
        const motmVotes = await pool.query(`
            SELECT mv.created_at, g.game_date, g.format, g.game_url, v.name as venue_name,
                   p.alias as voted_for_alias, p.full_name as voted_for_name
            FROM motm_votes mv
            JOIN games g ON g.id = mv.game_id
            LEFT JOIN venues v ON v.id = g.venue_id
            JOIN players p ON p.id = mv.voted_for_id
            WHERE mv.voter_id = $1
            ORDER BY mv.created_at DESC
        `, [id]);

        // 6. Admin actions (audit_logs targeting this player)
        const adminActions = await pool.query(`
            SELECT al.created_at, al.action, al.detail,
                   p.alias as admin_alias, p.full_name as admin_name
            FROM audit_logs al
            LEFT JOIN players p ON p.id = al.admin_id
            WHERE al.target_id = $1 AND al.action != 'login'
            ORDER BY al.created_at DESC
        `, [id]);

        // 8. Discipline records with IDs (for removal UI)
        const disciplineRecords = await pool.query(`
            SELECT dr.id, dr.points, dr.offense_type, dr.created_at,
                   g.game_date, v.name AS venue_name, g.game_url,
                   COALESCE(p.alias, p.full_name) AS recorded_by_name
            FROM discipline_records dr
            LEFT JOIN games g ON g.id = dr.game_id
            LEFT JOIN venues v ON v.id = g.venue_id
            LEFT JOIN users u ON u.id = dr.recorded_by
            LEFT JOIN players p ON p.user_id = u.id
            WHERE dr.player_id = $1
            ORDER BY dr.created_at DESC
        `, [id]);

        // 7. Login events (from audit_logs where action = 'login' and target = this player)
        const loginEvents = await pool.query(`
            SELECT al.created_at, al.detail
            FROM audit_logs al
            WHERE al.target_id = $1 AND al.action = 'login'
            ORDER BY al.created_at DESC
            LIMIT 100
        `, [id]);

        // 9a. Award votes CAST by this player
        const awardVotesCast = await pool.query(`
            SELECT gav.award_type, COALESCE(gav.created_at, g.game_date) AS created_at,
                   g.game_date, g.game_url, v.name AS venue_name,
                   p.alias AS nominee_alias, p.full_name AS nominee_name
            FROM game_award_votes gav
            JOIN games g ON g.id = gav.game_id
            LEFT JOIN venues v ON v.id = g.venue_id
            JOIN players p ON p.id = gav.nominee_player_id
            WHERE gav.voter_player_id = $1
            ORDER BY COALESCE(gav.created_at, g.game_date) DESC
        `, [id]);

        // 9b. Award votes RECEIVED by this player
        const awardVotesReceived = await pool.query(`
            SELECT gav.award_type, COALESCE(gav.created_at, g.game_date) AS created_at,
                   g.game_date, g.game_url, v.name AS venue_name,
                   p.alias AS voter_alias, p.full_name AS voter_name
            FROM game_award_votes gav
            JOIN games g ON g.id = gav.game_id
            LEFT JOIN venues v ON v.id = g.venue_id
            JOIN players p ON p.id = gav.voter_player_id
            WHERE gav.nominee_player_id = $1
            ORDER BY COALESCE(gav.created_at, g.game_date) DESC
        `, [id]);

        // 10. Game-linked stat changes for this player (from bulk post-game/wizard updates)
        const gameStatChanges = await pool.query(`
            SELECT gsc.created_at, gsc.game_id,
                   gsc.old_overall, gsc.new_overall,
                   gsc.old_gk,  gsc.new_gk,
                   gsc.old_def, gsc.new_def,
                   gsc.old_str, gsc.new_str,
                   gsc.old_fit, gsc.new_fit,
                   gsc.old_pac, gsc.new_pac,
                   gsc.old_dec, gsc.new_dec,
                   gsc.old_ass, gsc.new_ass,
                   gsc.old_sho, gsc.new_sho,
                   g.game_date, g.game_url, v.name AS venue_name,
                   cb.alias AS changed_by_alias, cb.full_name AS changed_by_name
            FROM game_stat_changes gsc
            JOIN games g ON g.id = gsc.game_id
            LEFT JOIN venues v ON v.id = g.venue_id
            LEFT JOIN players cb ON cb.id = gsc.changed_by
            WHERE gsc.player_id = $1
            ORDER BY gsc.created_at DESC
        `, [id]).catch(() => ({ rows: [] }));

        // ─── Phase A — Tag every row with category/sub/actor/severity ─────
        // The frontend uses these for the new filter axes. The mapping for
        // each row source is informed by the table it came from, since some
        // rows (like balance ledger entries) don't carry an action code in
        // the same way audit_logs do.
        const tag = (rows, codeOf) => rows.map(r => enrichAuditRow(r, codeOf(r)));

        // Balance — credit_transactions.type is the action code (game_fee, refund, etc.)
        const balanceTagged = balance.rows.map(r => {
            // If admin_id was set on the transaction, override actor to 'admin'
            const actor = r.admin_alias || r.admin_name ? 'admin' : undefined;
            return enrichAuditRow(r, r.type || 'admin_adjustment', actor ? { actor } : {});
        });

        // Stat history — synthetic action code: admin override if changed_by present, else system
        const statsTagged = stats.rows.map(r => enrichAuditRow(r,
            r.changed_by_alias || r.changed_by_name ? 'stats_updated' : 'player_stats_updated'));

        // Registrations / regEvents use event_type
        const regEventsTagged = regEvents.rows.map(r => enrichAuditRow(r, r.event_type || 'signed_up'));

        // MOTM
        const motmReceivedTagged = motmReceived.rows.map(r => enrichAuditRow(r, 'motm_received'));
        const motmVotesTagged    = motmVotes.rows.map(r    => enrichAuditRow(r, 'motm_vote_cast'));

        // Awards
        const awardCastTagged     = awardVotesCast.rows.map(r => enrichAuditRow(r, 'award_vote_cast'));
        const awardReceivedTagged = awardVotesReceived.rows.map(r => enrichAuditRow(r, 'award_vote_received'));

        // Admin actions: use the .action field
        const adminActionsTagged = adminActions.rows.map(r => enrichAuditRow(r, r.action || 'player_updated'));

        // Login events
        const loginTagged = loginEvents.rows.map(r => enrichAuditRow(r, 'login'));

        // Discipline records (separate table, conceptually a discipline event)
        const disciplineTagged = disciplineRecords.rows.map(r =>
            enrichAuditRow(r, r.recorded_by_name ? 'discipline_added' : 'discipline_recorded'));

        // Game stat changes (from bulk completion wizard)
        const gameStatChangesTagged = gameStatChanges.rows.map(r =>
            enrichAuditRow(r, r.changed_by_alias || r.changed_by_name ? 'stats_updated' : 'player_stats_updated'));

        res.json({
            balance: balanceTagged,
            stats: statsTagged,
            registrations: regEventsTagged,
            registrationPreferences: regPreferences.rows,    // not user-facing events
            motmReceived: motmReceivedTagged,
            motmVotesCast: motmVotesTagged,
            awardVotesCast: awardCastTagged,
            awardVotesReceived: awardReceivedTagged,
            adminActions: adminActionsTagged,
            loginEvents: loginTagged,
            disciplineRecords: disciplineTagged,
            gameStatChanges: gameStatChangesTagged
        });
    } catch (error) {
        console.error('Player audit error:', error);
        res.status(500).json({ error: 'Failed to load player audit' });
    }
});

// GET /api/admin/audit/game/:id — full audit history for a game
app.get('/api/admin/audit/game/:id', authenticateToken, requireAdmin, async (req, res) => {
    try {
        const { id } = req.params;

        // 1. Game audit log (admin actions)
        const gameLogs = await pool.query(`
            SELECT gal.created_at, gal.action, gal.detail,
                   p.alias as admin_alias, p.full_name as admin_name
            FROM game_audit_log gal
            LEFT JOIN players p ON p.id = gal.admin_id
            WHERE gal.game_id = $1
            ORDER BY gal.created_at DESC
        `, [id]);

        // 2. Registration events for this game
        const regEvents = await pool.query(`
            SELECT re.created_at, re.event_type, re.detail,
                   p.alias as player_alias, p.full_name as player_name, p.squad_number
            FROM registration_events re
            JOIN players p ON p.id = re.player_id
            WHERE re.game_id = $1
            ORDER BY re.created_at DESC
        `, [id]);

        // 3. Registrations (signed up currently) with pair/avoid names
        const currentRegs = await pool.query(`
            SELECT r.registered_at, r.status, r.backup_type, r.position_preference,
                   p.alias, p.full_name, p.squad_number,
                   (
                       SELECT string_agg(COALESCE(tp.alias, tp.full_name), ', ' ORDER BY tp.alias, tp.full_name)
                       FROM registration_preferences rp
                       JOIN players tp ON tp.id = rp.target_player_id
                       WHERE rp.registration_id = r.id AND rp.preference_type = 'pair'
                   ) AS pair_names,
                   (
                       SELECT string_agg(COALESCE(tp.alias, tp.full_name), ', ' ORDER BY tp.alias, tp.full_name)
                       FROM registration_preferences rp
                       JOIN players tp ON tp.id = rp.target_player_id
                       WHERE rp.registration_id = r.id AND rp.preference_type = 'avoid'
                   ) AS avoid_names
            FROM registrations r
            JOIN players p ON p.id = r.player_id
            WHERE r.game_id = $1
            ORDER BY r.registered_at ASC
        `, [id]);

        // 4. URL views for this game (who viewed the game page and when)
        const urlViews = await pool.query(`
            SELECT gv.viewed_at,
                   p.alias, p.full_name, p.squad_number,
                   CASE WHEN p.id IS NULL THEN 'Guest (not logged in)' ELSE NULL END as guest_label
            FROM game_url_views gv
            LEFT JOIN players p ON p.id = gv.player_id
            WHERE gv.game_id = $1
            ORDER BY gv.viewed_at DESC
            LIMIT 200
        `, [id]).catch(() => ({ rows: [] })); // graceful if table doesn't exist yet

        // 5. Award votes for this game (full breakdown — who voted for whom per award)
        const awardVotes = await pool.query(`
            SELECT gav.award_type,
                   vp.alias AS voter_alias, vp.full_name AS voter_name, vp.squad_number AS voter_squad,
                   np.alias AS nominee_alias, np.full_name AS nominee_name, np.squad_number AS nominee_squad,
                   COALESCE(gav.created_at, g.game_date) AS voted_at
            FROM game_award_votes gav
            JOIN games g ON g.id = gav.game_id
            JOIN players vp ON vp.id = gav.voter_player_id
            JOIN players np ON np.id = gav.nominee_player_id
            WHERE gav.game_id = $1
            ORDER BY gav.award_type ASC, COALESCE(gav.created_at, g.game_date) ASC
        `, [id]).catch(() => ({ rows: [] }));

        // 6. Stat changes — per-player before/after from game_stat_changes table
        const statChanges = await pool.query(`
            SELECT gsc.player_id, gsc.created_at,
                   gsc.old_overall, gsc.new_overall,
                   gsc.old_gk,  gsc.new_gk,
                   gsc.old_def, gsc.new_def,
                   gsc.old_str, gsc.new_str,
                   gsc.old_fit, gsc.new_fit,
                   gsc.old_pac, gsc.new_pac,
                   gsc.old_dec, gsc.new_dec,
                   gsc.old_ass, gsc.new_ass,
                   gsc.old_sho, gsc.new_sho,
                   p.alias, p.full_name, p.squad_number,
                   cb.alias AS changed_by_alias, cb.full_name AS changed_by_name
            FROM game_stat_changes gsc
            JOIN players p ON p.id = gsc.player_id
            LEFT JOIN players cb ON cb.id = gsc.changed_by
            WHERE gsc.game_id = $1
            ORDER BY COALESCE(p.alias, p.full_name)
        `, [id]).catch(() => ({ rows: [] })); // graceful if table not yet migrated

        // ─── Phase A — Tag every row with category/sub/actor/severity ─────
        const gameLogsTagged    = gameLogs.rows.map(r => enrichAuditRow(r, r.action || 'settings_updated'));
        const regEventsTagged   = regEvents.rows.map(r => enrichAuditRow(r, r.event_type || 'signed_up'));
        const urlViewsTagged    = urlViews.rows.map(r => enrichAuditRow(r, 'page_view'));
        const awardVotesTagged  = awardVotes.rows.map(r => enrichAuditRow(r, 'award_vote_cast'));
        const statChangesTagged = statChanges.rows.map(r =>
            enrichAuditRow(r, r.changed_by_alias || r.changed_by_name ? 'stats_updated' : 'player_stats_updated'));

        res.json({
            gameLogs: gameLogsTagged,
            registrationEvents: regEventsTagged,
            currentRegistrations: currentRegs.rows,   // squad snapshot — not events
            urlViews: urlViewsTagged,
            awardVotes: awardVotesTagged,
            statChanges: statChangesTagged
        });
    } catch (error) {
        console.error('Game audit error:', error);
        res.status(500).json({ error: 'Failed to load game audit' });
    }
});

// ── ADMIN: DM INBOX / THREAD VIEW ────────────────────────────────────────────

// GET /api/admin/players/:playerId/dm-conversations
// Admin inbox view — list all conversations for a player with previews
app.get('/api/admin/players/:playerId/dm-conversations', authenticateToken, requireAdmin, async (req, res) => {
    const { playerId } = req.params;
    try {
        const check = await pool.query(
            'SELECT id, COALESCE(alias, full_name) AS name FROM players WHERE id = $1',
            [playerId]
        );
        if (check.rows.length === 0) return res.status(404).json({ error: 'Player not found' });

        const result = await pool.query(`
            SELECT other_player_id, other_name, other_alias, other_tier,
                   last_message, last_message_at, last_sender_id,
                   total_messages, unread_count
            FROM (
                SELECT
                    CASE WHEN dm.sender_id = $1 THEN dm.recipient_id
                         ELSE dm.sender_id END AS other_player_id,
                    p.full_name AS other_name, p.alias AS other_alias,
                    p.reliability_tier AS other_tier,
                    dm.message AS last_message, dm.created_at AS last_message_at,
                    dm.sender_id AS last_sender_id, dm.read_at,
                    COUNT(*) OVER (
                        PARTITION BY LEAST(dm.sender_id, dm.recipient_id),
                                     GREATEST(dm.sender_id, dm.recipient_id)
                    ) AS total_messages,
                    COUNT(*) FILTER (
                        WHERE dm.sender_id != $1 AND dm.read_at IS NULL
                    ) OVER (
                        PARTITION BY LEAST(dm.sender_id, dm.recipient_id),
                                     GREATEST(dm.sender_id, dm.recipient_id)
                    ) AS unread_count,
                    ROW_NUMBER() OVER (
                        PARTITION BY LEAST(dm.sender_id, dm.recipient_id),
                                     GREATEST(dm.sender_id, dm.recipient_id)
                        ORDER BY dm.created_at DESC
                    ) AS rn
                FROM direct_messages dm
                JOIN players p ON p.id = CASE WHEN dm.sender_id = $1
                    THEN dm.recipient_id ELSE dm.sender_id END
                WHERE (dm.sender_id = $1 OR dm.recipient_id = $1)
                  AND dm.deleted_at IS NULL
            ) sub
            WHERE rn = 1
            ORDER BY last_message_at DESC
        `, [playerId]);

        res.json({ playerName: check.rows[0].name, conversations: result.rows });
    } catch (error) {
        console.error('Admin DM conversations error:', error);
        res.status(500).json({ error: 'Failed to load conversations' });
    }
});

// GET /api/admin/dm/all-conversations
// Platform-wide admin view — all unique DM conversation pairs, most recent first
// GET /api/admin/dm/all-conversations?offset=0&limit=100
// Paginated: returns { conversations, total, hasMore }
app.get('/api/admin/dm/all-conversations', authenticateToken, requireAdmin, async (req, res) => {
    const limit  = Math.min(parseInt(req.query.limit)  || 100, 200);
    const offset = Math.max(parseInt(req.query.offset) || 0,   0);
    try {
        // Count total unique conversations for hasMore
        const countRes = await pool.query(`
            SELECT COUNT(DISTINCT
                LEAST(sender_id, recipient_id)::text || '_' ||
                GREATEST(sender_id, recipient_id)::text
            ) AS total
            FROM direct_messages WHERE deleted_at IS NULL
        `);
        const total = parseInt(countRes.rows[0].total);

        // FIX: use a ranked subquery instead of correlated subqueries referencing
        // ungrouped outer columns — PostgreSQL strict GROUP BY rejects those.
        const result = await pool.query(`
            WITH ranked AS (
                SELECT
                    LEAST(sender_id, recipient_id)    AS player_a_id,
                    GREATEST(sender_id, recipient_id) AS player_b_id,
                    message,
                    sender_id                          AS last_sender_id,
                    created_at,
                    ROW_NUMBER() OVER (
                        PARTITION BY LEAST(sender_id, recipient_id),
                                     GREATEST(sender_id, recipient_id)
                        ORDER BY created_at DESC
                    ) AS rn,
                    COUNT(*) OVER (
                        PARTITION BY LEAST(sender_id, recipient_id),
                                     GREATEST(sender_id, recipient_id)
                    ) AS total_messages
                FROM direct_messages
                WHERE deleted_at IS NULL
            )
            SELECT
                r.player_a_id,
                r.player_b_id,
                COALESCE(pa.alias, pa.full_name) AS player_a_name,
                COALESCE(pb.alias, pb.full_name) AS player_b_name,
                pa.reliability_tier              AS player_a_tier,
                pb.reliability_tier              AS player_b_tier,
                r.created_at                     AS last_message_at,
                r.total_messages,
                r.message                        AS last_message,
                r.last_sender_id
            FROM ranked r
            JOIN players pa ON pa.id = r.player_a_id
            JOIN players pb ON pb.id = r.player_b_id
            WHERE r.rn = 1
            ORDER BY r.created_at DESC
            LIMIT $1 OFFSET $2
        `, [limit, offset]);
        res.json({
            conversations: result.rows,
            total,
            hasMore: offset + result.rows.length < total,
        });
    } catch (error) {
        console.error('Admin all-conversations error:', error);
        res.status(500).json({ error: 'Failed to load conversations' });
    }
});

// GET /api/admin/dm/recent-messages — latest individual messages platform-wide
app.get('/api/admin/dm/recent-messages', authenticateToken, requireAdmin, async (req, res) => {
    const limit  = Math.min(parseInt(req.query.limit)  || 50, 200);
    const offset = Math.max(parseInt(req.query.offset) || 0,  0);
    try {
        const result = await pool.query(`
            SELECT
                dm.id,
                dm.sender_id,
                dm.recipient_id,
                dm.message,
                dm.created_at,
                dm.read_at,
                COALESCE(ps.alias, ps.full_name) AS sender_name,
                COALESCE(pr.alias, pr.full_name) AS receiver_name
            FROM direct_messages dm
            JOIN players ps ON ps.id = dm.sender_id
            JOIN players pr ON pr.id = dm.recipient_id
            WHERE dm.deleted_at IS NULL
            ORDER BY dm.created_at DESC
            LIMIT $1 OFFSET $2
        `, [limit, offset]);

        const countRes = await pool.query(
            'SELECT COUNT(*) AS total FROM direct_messages WHERE deleted_at IS NULL'
        );
        const total = parseInt(countRes.rows[0].total);

        res.json({
            messages: result.rows,
            total,
            hasMore: offset + result.rows.length < total
        });
    } catch (error) {
        console.error('Recent messages error:', error);
        res.status(500).json({ error: 'Failed to load recent messages' });
    }
});

// GET /api/admin/dm-thread/:subjectId/:otherId
// Full thread view between two players — read-only admin view
app.get('/api/admin/dm-thread/:subjectId/:otherId', authenticateToken, requireAdmin, async (req, res) => {
    const { subjectId, otherId } = req.params;
    try {
        const check = await pool.query(
            'SELECT id, COALESCE(alias, full_name) AS name FROM players WHERE id = ANY($1)',
            [[subjectId, otherId]]
        );
        if (check.rows.length < 2) return res.status(404).json({ error: 'One or both players not found' });

        const result = await pool.query(`
            SELECT dm.id, dm.sender_id, dm.recipient_id, dm.message,
                   dm.read_at, dm.created_at,
                   COALESCE(p.alias, p.full_name, 'Unknown') AS sender_name,
                   p.squad_number AS sender_squad
            FROM direct_messages dm
            JOIN players p ON p.id = dm.sender_id
            WHERE (
                (dm.sender_id = $1 AND dm.recipient_id = $2)
                OR
                (dm.sender_id = $2 AND dm.recipient_id = $1)
            )
            AND dm.deleted_at IS NULL
            ORDER BY dm.created_at ASC
        `, [subjectId, otherId]);

        const names = {};
        check.rows.forEach(r => { names[r.id] = r.name; });
        res.json({
            messages:    result.rows,
            subjectName: names[subjectId] || 'Unknown',
            otherName:   names[otherId]   || 'Unknown',
            total:       result.rows.length
        });
    } catch (error) {
        console.error('Admin DM thread error:', error);
        res.status(500).json({ error: 'Failed to load thread' });
    }
});

// ═══════════════════════════════════════════════════════════════════════════
// FIX-271 — MESSAGING RESTRICTIONS (superadmin)
// ═══════════════════════════════════════════════════════════════════════════
// Block/mute a player from sending DMs platform-wide. Three duration modes:
//   - 24h, 7d, or forever (durationHours = 24, 168, or null).
// The check fires inside POST /api/dm/:playerId — currently-blocked senders
// receive 403 { error: 'messaging_blocked', detail: <reason + until> }.
// Audit-logged via comms.messaging_restrictions sub.

// Helper — single source of truth for "is this player currently blocked".
// SQL clause used by both the DM send gate and the admin listing endpoint.
const _MSG_BLOCKED_SQL = `
    messaging_blocked_at IS NOT NULL
    AND (messaging_blocked_until IS NULL OR messaging_blocked_until > NOW())
`;

// GET /api/admin/messaging/blocked — list players currently blocked from sending.
app.get('/api/admin/messaging/blocked', authenticateToken, requireSuperAdmin, async (req, res) => {
    try {
        const result = await pool.query(`
            SELECT id, alias, full_name, squad_number,
                   messaging_blocked_at,
                   messaging_blocked_until,
                   messaging_block_reason
              FROM players
             WHERE ${_MSG_BLOCKED_SQL}
             ORDER BY messaging_blocked_at DESC
        `);
        res.json({ blocked: result.rows });
    } catch (e) {
        console.error('GET /api/admin/messaging/blocked error:', e);
        res.status(500).json({ error: 'server_error', detail: e.message });
    }
});

// POST /api/admin/messaging/block/:playerId
// Body: { durationHours: 24 | 168 | null, reason: string }
//   durationHours === null  →  forever (messaging_blocked_until = NULL)
//   durationHours === N     →  mute expires at NOW() + N hours
app.post('/api/admin/messaging/block/:playerId', authenticateToken, requireSuperAdmin, async (req, res) => {
    try {
        const { playerId } = req.params;
        const { durationHours, reason } = req.body || {};

        // Validate durationHours — must be null OR a positive number ≤ a year.
        let hours = null;
        if (durationHours !== null && durationHours !== undefined) {
            const n = Number(durationHours);
            if (!Number.isFinite(n) || n <= 0 || n > 24 * 365) {
                return res.status(400).json({ error: 'durationHours must be null or between 1 and 8760 (1 year)' });
            }
            hours = n;
        }

        // Verify target exists (avoid silently 'updating' nothing — return 404).
        const targetR = await pool.query(
            'SELECT id, alias, full_name FROM players WHERE id = $1', [playerId]
        );
        if (targetR.rows.length === 0) return res.status(404).json({ error: 'player_not_found' });
        const target = targetR.rows[0];

        const cleanReason = (reason && typeof reason === 'string')
            ? reason.trim().slice(0, 500) || null
            : null;

        const upd = await pool.query(`
            UPDATE players
               SET messaging_blocked_at    = NOW(),
                   messaging_blocked_until = $2,
                   messaging_block_reason  = $3
             WHERE id = $1
            RETURNING messaging_blocked_at, messaging_blocked_until, messaging_block_reason
        `, [
            playerId,
            hours === null ? null : new Date(Date.now() + hours * 3600 * 1000),
            cleanReason,
        ]);

        const durationLabel = hours === null ? 'forever' : (hours === 24 ? '24h' : (hours === 168 ? '7d' : `${hours}h`));
        auditLog(pool, req.user.playerId, 'dm_block', playerId,
            `Muted ${target.alias || target.full_name} for ${durationLabel}${cleanReason ? ` — ${cleanReason}` : ''}`)
            .catch(() => {});

        res.json({
            ok: true,
            blocked_at:    upd.rows[0].messaging_blocked_at,
            blocked_until: upd.rows[0].messaging_blocked_until,
            reason:        upd.rows[0].messaging_block_reason,
        });
    } catch (e) {
        console.error('POST /api/admin/messaging/block error:', e);
        res.status(500).json({ error: 'server_error', detail: e.message });
    }
});

// POST /api/admin/messaging/unblock/:playerId — clear all three block columns.
app.post('/api/admin/messaging/unblock/:playerId', authenticateToken, requireSuperAdmin, async (req, res) => {
    try {
        const { playerId } = req.params;
        const targetR = await pool.query(
            'SELECT id, alias, full_name FROM players WHERE id = $1', [playerId]
        );
        if (targetR.rows.length === 0) return res.status(404).json({ error: 'player_not_found' });
        const target = targetR.rows[0];

        await pool.query(`
            UPDATE players
               SET messaging_blocked_at    = NULL,
                   messaging_blocked_until = NULL,
                   messaging_block_reason  = NULL
             WHERE id = $1
        `, [playerId]);

        auditLog(pool, req.user.playerId, 'dm_unblock', playerId,
            `Unmuted ${target.alias || target.full_name}`).catch(() => {});

        res.json({ ok: true });
    } catch (e) {
        console.error('POST /api/admin/messaging/unblock error:', e);
        res.status(500).json({ error: 'server_error', detail: e.message });
    }
});

// GET /api/admin/messaging/spree-history?days=N — players who hit ≥3 unique recipients
// on any single calendar day (Europe/London) in the last N days. Useful for retrospective
// review even if the email alert was missed. Default N = 7, capped at 60 for safety.
app.get('/api/admin/messaging/spree-history', authenticateToken, requireSuperAdmin, async (req, res) => {
    try {
        const days = Math.min(60, Math.max(1, parseInt(req.query.days) || 7));
        const result = await pool.query(`
            SELECT
              dm.sender_id                                              AS sender_id,
              COALESCE(p.alias, p.full_name)                            AS sender_name,
              p.squad_number                                            AS squad_number,
              (dm.created_at AT TIME ZONE 'Europe/London')::date        AS day,
              COUNT(DISTINCT dm.recipient_id)::int                      AS unique_recipients,
              COUNT(*)::int                                             AS total_messages
              FROM direct_messages dm
              JOIN players p ON p.id = dm.sender_id
             WHERE dm.deleted_at IS NULL
               AND dm.created_at >= NOW() - ($1 || ' days')::interval
             GROUP BY dm.sender_id, p.alias, p.full_name, p.squad_number, day
            HAVING COUNT(DISTINCT dm.recipient_id) >= 3
             ORDER BY day DESC, unique_recipients DESC
        `, [String(days)]);
        res.json({ days, rows: result.rows });
    } catch (e) {
        console.error('GET /api/admin/messaging/spree-history error:', e);
        res.status(500).json({ error: 'server_error', detail: e.message });
    }
});

