// ── ADMIN: UNBAN PLAYER ───────────────────────────────────────────────────────

// POST /api/admin/players/:id/discipline — manually add discipline points (admin only)
// Points number only — no reason required. Recalculates tier immediately.
//
// IMPORTANT: DISC_TIER_THRESHOLDS below must match your calculate_player_tier DB function.
// Adjust these constants if tier behaviour doesn't match what you expect.
// These thresholds apply to the REVOLVING window (last 10 completed games + all manual entries).
const DISC_TIER_THRESHOLDS = { black: 25, white: 10, bronze: 4, silver: 1 };
function tierFromRevolvingPoints(pts) {
    if (pts >= DISC_TIER_THRESHOLDS.black)  return 'black';
    if (pts >= DISC_TIER_THRESHOLDS.white)  return 'white';
    if (pts >= DISC_TIER_THRESHOLDS.bronze) return 'bronze';
    if (pts >= DISC_TIER_THRESHOLDS.silver) return 'silver';
    return 'gold';
}

// Writes tier to DB and manages white_ban_started_at:
// becoming white → stamps NOW() (if not already set)
// leaving white  → clears to NULL; other transitions → leave column alone
//
// FIX-296: explicit $1::text casts on all three uses of $1. Without them,
// PG 14+ raises "inconsistent types deduced for parameter $1" (SQLSTATE 42P08,
// detail: text versus character varying) because reliability_tier is a
// varchar column (suggests $1::varchar) while the literal 'white' comparisons
// are text (suggest $1::text), and the planner can't reconcile across the
// SET clause and the CASE WHEN clauses. Casting $1 to text pins the type;
// the SET clause auto-implicit-casts text→varchar which is allowed under
// PG assignment-cast rules. Same root cause as FIX-292's $1::uuid fixes,
// just for text/varchar deduction instead of uuid/text. Patching this
// helper fixes all 6 call sites at once (discipline add, discipline remove,
// admin recalc-tier, white-ban cron, late-dropout setImmediate, etc).
async function applyTierChange(db, playerId, newTier) {
    await db.query(
        `UPDATE players
         SET reliability_tier     = $1::text,
             white_ban_started_at = CASE
               WHEN $1::text = 'white' AND white_ban_started_at IS NULL THEN NOW()
               WHEN $1::text != 'white' THEN NULL
               ELSE white_ban_started_at
             END
         WHERE id = $2::uuid`,
        [newTier, playerId]
    );
}

app.post('/api/admin/players/:id/discipline', authenticateToken, requireAdmin, async (req, res) => {
    const { id } = req.params;
    const { points } = req.body;

    const pts = parseInt(points);
    if (!pts || pts < 1 || pts > 20) {
        return res.status(400).json({ error: 'Points must be between 1 and 20' });
    }

    const client = await pool.connect();
    try {
        await client.query('BEGIN');

        // Insert manual record (game_id NULL = manual admin entry)
        await client.query(`
            INSERT INTO discipline_records (player_id, game_id, points, offense_type, recorded_by)
            VALUES ($1, NULL, $2, 'Manual (admin)', $3)
        `, [id, pts, req.user.userId]);

        // Compute revolving points inline — includes manual (game_id IS NULL) entries.
        // calculate_player_tier() is a DB function that filters game_id IS NOT NULL so it
        // never counts manual entries. We bypass it here and derive tier ourselves.
        //
        // FIX-292: explicit ::uuid casts on $1 (same reason as the discipline-remove
        // endpoint — PG 14+ can deduce inconsistent types for $1 when it's used
        // in both the outer SELECT and the inner correlated subquery).
        const revolvingResult = await client.query(`
            SELECT COALESCE(SUM(dr.points), 0) AS revolving_pts
            FROM discipline_records dr
            WHERE dr.player_id = $1::uuid
            AND (dr.game_id IS NULL OR dr.game_id IN (
                SELECT r.game_id FROM registrations r
                JOIN games g ON g.id = r.game_id
                WHERE r.player_id = $1::uuid AND r.status = 'confirmed'
                AND g.game_status = 'completed'
                ORDER BY g.game_date DESC LIMIT 10
            ))
        `, [id]);
        const revolvingPts = parseInt(revolvingResult.rows[0].revolving_pts);
        const newTier = tierFromRevolvingPoints(revolvingPts);
        await applyTierChange(client, id, newTier);

        await client.query('COMMIT');
        res.json({ success: true, newTier, pointsAdded: pts, revolvingTotal: revolvingPts });
        setImmediate(async () => {
            await auditLog(pool, req.user.playerId, 'discipline_added', id,
                `${pts} point(s) added manually | revolving total: ${revolvingPts} | new tier: ${newTier}`);
        });
    } catch (error) {
        await client.query('ROLLBACK').catch(() => {});
        console.error('Add discipline points error:', error);
        res.status(500).json({ error: 'Failed to add discipline points' });
    } finally {
        client.release();
    }
});

// DELETE /api/admin/discipline/:recordId — remove a discipline record and recalculate tier
app.delete('/api/admin/discipline/:recordId', authenticateToken, requireAdmin, async (req, res) => {
    const { recordId } = req.params;
    // FIX-250: surface actual SQL/runtime errors so superadmin can self-diagnose
    // when this flow fails. Previously the endpoint returned only "Failed to
    // remove discipline record" and the real error was swallowed in console.error
    // server-side, leaving the admin blind. The endpoint is requireAdmin-gated
    // so leaking error.message client-side is acceptable here.
    const client = await pool.connect();
    try {
        await client.query('BEGIN');

        // Fetch the record before deleting so we can audit it
        const recordResult = await client.query(
            'SELECT id, player_id, points, offense_type FROM discipline_records WHERE id = $1',
            [recordId]
        );
        if (recordResult.rows.length === 0) {
            await client.query('ROLLBACK');
            return res.status(404).json({ error: 'Discipline record not found' });
        }
        const record = recordResult.rows[0];
        const playerId = record.player_id;

        // Delete the record
        await client.query('DELETE FROM discipline_records WHERE id = $1', [recordId]);

        // FIX-250: Restructured recalc — the previous version used ORDER BY +
        // LIMIT inside an IN() subquery which is valid PostgreSQL but unusual.
        // Restructure as a derived-table LEFT JOIN for clarity and to make the
        // 10-most-recent-completed-games intent explicit. Same result, lower
        // surprise factor for future maintainers.
        //
        // FIX-292: explicit ::uuid casts on $1. Without them, PG 14+ raises
        //   "inconsistent types deduced for parameter $1" (SQLSTATE 42P08)
        // because $1 is referenced both inside the CTE (registrations.player_id)
        // AND in the outer SELECT (discipline_records.player_id). Both columns
        // ARE uuid per the FK migration, but the planner deduces the type
        // independently per CTE scope and the two deductions can disagree
        // under some plan shapes. A single explicit cast pins the type and
        // makes the query bulletproof.
        const revolvingResult = await client.query(`
            WITH recent_games AS (
                SELECT r.game_id
                FROM registrations r
                JOIN games g ON g.id = r.game_id
                WHERE r.player_id = $1::uuid
                  AND r.status = 'confirmed'
                  AND g.game_status = 'completed'
                ORDER BY g.game_date DESC
                LIMIT 10
            )
            SELECT COALESCE(SUM(dr.points), 0) AS revolving_pts
            FROM discipline_records dr
            WHERE dr.player_id = $1::uuid
              AND (dr.game_id IS NULL OR dr.game_id IN (SELECT game_id FROM recent_games))
        `, [playerId]);
        const revolvingPts = parseInt(revolvingResult.rows[0].revolving_pts);
        const newTier = tierFromRevolvingPoints(revolvingPts);

        await applyTierChange(client, playerId, newTier);
        await client.query('COMMIT');

        res.json({ success: true, newTier, revolvingTotal: revolvingPts, removedPoints: record.points });

        setImmediate(async () => {
            await auditLog(pool, req.user.playerId, 'discipline_removed', playerId,
                `${record.points} point(s) removed (${record.offense_type}) | new revolving total: ${revolvingPts} | new tier: ${newTier}`);
        });
    } catch (error) {
        await client.query('ROLLBACK').catch(() => {});
        // FIX-250: log full error context AND return error.message to client.
        // This endpoint is admin-only so the message is not user-leak surface.
        console.error('Remove discipline record error:', {
            recordId,
            adminId: req.user?.playerId,
            errorMessage: error.message,
            errorCode: error.code,
            errorDetail: error.detail,
            errorStack: error.stack
        });
        res.status(500).json({
            error: 'Failed to remove discipline record',
            detail: error.message,
            code: error.code || null
        });
    } finally {
        client.release();
    }
});

// POST /api/admin/players/:id/recalc-tier — force-recalculate a player's tier from their revolving points
// Fixes stale tiers caused by legacy code or manual corrections.
// Admin only. Uses same inline logic as the manual discipline endpoint.
app.post('/api/admin/players/:id/recalc-tier', authenticateToken, requireAdmin, async (req, res) => {
    const { id } = req.params;
    try {
        // FIX-292: explicit ::uuid casts on $1 — same PG inference issue.
        const revolvingResult = await pool.query(`
            SELECT COALESCE(SUM(dr.points), 0) AS revolving_pts
            FROM discipline_records dr
            WHERE dr.player_id = $1::uuid
            AND (dr.game_id IS NULL OR dr.game_id IN (
                SELECT r.game_id FROM registrations r
                JOIN games g ON g.id = r.game_id
                WHERE r.player_id = $1::uuid AND r.status = 'confirmed'
                AND g.game_status = 'completed'
                ORDER BY g.game_date DESC LIMIT 10
            ))
        `, [id]);
        const revolvingPts = parseInt(revolvingResult.rows[0].revolving_pts);
        const newTier = tierFromRevolvingPoints(revolvingPts);
        await applyTierChange(pool, id, newTier);
        res.json({ success: true, newTier, revolvingTotal: revolvingPts });
        setImmediate(() => auditLog(pool, req.user.playerId, 'tier_recalculated', id,
            `Tier recalculated | revolving pts: ${revolvingPts} | new tier: ${newTier}`));
    } catch (error) {
        console.error('Recalc tier error:', error);
        res.status(500).json({ error: 'Failed to recalculate tier' });
    }
});

// POST /api/admin/players/:id/unban — superadmin only, clears discipline and resets to gold
// CRIT-14: requireSuperAdmin — admins must not be able to unban players the superadmin deliberately banned
app.post('/api/admin/players/:id/unban', authenticateToken, requireSuperAdmin, async (req, res) => {
    const { id } = req.params;
    const client = await pool.connect();
    try {
        await client.query('BEGIN');

        // Clear all existing discipline records — clean slate, zero points
        await client.query('DELETE FROM discipline_records WHERE player_id = $1', [id]);

        // Force gold tier — player returns with a clean record, clear ban timestamp
        await client.query(
            'UPDATE players SET reliability_tier = $1, white_ban_started_at = NULL WHERE id = $2',
            ['gold', id]
        );

        // Insert reinstatement notification for the player
        await client.query(`
            INSERT INTO notifications (player_id, type, message)
            VALUES ($1, 'account_reinstated', '✅ Your account has been reinstated. Welcome back.')
        `, [id]);

        await client.query('COMMIT');

        // Fire push notification (non-blocking)
        sendNotification('account_reinstated', id, {}).catch(() => {});

        res.json({ message: 'Player unbanned successfully', newTier: 'gold' });
        setImmediate(async () => {
            await auditLog(pool, req.user.playerId, 'player_unbanned', id,
                `Discipline cleared | new tier: gold`);
        });
    } catch (error) {
        await client.query('ROLLBACK');
        console.error('Unban error:', error);
    } finally {
        client.release();
    }
});

// ── DIRECT MESSAGES ──────────────────────────────────────────────────────────

// GET /api/dm/conversations — list all DM conversations for the logged-in player
// Returns latest message per conversation, unread count, other player info
app.get('/api/dm/conversations', authenticateToken, async (req, res) => {
    try {
        const result = await pool.query(`
            SELECT
                other_player_id,
                other_name,
                other_alias,
                other_tier,
                last_message,
                last_message_at,
                last_sender_id,
                COUNT(*) FILTER (
                    WHERE sender_id != $1 AND read_at IS NULL
                ) AS unread_count
            FROM (
                SELECT
                    CASE WHEN dm.sender_id = $1 THEN dm.recipient_id ELSE dm.sender_id END AS other_player_id,
                    p.full_name    AS other_name,
                    p.alias        AS other_alias,
                    p.reliability_tier AS other_tier,
                    dm.message     AS last_message,
                    dm.created_at  AS last_message_at,
                    dm.sender_id   AS last_sender_id,
                    dm.sender_id,
                    dm.read_at,
                    ROW_NUMBER() OVER (
                        PARTITION BY LEAST(dm.sender_id, dm.recipient_id), GREATEST(dm.sender_id, dm.recipient_id)
                        ORDER BY dm.created_at DESC
                    ) AS rn
                FROM direct_messages dm
                JOIN players p ON p.id = CASE WHEN dm.sender_id = $1 THEN dm.recipient_id ELSE dm.sender_id END
                WHERE (dm.sender_id = $1 OR dm.recipient_id = $1)
                  AND dm.deleted_at IS NULL
            ) sub
            WHERE rn = 1
            GROUP BY other_player_id, other_name, other_alias, other_tier,
                     last_message, last_message_at, last_sender_id
            ORDER BY last_message_at DESC
        `, [req.user.playerId]);

        res.json(result.rows);
    } catch (error) {
        console.error('Get conversations error:', error);
        res.status(500).json({ error: 'Failed to fetch conversations' });
    }
});

// GET /api/dm/:playerId — get the DM thread between logged-in player and another player
// ?since=<ISO> for incremental polling, ?limit=&offset= for pagination
app.get('/api/dm/:playerId', authenticateToken, async (req, res) => {
    const { playerId } = req.params;
    const { since }    = req.query;
    // SEC-022b: Validate `since` + Fix 33: pagination
    if (since && isNaN(Date.parse(since))) {
        return res.status(400).json({ error: 'Invalid `since` parameter — must be a valid ISO date' });
    }
    const limit  = Math.min(parseInt(req.query.limit)  || 50, 100);
    const offset = Math.max(parseInt(req.query.offset) || 0,  0);

    try {
        // Verify other player exists
        const check = await pool.query('SELECT id FROM players WHERE id = $1', [playerId]);
        if (check.rows.length === 0) return res.status(404).json({ error: 'Player not found' });

        const sinceClause = since ? 'AND dm.created_at > $3' : '';
        // Fix 33: paginate DM threads — prevents unbounded query on high-volume conversations
        const paginateSuffix = since
            ? `LIMIT ${limit} OFFSET ${offset}`
            : `LIMIT ${limit} OFFSET ${offset}`;
        const params = since
            ? [req.user.playerId, playerId, since]
            : [req.user.playerId, playerId];

        const result = await pool.query(`
            SELECT
                dm.id,
                dm.sender_id,
                dm.recipient_id,
                dm.message,
                dm.read_at,
                dm.created_at,
                COALESCE(p.alias, p.full_name) AS sender_name
            FROM direct_messages dm
            JOIN players p ON p.id = dm.sender_id
            WHERE (
                (dm.sender_id = $1 AND dm.recipient_id = $2)
                OR
                (dm.sender_id = $2 AND dm.recipient_id = $1)
            )
            AND dm.deleted_at IS NULL
            ${sinceClause}
            ORDER BY dm.created_at ASC
            ${paginateSuffix}
        `, params);

        res.json(result.rows);
    } catch (error) {
        console.error('Get DM thread error:', error);
        res.status(500).json({ error: 'Failed to fetch messages' });
    }
});

// POST /api/dm/:playerId — send a DM to a player (SEC-009: rate limited)
app.post('/api/dm/:playerId', authenticateToken, dmSendLimiter, async (req, res) => {
    const { playerId }    = req.params;
    const { message }     = req.body;
    const senderId        = req.user.playerId;

    if (String(playerId) === String(senderId)) {
        return res.status(400).json({ error: 'You cannot message yourself' });
    }
    if (!message || typeof message !== 'string' || !message.trim()) {
        return res.status(400).json({ error: 'Message is required' });
    }
    if (message.trim().length > 500) {
        return res.status(400).json({ error: 'Message must be 500 characters or fewer' });
    }

    try {
        // FIX-271: gate on sender's messaging-block state before doing any other
        // work. If the sender is currently muted, return 403 with the admin's
        // reason (if set) so the client can show a meaningful error. Defensive:
        // fall back to a plain SELECT if the columns don't exist yet (server
        // deployed before the ALTER TABLE), treating "no column" as "not muted".
        try {
            const blockCheck = await pool.query(
                `SELECT messaging_blocked_at, messaging_blocked_until, messaging_block_reason
                   FROM players WHERE id = $1`,
                [senderId]
            );
            const row = blockCheck.rows[0];
            if (row && row.messaging_blocked_at) {
                const expired = row.messaging_blocked_until &&
                                new Date(row.messaging_blocked_until).getTime() <= Date.now();
                if (!expired) {
                    const until = row.messaging_blocked_until
                        ? `until ${new Date(row.messaging_blocked_until).toISOString()}`
                        : 'indefinitely';
                    const detail = row.messaging_block_reason
                        ? `${row.messaging_block_reason} (${until})`
                        : `You're temporarily restricted from sending messages (${until}). Contact an admin if you think this is in error.`;
                    return res.status(403).json({ error: 'messaging_blocked', detail });
                }
            }
        } catch (e) {
            // Column-missing or transient — fall through and allow the send.
            // Better to occasionally let through than block all DMs on a deploy lag.
            if (!/column.*does not exist/i.test(e.message || '')) {
                console.warn('messaging-block check failed (non-fatal):', e.message);
            }
        }

        // Verify recipient exists. Try to pull dm_notifications_enabled so we
        // can gate the push notification below — message itself still gets
        // stored regardless of the pref (opt-out of pings, not of receiving).
        // Defensive: if the column doesn't exist yet (server deployed before
        // the ALTER TABLE), fall back to the legacy SELECT and assume the
        // recipient wants push. Avoids breaking DMs during a rolling deploy.
        let recipientCheck;
        let recipientWantsPush = true;
        try {
            recipientCheck = await pool.query(
                'SELECT id, alias, full_name, dm_notifications_enabled FROM players WHERE id = $1', [playerId]
            );
            if (recipientCheck.rows.length > 0) {
                recipientWantsPush = recipientCheck.rows[0].dm_notifications_enabled !== false;
            }
        } catch (e) {
            // Likely "column does not exist" pre-migration. Retry without the column.
            recipientCheck = await pool.query(
                'SELECT id, alias, full_name FROM players WHERE id = $1', [playerId]
            );
            // recipientWantsPush stays true (default)
        }
        if (recipientCheck.rows.length === 0) {
            return res.status(404).json({ error: 'Player not found' });
        }
        const recipient = recipientCheck.rows[0];

        const result = await pool.query(`
            INSERT INTO direct_messages (sender_id, recipient_id, message)
            VALUES ($1, $2, $3)
            RETURNING id, sender_id, recipient_id, message, read_at, created_at,
                (SELECT COALESCE(alias, full_name) FROM players WHERE id = $1) AS sender_name
        `, [senderId, playerId, message.trim()]);

        const newMsg = result.rows[0];

        // In-app notification + push to recipient (fire and forget)
        const senderResult = await pool.query(
            'SELECT COALESCE(alias, full_name) AS name FROM players WHERE id = $1',
            [senderId]
        );
        const senderName = senderResult.rows[0]?.name || 'Someone';
        const preview    = message.trim().length > 40
            ? message.trim().substring(0, 40) + '…'
            : message.trim();

        pool.query(`
            INSERT INTO notifications (player_id, type, message)
            VALUES ($1, 'new_dm', $2)
        `, [playerId, `${senderName}: ${preview}`]).catch(() => {});

        // Push only fires if the recipient hasn't opted out via the messages-screen toggle.
        // The in-app notifications row above is still created so the bell badge updates,
        // and the conversation polling on web/mobile still surfaces the new message.
        if (recipientWantsPush) {
            sendNotification('new_dm', playerId, {
                preview: `${senderName}: ${preview}`,
                senderName,
                senderId,   // so app can navigate to the correct DM thread
            }).catch(() => {});
        }

        // FIX-271: DM spree detection — alert superadmin (once per day per sender)
        // when a sender hits 3+ unique recipients on a single day. "Today" =
        // calendar day in Europe/London (matches the timezone used elsewhere for
        // user-facing dates). Fire-and-forget; never blocks the response. If any
        // of the new columns don't exist yet (pre-migration), the entire check
        // silently no-ops.
        (async () => {
            try {
                const sprR = await pool.query(`
                    SELECT
                      COUNT(DISTINCT recipient_id)::int AS unique_recipients_today,
                      (
                        SELECT last_dm_spree_alert_at
                          FROM players
                         WHERE id = $1
                      ) AS last_alert_day,
                      (CURRENT_TIMESTAMP AT TIME ZONE 'Europe/London')::date AS london_today
                      FROM direct_messages
                     WHERE sender_id = $1
                       AND deleted_at IS NULL
                       AND (created_at AT TIME ZONE 'Europe/London')::date
                           = (CURRENT_TIMESTAMP AT TIME ZONE 'Europe/London')::date
                `, [senderId]);
                const row = sprR.rows[0] || {};
                const unique = row.unique_recipients_today || 0;
                const londonToday = row.london_today; // 'YYYY-MM-DD' as Date
                const lastAlert   = row.last_alert_day;

                // Already alerted today → silent return.
                const alreadyAlerted = lastAlert &&
                    new Date(lastAlert).toISOString().slice(0, 10) ===
                    new Date(londonToday).toISOString().slice(0, 10);

                if (unique >= 3 && !alreadyAlerted) {
                    // Mark before sending to avoid duplicate alerts on the very
                    // next message landing milliseconds apart from concurrent
                    // workers (best-effort idempotency).
                    await pool.query(
                        `UPDATE players SET last_dm_spree_alert_at = $1 WHERE id = $2`,
                        [londonToday, senderId]
                    );

                    notifyAdmin(
                        `⚠️ DM spree — ${senderName} messaged ${unique} different players today`,
                        [
                            ['Sender',           `${senderName} (id ${senderId})`],
                            ['Unique recipients today', String(unique)],
                            ['Most recent recipient',   `${recipient.alias || recipient.full_name} (id ${recipient.id})`],
                            ['Time (UTC)',       new Date().toISOString()],
                            ['Review',           'https://totalfooty.co.uk/manage-players.html?player=' + senderId],
                        ]
                    ).catch(() => {});

                    // Audit-log the detection (not the alert send) so it appears
                    // in the messaging-restrictions sub of the comms category.
                    // Pass null as adminId — this is a system-detected event,
                    // not an admin action (matches the pattern used for
                    // badge_auto_awarded elsewhere in this file).
                    auditLog(pool, null, 'dm_spree_detected', senderId,
                        `${unique} unique recipients today — admin alerted`).catch(() => {});

                    // FIX-308: also create a CRM task so the spree shows up in
                    // the admin's task inbox (not just email). One row per sender
                    // per day — uniqueness enforced by the once-per-day
                    // last_dm_spree_alert_at gate above, so this is safe to
                    // unconditionally insert here. Type='message_spree' is a new
                    // queue entry kind; UI groups it under "Comms / Moderation".
                    try {
                        await pool.query(`
                            INSERT INTO admin_action_queue
                                (type, status, title, notes,
                                 subject_player_id, flagged_by, recommend_refund)
                            VALUES ('message_spree', 'pending', $1, $2, $3, NULL, FALSE)
                        `, [
                            `DM spree — ${senderName} messaged ${unique} different players today`,
                            `Auto-flagged by the spree detector. Review the conversation history before considering a temporary mute. Subject: player ${senderId}.`,
                            senderId,
                        ]);
                    } catch (qe) {
                        // Non-fatal — email already fired, audit row already
                        // logged. Just log the failure (column-missing pre-FIX-308
                        // or transient DB issue).
                        if (!/column.*does not exist|relation.*does not exist/i.test(qe.message || '')) {
                            console.warn('[FIX-308] message_spree task insert failed:', qe.message);
                        }
                    }
                }
            } catch (e) {
                // Pre-migration column-missing is the most common cause; treat as no-op.
                if (!/column.*does not exist/i.test(e.message || '')) {
                    console.warn('DM spree check failed (non-fatal):', e.message);
                }
            }
        })();

        res.status(201).json(newMsg);
    } catch (error) {
        console.error('Send DM error:', error);
        res.status(500).json({ error: 'Failed to send message' });
    }
});

// GET /api/player/dm-notification-pref — current opt-in/out state for the logged-in player.
// Used by the messages-screen toggle on web + mobile to render the initial switch state.
app.get('/api/player/dm-notification-pref', authenticateToken, async (req, res) => {
    try {
        // Try with the new column. If the column doesn't exist yet, default to true
        // and surface that to the client — keeps the toggle visible & functional.
        try {
            const result = await pool.query(
                'SELECT dm_notifications_enabled FROM players WHERE id = $1',
                [req.user.playerId]
            );
            if (result.rows.length === 0) return res.status(404).json({ error: 'Player not found' });
            res.json({ enabled: result.rows[0].dm_notifications_enabled !== false });
        } catch (colErr) {
            // Column likely doesn't exist pre-migration. Verify the player exists, default true.
            const exists = await pool.query('SELECT 1 FROM players WHERE id = $1', [req.user.playerId]);
            if (exists.rows.length === 0) return res.status(404).json({ error: 'Player not found' });
            res.json({ enabled: true });
        }
    } catch (error) {
        console.error('Get DM notification pref error:', error);
        res.status(500).json({ error: 'Failed to fetch preference' });
    }
});

// POST /api/player/dm-notification-pref — flip the opt-in/out flag.
// Body: { enabled: boolean }. Returns the new state so the client can re-render.
app.post('/api/player/dm-notification-pref', authenticateToken, async (req, res) => {
    const { enabled } = req.body;
    if (typeof enabled !== 'boolean') {
        return res.status(400).json({ error: 'enabled must be a boolean' });
    }
    try {
        const result = await pool.query(
            'UPDATE players SET dm_notifications_enabled = $1 WHERE id = $2 RETURNING dm_notifications_enabled',
            [enabled, req.user.playerId]
        );
        if (result.rows.length === 0) return res.status(404).json({ error: 'Player not found' });
        res.json({ enabled: result.rows[0].dm_notifications_enabled !== false });
    } catch (error) {
        // If the column hasn't been added yet, return a clear setup error rather than 500.
        // We can't silently no-op here — the whole point of the call is to persist the choice.
        if (error && error.code === '42703') {
            console.warn('Set DM notification pref: column missing — run the ALTER TABLE migration');
            return res.status(503).json({ error: 'Notification preferences not yet available — please try again shortly.' });
        }
        console.error('Set DM notification pref error:', error);
        res.status(500).json({ error: 'Failed to update preference' });
    }
});

// POST /api/dm/:playerId/report — report a conversation to superadmin
app.post('/api/dm/:playerId/report', authenticateToken, dmReportLimiter, async (req, res) => {
    try {
        const reporterId  = req.user.playerId;
        const { playerId } = req.params; // the other person in the conversation

        if (String(playerId) === String(reporterId)) {
            return res.status(400).json({ error: 'Cannot report yourself' });
        }

        // Fetch reporter info
        const reporterResult = await pool.query(
            'SELECT COALESCE(alias, full_name) AS name FROM players WHERE id = $1',
            [reporterId]
        );
        if (reporterResult.rows.length === 0) return res.status(404).json({ error: 'Player not found' });
        const reporterName = reporterResult.rows[0].name;

        // Fetch sender info
        const senderResult = await pool.query(
            'SELECT COALESCE(alias, full_name) AS name FROM players WHERE id = $1',
            [playerId]
        );
        if (senderResult.rows.length === 0) return res.status(404).json({ error: 'Other player not found' });
        const senderName = senderResult.rows[0].name;

        // Get the most recent message sent FROM the other player TO the reporter
        const msgResult = await pool.query(`
            SELECT message, created_at
            FROM direct_messages
            WHERE sender_id = $1 AND recipient_id = $2 AND deleted_at IS NULL
            ORDER BY created_at DESC
            LIMIT 1
        `, [playerId, reporterId]);

        const latestMsg    = msgResult.rows[0];
        const messageText  = latestMsg ? latestMsg.message : '(no messages found)';
        const messageDate  = latestMsg
            ? new Date(latestMsg.created_at).toLocaleString('en-GB', {
                day: '2-digit', month: 'short', year: 'numeric',
                hour: '2-digit', minute: '2-digit', timeZone: 'Europe/London'
              })
            : 'Unknown';

        // Fire-and-forget email to superadmin
        setImmediate(async () => {
            try {
                await emailTransporter.sendMail({
                    from: '"TotalFooty" <totalfooty19@gmail.com>',
                    to: SUPERADMIN_EMAIL || 'totalfooty19@gmail.com',
                    subject: `🚨 Message Reported — ${htmlEncode(reporterName).replace(/[\r\n]/g, '')}`,
                    html: wrapEmailHtml(`
                        <p style="font-weight:700;font-size:16px;margin:0 0 16px;">Message Report</p>
                        <table style="width:100%;border-collapse:collapse;font-size:15px;color:#ccc;">
                            <tr><td style="padding:6px 0;color:#888;width:140px;">Reported by</td>
                                <td style="font-weight:900;">${htmlEncode(reporterName)}</td></tr>
                            <tr><td style="padding:6px 0;color:#888;">Message from</td>
                                <td style="font-weight:900;">${htmlEncode(senderName)}</td></tr>
                            <tr><td style="padding:6px 0;color:#888;">Sent at</td>
                                <td>${htmlEncode(messageDate)}</td></tr>
                            <tr><td style="padding:6px 0;color:#888;vertical-align:top;">Message</td>
                                <td style="background:#1a1a1a;padding:10px;border-radius:6px;border-left:3px solid #ff3366;">
                                    ${htmlEncode(messageText)}
                                </td></tr>
                        </table>
                        <p style="color:#888;font-size:13px;margin-top:16px;">
                            Log in to the admin panel to review the full conversation.
                        </p>
                    `)
                });
            } catch (e) {
                console.error('DM report email failed (non-critical):', e.message);
            }
        });

        setImmediate(() => auditLog(pool, reporterId, 'dm_reported', playerId,
            `${reporterName} reported a message from ${senderName}`));

        res.json({ message: 'Report submitted successfully' });
    } catch (error) {
        console.error('DM report error:', error);
        res.status(500).json({ error: 'Failed to submit report' });
    }
});

