    // already enforced by appearancesCte in calcSeriesLeaderboard.
    30: { name: 'Turtle',              icon: '🐢', category: 'award', awardType: 'turtle',           validCalcTypes: ['most','most_per_game'],                                              primaryLabel: 'Turtles',         supportingLabel: null },
