async function fix356BootstrapFaq() {
    try {
        // Schema (idempotent)
        await pool.query(`
            CREATE TABLE IF NOT EXISTS faq_entries (
                id              SERIAL PRIMARY KEY,
                category        TEXT NOT NULL,
                question        TEXT NOT NULL,
                answer          TEXT NOT NULL,
                keywords        TEXT[] NOT NULL DEFAULT '{}',
                display_order   INT NOT NULL DEFAULT 0,
                active          BOOLEAN NOT NULL DEFAULT TRUE,
                created_at      TIMESTAMPTZ DEFAULT NOW(),
                updated_at      TIMESTAMPTZ DEFAULT NOW(),
                updated_by      UUID
            )
        `);
        await pool.query(`
            CREATE INDEX IF NOT EXISTS idx_faq_entries_active_order
                ON faq_entries (active, display_order)
        `);
        await pool.query(`
            CREATE TABLE IF NOT EXISTS faq_unanswered (
                id              SERIAL PRIMARY KEY,
                query           TEXT NOT NULL,
                user_comment    TEXT,
                player_id       UUID,
                status          TEXT NOT NULL DEFAULT 'pending'
                                 CHECK (status IN ('pending', 'resolved', 'dismissed')),
                created_at      TIMESTAMPTZ DEFAULT NOW(),
                resolved_at     TIMESTAMPTZ,
                resolved_by     UUID,
                resolved_to_faq_id INT REFERENCES faq_entries(id) ON DELETE SET NULL,
                resolution_note TEXT
            )
        `);
        await pool.query(`
            CREATE INDEX IF NOT EXISTS idx_faq_unanswered_status
                ON faq_unanswered (status, created_at DESC)
        `);

        // FIX-357: signup intent table — used by the lock-preempt system
        await pool.query(`
            CREATE TABLE IF NOT EXISTS game_signup_intents (
                id          UUID PRIMARY KEY DEFAULT gen_random_uuid(),
                game_id     UUID NOT NULL REFERENCES games(id) ON DELETE CASCADE,
                player_id   UUID NOT NULL REFERENCES players(id) ON DELETE CASCADE,
                intent_type TEXT NOT NULL,
                created_at  TIMESTAMPTZ NOT NULL DEFAULT NOW(),
                resolved_at TIMESTAMPTZ,
                UNIQUE (game_id, player_id, intent_type)
            )
        `);
        await pool.query(`
            CREATE INDEX IF NOT EXISTS idx_signup_intents_unresolved
                ON game_signup_intents (game_id, created_at)
                WHERE resolved_at IS NULL
        `);

        // Seed — only if table is empty
        const cnt = await pool.query('SELECT COUNT(*)::int AS n FROM faq_entries');
        if (cnt.rows[0].n === 0) {
            console.log(`📚 FIX-356: seeding ${FIX_356_FAQ_SEED.length} baseline FAQs…`);
            for (const f of FIX_356_FAQ_SEED) {
                await pool.query(
                    `INSERT INTO faq_entries (category, question, answer, keywords, display_order)
                          VALUES ($1, $2, $3, $4, $5)`,
                    [f.category, f.question, f.answer, f.keywords || [], f.order || 0]
                );
            }
            console.log(`✅ FIX-356: FAQ seed complete`);
        } else {
            console.log(`📚 FIX-356: FAQ table already populated (${cnt.rows[0].n} rows), skipping seed`);
        }
    } catch (e) {
        console.error('❌ FIX-356 FAQ bootstrap failed:', e.message);
        // Non-fatal — server can run without FAQs, admins can re-trigger later
    }
}

// ──────────────────────────────────────────────────────────────────────────
// FIX-359..364 — Wonderful Payments hardening + observability bootstrap
// ──────────────────────────────────────────────────────────────────────────
// Adds two schema objects (idempotent, safe to run on every boot):
//   1. wonderful_payments.notified_at  — push-notification idempotency guard
//      so we don't double-push on webhook retries / reconciler hits.
//   2. wonderful_webhook_log           — append-only audit table of every
//      webhook attempt with raw payload + match outcome. Powers the CRM
//      "Webhook log" diagnostic added in FIX-364. Separate table (not JSONB
//      on wonderful_payments) so webhook acks stay fast and the main row
//      doesn't bloat over time.
// Bootstrap the organiser_reviews table. This was historically provisioned
// out-of-band and was MISSING on production (every query catches 42P01 and
// degrades silently — which is why organiser ratings never appeared). Created
// here idempotently with the multi-organiser unique key so a player can review
// each organiser on a game exactly once.
async function bootstrapOrganiserReviews() {
    try {
        await pool.query(`
            CREATE TABLE IF NOT EXISTS organiser_reviews (
                id                  BIGSERIAL PRIMARY KEY,
                game_id             UUID NOT NULL REFERENCES games(id)   ON DELETE CASCADE,
                organiser_player_id UUID NOT NULL REFERENCES players(id) ON DELETE CASCADE,
                reviewer_player_id  UUID NOT NULL REFERENCES players(id) ON DELETE CASCADE,
                tenant_id           UUID REFERENCES tenants(id) ON DELETE SET NULL,
                rating              INT  NOT NULL CHECK (rating BETWEEN 1 AND 5),
                comment             TEXT,
                created_at          TIMESTAMPTZ NOT NULL DEFAULT NOW(),
                updated_at          TIMESTAMPTZ NOT NULL DEFAULT NOW(),
                CONSTRAINT organiser_reviews_game_org_reviewer_key
                    UNIQUE (game_id, organiser_player_id, reviewer_player_id)
            )
        `);
        await pool.query(`
            CREATE INDEX IF NOT EXISTS idx_organiser_reviews_organiser
                ON organiser_reviews (organiser_player_id)
        `);
        await pool.query(`
            CREATE INDEX IF NOT EXISTS idx_organiser_reviews_game
                ON organiser_reviews (game_id)
        `);
        await pool.query(`
            CREATE INDEX IF NOT EXISTS idx_organiser_reviews_tenant
                ON organiser_reviews (tenant_id, created_at DESC)
        `);
        // Migration path: if the table pre-existed with the OLD unique key
        // (game_id, reviewer_player_id), swap it for the multi-organiser key.
        await pool.query(`
            DO $$
            BEGIN
                IF EXISTS (
                    SELECT 1 FROM pg_constraint
                     WHERE conrelid = 'organiser_reviews'::regclass
                       AND contype = 'u'
                       AND conname <> 'organiser_reviews_game_org_reviewer_key'
                ) THEN
                    -- Drop any other unique constraint(s) (old single-target key).
                    EXECUTE (
                        SELECT string_agg('ALTER TABLE organiser_reviews DROP CONSTRAINT ' || quote_ident(conname) || ';', ' ')
                          FROM pg_constraint
                         WHERE conrelid = 'organiser_reviews'::regclass
                           AND contype = 'u'
                           AND conname <> 'organiser_reviews_game_org_reviewer_key'
                    );
                END IF;
                IF NOT EXISTS (
                    SELECT 1 FROM pg_constraint
                     WHERE conrelid = 'organiser_reviews'::regclass
                       AND conname = 'organiser_reviews_game_org_reviewer_key'
                ) THEN
                    ALTER TABLE organiser_reviews
                        ADD CONSTRAINT organiser_reviews_game_org_reviewer_key
                        UNIQUE (game_id, organiser_player_id, reviewer_player_id);
                END IF;
            END $$;
        `);
        console.log('✅ organiser_reviews schema ready (multi-organiser unique key)');
    } catch (e) {
        console.error('❌ organiser_reviews bootstrap failed:', e.message);
        // Non-fatal — endpoints already degrade gracefully if the table is absent.
    }
}

