// ──────────────────────────────────────────────────────────────────────────
// FIX-357 — Lock-preempt helpers
// ──────────────────────────────────────────────────────────────────────────
// When a player tries to sign up while admin holds the lock, we:
//   1. Record their intent in game_signup_intents
//   2. Schedule a 15s auto-release of the admin's lock (if not already pending)
//   3. Notify the admin via push
// The admin can call /unlock early to release sooner; the timer is then cancelled.

const LOCK_PREEMPT_GRACE_SECONDS = 15;
const _pendingLockReleases = new Map();   // gameId -> timer handle

function _scheduleLockRelease(gameId, delaySeconds) {
    if (_pendingLockReleases.has(gameId)) return;

    const handle = setTimeout(async () => {
        _pendingLockReleases.delete(gameId);
        try {
            const r = await pool.query(`
                UPDATE games
                   SET player_editing_locked = FALSE,
                       locked_by = NULL,
                       locked_at = NULL
                 WHERE id = $1
                   AND player_editing_locked = TRUE
                 RETURNING locked_by
            `, [gameId]);
            if (r.rowCount > 0) {
                console.log(`[FIX-357] auto-released lock on game ${gameId} after ${delaySeconds}s grace`);
                setImmediate(() => gameAuditLog(pool, gameId, r.rows[0].locked_by,
                    'game_unlocked',
                    `Auto-released for waiting player after ${delaySeconds}s grace`
                ).catch(() => {}));
                pool.query(
                    `UPDATE game_signup_intents
                        SET resolved_at = NOW()
                      WHERE game_id = $1 AND resolved_at IS NULL`,
                    [gameId]
                ).catch(() => {});
            }
        } catch (e) {
            console.warn('[FIX-357] scheduled release failed:', e.message);
        }
    }, delaySeconds * 1000);

    _pendingLockReleases.set(gameId, handle);
}

function _clearPendingLockRelease(gameId) {
    const handle = _pendingLockReleases.get(gameId);
    if (handle) {
        clearTimeout(handle);
        _pendingLockReleases.delete(gameId);
    }
}

async function _recordSignupIntent(gameId, playerId, intentType) {
    let isNewPreempt = false;
    try {
        const ins = await pool.query(
            `INSERT INTO game_signup_intents (game_id, player_id, intent_type)
                  VALUES ($1, $2, $3)
             ON CONFLICT (game_id, player_id, intent_type)
             DO UPDATE SET created_at = CASE
                                  WHEN game_signup_intents.resolved_at IS NOT NULL
                                       OR game_signup_intents.created_at < NOW() - INTERVAL '60 seconds'
                                  THEN NOW()
                                  ELSE game_signup_intents.created_at
                               END,
                           resolved_at = NULL
             RETURNING (created_at >= NOW() - INTERVAL '2 seconds') AS just_inserted_or_refreshed`,
            [gameId, playerId, intentType]
        );
        isNewPreempt = !!ins.rows[0]?.just_inserted_or_refreshed;
    } catch (e) {
        if (e && e.code === '42P01') {
            console.warn('[FIX-357] game_signup_intents missing; preempt disabled until bootstrap runs');
        } else {
            console.warn('[FIX-357] intent insert failed:', e.message);
        }
    }

    if (isNewPreempt) {
        setImmediate(() => _scheduleLockRelease(gameId, LOCK_PREEMPT_GRACE_SECONDS));
        setImmediate(() => _notifyAdminOfWaitingPlayer(gameId, playerId));
    }

    return {
        code: 'GAME_LOCKED_RETRY_PENDING',
        error: 'Admin is finishing up. Retrying in 15 seconds…',
        retry_after_seconds: LOCK_PREEMPT_GRACE_SECONDS,
    };
}

async function _notifyAdminOfWaitingPlayer(gameId, playerId) {
    try {
        const r = await pool.query(
            `SELECT locked_by FROM games WHERE id = $1`,
            [gameId]
        );
        const adminPlayerId = r.rows[0]?.locked_by;
        if (!adminPlayerId) return;

        const playerInfo = await pool.query(
            'SELECT alias, full_name FROM players WHERE id = $1',
            [playerId]
        );
        const playerName = playerInfo.rows[0]?.alias
                         || playerInfo.rows[0]?.full_name
                         || 'A player';

        await sendNotification('lock_preempt', adminPlayerId, {
            gameId, playerName,
            graceSeconds: LOCK_PREEMPT_GRACE_SECONDS,
        });
    } catch (e) {
        console.warn('[FIX-357] notify admin failed (non-critical):', e.message);
    }
}

async function _resolveSignupIntentForPlayer(gameId, playerId) {
    try {
        const r = await pool.query(
            `UPDATE game_signup_intents
                SET resolved_at = NOW()
              WHERE game_id = $1 AND player_id = $2 AND resolved_at IS NULL
             RETURNING id`,
            [gameId, playerId]
        );
        if (r.rowCount > 0) {
            const rem = await pool.query(
                `SELECT 1 FROM game_signup_intents
                  WHERE game_id = $1 AND resolved_at IS NULL LIMIT 1`,
                [gameId]
            );
            if (rem.rows.length === 0) {
                _clearPendingLockRelease(gameId);
            }
        }
    } catch (e) {
        if (!(e && e.code === '42P01')) {
            console.warn('[FIX-357] resolve intent failed:', e.message);
        }
    }
}


app.listen(PORT, () => {
    console.log(`🚀 Total Footy API running on port ${PORT} — build: web57`);

    // FIX-356: bootstrap FAQ schema + seed (non-blocking, runs in parallel with email check)
    fix356BootstrapFaq().catch(e => console.error('FIX-356 bootstrap surfaced:', e.message));

    // FIX-359..364: bootstrap Wonderful hardening schema (notified_at + webhook log)
    bootstrapOrganiserReviews().catch(e => console.error('organiser_reviews bootstrap surfaced:', e.message));
    fix359BootstrapWonderfulHardening().catch(e => console.error('FIX-359 bootstrap surfaced:', e.message));

    // FIX-366: bootstrap multi-region column + backfill (non-blocking)
    fix366BootstrapMultiRegion().catch(e => console.error('FIX-366 bootstrap surfaced:', e.message));
    fix386BootstrapRefundPolicy().catch(e => console.error('FIX-386 bootstrap surfaced:', e.message));
    fix398BootstrapPilot().catch(e => console.error('FIX-398 bootstrap surfaced:', e.message));
    fix400BootstrapOverrated().catch(e => console.error('FIX-400 bootstrap surfaced:', e.message));
    fix401BootstrapLeagues().catch(e => console.error('FIX-401 bootstrap surfaced:', e.message));
    fix411BootstrapStatsVoid().catch(e => console.error('FIX-411 bootstrap surfaced:', e.message));

    // ── Email transport self-check ──────────────────────────────────────────
    // Verifies SMTP credentials on boot so silent email failures become loud.
    // Without this, an expired Gmail App Password would just cause every email
    // to fail without you knowing — exactly the bug we hit.
    const adminTarget = SUPERADMIN_EMAIL || 'totalfooty19@gmail.com';
    const hasPwd = !!process.env.GMAIL_APP_PASSWORD;
    console.log(`📧 Email config: GMAIL_APP_PASSWORD ${hasPwd ? 'SET' : '** MISSING **'} | SUPERADMIN_EMAIL → ${adminTarget}`);
    emailTransporter.verify((err) => {
        if (err) {
            console.error('❌ EMAIL TRANSPORT BROKEN — Gmail SMTP verify failed:',
                err.message || err, '| code:', err.code || '(none)',
                '| response:', err.response || '(none)');
            console.error('   → Likely fix: regenerate Gmail App Password at https://myaccount.google.com/apppasswords');
            console.error('   → Then update GMAIL_APP_PASSWORD env var in Render and restart.');
        } else {
            console.log('✅ Email transport verified — Gmail SMTP ready');
        }
    });

    // ── Team-email settle recovery sweep ────────────────────────────────────
    // Pending "settle" timers live in memory (setTimeout). If the server restarts
    // or Render cold-starts during a pending window, the timer is lost. This sweep
    // runs on boot (to catch settles whose scheduled time has already passed) and
    // every 2 minutes (to catch settles orphaned by any runtime anomaly).
    const recoverPendingTeamSettles = async () => {
        try {
            const due = await pool.query(
                `SELECT id FROM games
                 WHERE teams_email_settle_at IS NOT NULL
                   AND teams_email_settle_at <= NOW()`
            );
            if (due.rows.length === 0) return;
            console.log(`⏱️  Recovering ${due.rows.length} pending team-email settle(s)`);
            for (const row of due.rows) {
                // Skip if there's already an in-memory timer running for this game
                // (avoids firing twice if the sweep interleaves with a live schedule).
                if (_teamEmailTimers.has(row.id)) continue;
                await fireTeamEmailSettle(row.id);
            }
        } catch (e) {
            console.error('Team email settle recovery error:', e.message);
        }
    };
    // Fire once on boot (after a short delay to let DB pool stabilise)
    setTimeout(recoverPendingTeamSettles, 5000);
    // And periodically thereafter
    setInterval(recoverPendingTeamSettles, 2 * 60 * 1000); // every 2 minutes

    // ── Monthly trophies cron ───────────────────────────────────────────────
    // Tick hourly. tickMonthlyTrophyCron() returns early unless it's the 1st
    // of the month, then processes the previous month if not already done.
    // setInterval is the established pattern here (no node-cron dependency).
    // First tick runs 1 minute after boot to catch a 1st-of-month restart.
    setTimeout(tickMonthlyTrophyCron, 60 * 1000);
    setInterval(tickMonthlyTrophyCron, 60 * 60 * 1000); // every hour
    // FIX-331 ROW Day 17: monthly invoice auto-generation. Same hourly tick,
    // only fires on day 1 of month. Idempotent via UNIQUE constraint on
    // invoices(tenant_id, period_start, period_end) + audit-log dedup.
    setInterval(_fix331TickInvoiceCron, 60 * 60 * 1000); // every hour
    setInterval(tickPilotExpiryCron, 60 * 60 * 1000); // FIX-398: hourly pilot-expiry check

    // ── Wonderful payment reconciler ────────────────────────────────────────
    // The webhook is the primary credit path but it can fail silently: Render
    // cold starts, transient network errors, Wonderful API hiccups, dropped
    // browser tabs. This sweep finds any payment that's still non-credited and
    // re-verifies with Wonderful, crediting (+ auto-registering for the game,
    // if applicable) if paid. Runs on boot (catches webhooks missed during a
    // deploy or cold-start) and every 5 minutes thereafter.
    // FIX-361 (Web66): split into recent + broad sweeps with INDEPENDENT locks.
    // Why: a slow broad sweep was blocking the urgent 'just paid in last 10 min'
    // case for up to 5 minutes. A payment that takes 90s to clear (as the
    // 25-May bug showed) crossed the 5-min boundary and stayed stuck longer
    // than necessary. With two locks, the 90s recent sweep runs even when the
    // broad sweep is busy — and vice-versa. The recent sweep is bounded by
    // its narrow window (last 10 min, max 30 rows) so it's always quick.
    let wonderfulReconcilerRecentRunning = false;
    let wonderfulReconcilerBroadRunning = false;

    async function _runWonderfulReconcilerSweep(scope) {
        if (!WONDERFUL_API_KEY) return;
        // scope.label - 'recent' or 'broad'
        // scope.whereClause - SQL fragment (built below)
        try {
            // Only look back 72 hours — older stuck payments need manual admin
            // intervention anyway. LIMIT 30 per run so we don't hammer Wonderful.
            // Skip terminal states (credited/failed/cancelled/expired/init_failed)
            // and rows younger than 30s (to avoid racing a live initiate call).
            // We INCLUDE init_pending rows because a stuck init_pending might be one
            // where the DB INSERT succeeded but the subsequent Wonderful call failed
            // to return cleanly — _wonderfulVerifyStatus will list-search and resolve.
            const pending = await pool.query(
                `SELECT * FROM wonderful_payments
                 WHERE status NOT IN ('credited', 'credited_manually', 'failed', 'cancelled', 'expired', 'init_failed')
                   ${scope.whereClause}
                 ORDER BY created_at ASC
                 LIMIT 30`
            );
            if (pending.rows.length === 0) return;
            console.log(`💳 [WF reconciler:${scope.label}]: checking ${pending.rows.length} pending payment(s)…`);

            let credited = 0, stillPending = 0, failed = 0;
            for (const pmt of pending.rows) {
                try {
                    const { verified, resolvedWpId } = await _wonderfulVerifyStatus(pmt);
                    if (!verified) { failed++; continue; }
                    if (verified === 'paid' || verified === 'accepted') {
                        const result = await creditAndAutoRegisterWonderful(pmt, {
                            contextLabel: 'reconciler:' + scope.label,
                            verifyWpId: resolvedWpId
                        });
                        if (result.credited) {
                            credited++;
                            console.log(`  ✓ credited £${result.pounds.toFixed(2)} — ref ${pmt.merchant_reference}${pmt.game_id ? ` · auto-register: ${result.autoRegister.status || 'topup-only'}` : ''}`);
                        }
                    } else {
                        // Not paid — mirror Wonderful's state in our DB without crediting. Guard manual credit.
                        if (pmt.status !== verified) {
                            await pool.query(
                                `UPDATE wonderful_payments SET status = $1, wonderful_payment_id = COALESCE(wonderful_payment_id, $2) WHERE id = $3 AND status NOT IN ('credited', 'credited_manually')`,
                                [verified, resolvedWpId, pmt.id]
                            ).catch(() => {});
                        }
                        stillPending++;
                    }
                } catch (e) {
                    failed++;
                    console.error(`  ✗ reconciler:${scope.label} error for ref ${pmt.merchant_reference}:`, e.message);
                }
            }
            if (credited > 0 || failed > 0) {
                console.log(`💳 Wonderful reconciler:${scope.label} done: ${credited} credited, ${stillPending} still pending, ${failed} failed`);
            }
        } catch (e) {
            console.error(`Wonderful reconciler:${scope.label} sweep error:`, e.message);
        }
    }

    async function reconcileRecentWonderfulPayments() {
        // Recent sweep: payments created in the last 10 minutes (high-priority window).
        // Runs every 90 seconds. Catches the "paid in 90s but missed first sweep" case
        // that the original 5-min cadence couldn't handle.
        if (wonderfulReconcilerRecentRunning) return;
        wonderfulReconcilerRecentRunning = true;
        try {
            await _runWonderfulReconcilerSweep({
                label: 'recent',
                whereClause: `AND created_at BETWEEN NOW() - INTERVAL '10 minutes' AND NOW() - INTERVAL '30 seconds'`
            });
        } finally {
            wonderfulReconcilerRecentRunning = false;
        }
    }

    async function reconcileBroadWonderfulPayments() {
        // Broad sweep: payments older than 10 minutes, up to 72 hours. Runs every
        // 5 minutes. Catches longer-stuck rows the recent sweep has aged out of.
        if (wonderfulReconcilerBroadRunning) return;
        wonderfulReconcilerBroadRunning = true;
        try {
            await _runWonderfulReconcilerSweep({
                label: 'broad',
                whereClause: `AND created_at BETWEEN NOW() - INTERVAL '72 hours' AND NOW() - INTERVAL '10 minutes'`
            });
        } finally {
            wonderfulReconcilerBroadRunning = false;
        }
    }

    // Boot kicker: broad sweep on boot (catches anything missed during deploy/cold-start).
    // Recent and broad then run on their own cadences.
    setTimeout(reconcileBroadWonderfulPayments, 10_000);
    setTimeout(reconcileRecentWonderfulPayments, 20_000);
    setInterval(reconcileRecentWonderfulPayments, 90 * 1000);
    setInterval(reconcileBroadWonderfulPayments, 5 * 60 * 1000);

    // ── Multi-vote auto-close cron ──────────────────────────────────────────
    // FIX-220 R4-#1: voting_closes_at expires but no automatic closure runs.
    // Without this, expired Multi votes stay in 'proposed' status forever,
    // blocking the game lifecycle. Players see "voting closed" carousel that
    // never resolves to confirmed teams. Sweep every minute and auto-close
    // any expired but still-proposed votes.
    let _mvAutoCloseRunning = false;
    async function autoCloseExpiredMultiVotes() {
        if (_mvAutoCloseRunning) return;
        _mvAutoCloseRunning = true;
        try {
            // Find games with at least one proposed setup whose voting_closes_at
            // has passed. Use DISTINCT game_id since a game may have N candidates.
            const expired = await pool.query(`
                SELECT DISTINCT game_id
                  FROM team_setups
                 WHERE status = 'proposed'
                   AND voting_opened_at IS NOT NULL
                   AND voting_closed_at IS NULL
                   AND voting_closes_at IS NOT NULL
                   AND voting_closes_at < NOW()
                 LIMIT 50
            `);
            for (const row of expired.rows) {
                try {
                    const result = await _closeMultiTeamVoting(pool, row.game_id, 'auto_timer', null);
                    if (result.ok) {
                        console.log(`[mv-auto-close] closed game=${row.game_id} winner=${result.winnerId} source=${result.source}`);
                    } else {
                        console.warn(`[mv-auto-close] close failed for game=${row.game_id}: ${result.error}`);
                    }
                } catch (e) {
                    // Single-game failure must not block the sweep
                    console.error(`[mv-auto-close] error closing game=${row.game_id}:`, e.message);
                }
            }
        } catch (e) {
            console.error('[mv-auto-close] sweep error:', e.message);
        } finally {
            _mvAutoCloseRunning = false;
        }
    }
    // First tick 30s after boot (lets DB pool warm up), then every 60s.
    setTimeout(autoCloseExpiredMultiVotes, 30_000);
    setInterval(autoCloseExpiredMultiVotes, 60 * 1000);

    // FIX-245: nightly feedback aggregation. Runs every 4 hours so a
    // late-night vote doesn't sit until the next "calendar" night. Same
    // setInterval pattern as the rest of the cron family.
    setInterval(_runNightlyFeedbackAggregation, 4 * 60 * 60 * 1000);
    // Initial run 5 minutes after boot — catches anything missed during downtime.
    setTimeout(_runNightlyFeedbackAggregation, 5 * 60 * 1000);

    // Keep database AND backend warm (ping every 5 minutes)
    setInterval(async () => {
        try {
            await pool.query('SELECT 1');
        } catch (error) {
            console.error('✗ Keep-alive error:', error.message);
        }
    }, 5 * 60 * 1000); // 5 minutes (more aggressive)

    // ════════════════════════════════════════════════════════════════════════
    // FIX-315 — RSVP cron jobs
    // ════════════════════════════════════════════════════════════════════════

    // 48h warning sweep — hourly. Fires the warning email + push to any RSVP
    // whose deadline is within the next 48h and hasn't been warned yet.
    let _rsvpWarningCronRunning = false;
    async function _rsvpWarningCron() {
        if (_rsvpWarningCronRunning) return;
        _rsvpWarningCronRunning = true;
        try {
            const due = await pool.query(`
                SELECT r.id, r.player_id, r.game_id, r.rsvp_deadline
                  FROM registrations r
                 WHERE r.status = 'rsvp'
                   AND r.rsvp_warned_at IS NULL
                   AND r.rsvp_deadline BETWEEN NOW() AND NOW() + INTERVAL '48 hours'
                 ORDER BY r.rsvp_deadline ASC
                 LIMIT 200
            `);
            if (due.rows.length === 0) return;
            // Mark warned immediately to prevent duplicate sends if the cron overruns.
            await pool.query(
                `UPDATE registrations SET rsvp_warned_at = NOW() WHERE id = ANY($1::uuid[])`,
                [due.rows.map(r => r.id)]
            );
            for (const row of due.rows) {
                try {
                    const gd = await getGameDataForNotification(row.game_id);
                    _sendRsvpEmail('warning', row.player_id, gd, { deadline: row.rsvp_deadline }).catch(() => {});
                    sendNotification('rsvp_warning', row.player_id, {
                        ...gd,
                        deadline_short: _rsvpFormatDeadline(row.rsvp_deadline)
                    }).catch(() => {});
                    await gameAuditLog(pool, row.game_id, null, 'rsvp_warning_sent',
                        `Auto 48h warning sent to player ${row.player_id}`).catch(() => {});
                } catch (e) {
                    console.warn('[FIX-315] warning cron row failed:', e.message);
                }
            }
            console.log(`⏰ [FIX-315] RSVP warning sweep — ${due.rows.length} warning(s) sent`);
        } catch (e) {
            console.error('[FIX-315] _rsvpWarningCron error:', e.message);
        } finally {
            _rsvpWarningCronRunning = false;
        }
    }
    setTimeout(_rsvpWarningCron, 90 * 1000);            // first run 90s after boot
    setInterval(_rsvpWarningCron, 60 * 60 * 1000);      // hourly thereafter

    // 24h bump sweep — every 5 minutes. Auto-bumps any RSVP whose deadline
    // has passed, then promotes confirmed_backups in paid_at order to fill
    // the freed slots, then fires bump notifications.
    let _rsvpBumpCronRunning = false;
    async function _rsvpBumpCron() {
        if (_rsvpBumpCronRunning) return;
        _rsvpBumpCronRunning = true;
        try {
            // Find games with at least one expired RSVP, process per-game (txn-safe).
            const dueGames = await pool.query(`
                SELECT DISTINCT game_id FROM registrations
                 WHERE status = 'rsvp' AND rsvp_deadline < NOW()
                 LIMIT 100
            `);
            for (const gRow of dueGames.rows) {
                const client = await pool.connect();
                try {
                    await client.query('BEGIN');
                    const gMeta = await client.query(
                        `SELECT id, max_players, team_selection_type, tournament_team_count
                           FROM games WHERE id = $1 FOR UPDATE`,
                        [gRow.game_id]
                    );
                    if (gMeta.rows.length === 0) { await client.query('ROLLBACK'); client.release(); continue; }

                    const bumped = await client.query(`
                        UPDATE registrations
                           SET status = 'bumped', bumped_at = NOW()
                         WHERE game_id = $1 AND status = 'rsvp' AND rsvp_deadline < NOW()
                         RETURNING id, player_id`,
                        [gRow.game_id]
                    );
                    if (bumped.rows.length === 0) { await client.query('COMMIT'); client.release(); continue; }

                    // Promote confirmed_backups into freed slots (paid_at order).
                    const promoted = await _fix315PromoteConfirmedBackups(client, gRow.game_id, bumped.rows.length, gMeta.rows[0]);
                    await client.query('COMMIT');

                    const slotsRemaining = bumped.rows.length - promoted.length;
                    const gd = await getGameDataForNotification(gRow.game_id);
                    for (const row of bumped.rows) {
                        _sendRsvpEmail('bumped', row.player_id, gd,
                            { hasOpenSpots: slotsRemaining > 0, openCount: slotsRemaining }).catch(() => {});
                        sendNotification('rsvp_bumped', row.player_id,
                            { ...gd, hasOpenSpots: slotsRemaining > 0 }).catch(() => {});
                        await gameAuditLog(pool, gRow.game_id, null, 'rsvp_bumped',
                            `Auto-bumped (deadline passed)`).catch(() => {});
                    }
                    // Mark notified so we don't double-fire (per-row, by id).
                    await pool.query(
                        `UPDATE registrations SET bumped_notified_at = NOW() WHERE id = ANY($1::uuid[])`,
                        [bumped.rows.map(r => r.id)]
                    ).catch(() => {});

                    console.log(`⏰ [FIX-315] RSVP bump for game ${gRow.game_id}: ${bumped.rows.length} bumped, ${promoted.length} promoted`);
                } catch (e) {
                    await client.query('ROLLBACK').catch(() => {});
                    console.error(`[FIX-315] bump cron game ${gRow.game_id} failed:`, e.message);
                } finally {
                    client.release();
                }
            }
        } catch (e) {
            console.error('[FIX-315] _rsvpBumpCron error:', e.message);
        } finally {
            _rsvpBumpCronRunning = false;
        }
    }
    setTimeout(_rsvpBumpCron, 60 * 1000);             // first run 60s after boot
    setInterval(_rsvpBumpCron, 5 * 60 * 1000);        // every 5 minutes
    // END FIX-315 cron ═══════════════════════════════════════════════════════


    // Game reminder scheduler DISABLED — teams_confirmed notification replaces this
    // (sendNotification('teams_confirmed') fires on admin confirm-teams action)

    // Daily sweep: remove expired 'New' (baby) badge from players > 30 days old
    // This catches players who registered but never played (autoAllocateBadges never ran for them)
    setInterval(async () => {
        try {
            // Get affected players before deleting so we can audit each one
            const affected = await pool.query(`
                SELECT pb.player_id
                FROM player_badges pb
                JOIN badges b ON b.id = pb.badge_id
                JOIN players p ON p.id = pb.player_id
                WHERE b.name = 'New'
                  AND p.created_at < NOW() - INTERVAL '30 days'
            `);
            if (affected.rows.length === 0) return;

            const result = await pool.query(`
                DELETE FROM player_badges pb
                USING badges b, players p
                WHERE pb.badge_id = b.id
                  AND pb.player_id = p.id
                  AND b.name = 'New'
                  AND p.created_at < NOW() - INTERVAL '30 days'
            `);

            if (result.rowCount > 0) {
                console.log(`⏰ Baby badge sweep: removed New badge from ${result.rowCount} player(s)`);
                for (const row of affected.rows) {
                    await auditLog(pool, null, 'badge_auto_removed', row.player_id, 'badge: New (30-day sweep)');
                }
            }
        } catch (error) {
            console.error('✗ Baby badge sweep error:', error.message);
        }
    }, 24 * 60 * 60 * 1000); // Once every 24 hours

    // TF Game Awards — auto-close expired voting every 10 minutes
    setInterval(async () => {
        try {
            const expiredAwards = await pool.query(`
                SELECT id FROM games
                WHERE awards_open = true
                  AND awards_close_at IS NOT NULL
                  AND awards_close_at < NOW()
                  AND game_status = 'completed'
            `);

            if (expiredAwards.rows.length === 0) return;

            console.log(`⏰ Auto-closing TF Game Awards for ${expiredAwards.rows.length} game(s)...`);
            for (const row of expiredAwards.rows) {
                try {
                    const result = await closeAwards(row.id);
                    const count = result?.confirmedWinners?.length || 0;
                    console.log(`✅ Awards auto-closed for game ${row.id}: ${count} award(s) confirmed`);
                    await gameAuditLog(pool, row.id, null, 'awards_auto_closed',
                        `${count} award(s) confirmed`).catch(() => {});
                } catch (e) {
                    console.error(`✗ Awards auto-close failed for game ${row.id}:`, e.message);
                }
            }
        } catch (error) {
            console.error('✗ Awards scheduler error:', error.message);
        }
    }, 10 * 60 * 1000); // 10 minutes

    // Auto-finalize expired MOTM voting every 10 minutes
    setInterval(async () => {
        try {
            const expired = await pool.query(`
                SELECT g.id
                FROM games g
                WHERE g.motm_voting_ends < NOW()
                  AND g.motm_winner_id IS NULL
                  AND g.game_status = 'completed'
                  AND EXISTS (SELECT 1 FROM motm_nominees mn WHERE mn.game_id = g.id)
            `);

            if (expired.rows.length === 0) return;

            console.log(`⏰ Auto-finalizing MOTM for ${expired.rows.length} game(s)...`);
            for (const row of expired.rows) {
                try {
                    const result = await runMotmFinalize(row.id);
                    if (!result.alreadyFinalized) {
                        const names = result.winners.map(w => w.name).join(' & ');
                        console.log(`✅ MOTM auto-finalized game ${row.id}: ${names}`);
                        await gameAuditLog(pool, row.id, null, 'motm_finalized',
                            `Auto-finalized | Winner(s): ${names} | Votes: ${result.winners[0]?.votes ?? '?'}`).catch(() => {});
                    }
                    // Always run ref finalize — MOTM and refs are independent
                    await finaliseRefereeReviews(row.id).catch(e =>
                        console.error(`Ref review finalize failed ${row.id}:`, e.message));
                } catch (e) {
                    console.error(`✗ MOTM auto-finalize failed for game ${row.id}:`, e.message);
                }
            }
        } catch (error) {
            console.error('✗ MOTM scheduler error:', error.message);
        }
    }, 10 * 60 * 1000); // 10 minutes

    // Ref review window close scheduler — runs every 10 minutes
    // Handles games that have no MOTM (e.g. external losses) so ref reviews still finalise
    setInterval(async () => {
        try {
            const expiredRefs = await pool.query(`
                SELECT DISTINCT gr.game_id
                FROM game_referees gr
                JOIN games g ON g.id = gr.game_id
                WHERE g.ref_review_ends < NOW()
                  AND g.game_status = 'completed'
                  AND gr.status = 'confirmed'
                  AND gr.final_rating IS NULL
            `);
            for (const row of expiredRefs.rows) {
                await finaliseRefereeReviews(row.game_id).catch(e =>
                    console.error(`Scheduled ref review finalize failed ${row.game_id}:`, e.message));
            }
        } catch (e) {
            console.error('Ref review scheduler error:', e.message);
        }
    }, 10 * 60 * 1000); // 10 minutes

        // Min-rating auto-drop scheduler — runs every 5 minutes
    // Updates min_rating_drop_sent flag. effectiveMinOvr() uses game_date vs Date.now()
    // so the actual gate drops automatically; this flag just prevents double-firing.
    let minRatingDropRunning = false;
    setInterval(async () => {
        if (minRatingDropRunning) return;
        minRatingDropRunning = true;
        try {
            // 48h drop: games 47h55m–48h5m away, not yet dropped once
            const drop48 = await pool.query(`
                SELECT id FROM games
                WHERE min_rating_enabled = TRUE
                  AND star_rating >= 2
                  AND min_rating_drop_sent = 0
                  AND game_date BETWEEN NOW() + INTERVAL '47 hours 55 minutes'
                                   AND NOW() + INTERVAL '48 hours 5 minutes'
                  AND game_status NOT IN ('cancelled','completed')
            `);
            for (const row of drop48.rows) {
                const claimed = await pool.query(
                    `UPDATE games SET min_rating_drop_sent = 1
                      WHERE id = $1 AND min_rating_drop_sent = 0 RETURNING id`,
                    [row.id]
                );
                if (claimed.rowCount > 0)
                    console.log(`⏰ Min-rating 48h drop: game ${row.id}`);
            }
            // 24h drop: games 23h55m–24h5m away, dropped once but not twice
            const drop24 = await pool.query(`
                SELECT id FROM games
                WHERE min_rating_enabled = TRUE
                  AND star_rating >= 2
                  AND min_rating_drop_sent = 1
                  AND game_date BETWEEN NOW() + INTERVAL '23 hours 55 minutes'
                                   AND NOW() + INTERVAL '24 hours 5 minutes'
                  AND game_status NOT IN ('cancelled','completed')
            `);
            for (const row of drop24.rows) {
                const claimed = await pool.query(
                    `UPDATE games SET min_rating_drop_sent = 2
                      WHERE id = $1 AND min_rating_drop_sent = 1 RETURNING id`,
                    [row.id]
                );
                if (claimed.rowCount > 0)
                    console.log(`⏰ Min-rating 24h drop: game ${row.id}`);
            }
        } catch (e) {
            console.error('✗ Min-rating drop scheduler error:', e.message);
        } finally {
            minRatingDropRunning = false;
        }
    }, 5 * 60 * 1000);

    // ── AI Bio: Sunday 2am batch regeneration ──
    let bioRunning = false;
    setInterval(async () => {
        if (bioRunning) return;
        const now = new Date();
        // Sunday (0) at 2am
        // Render runs UTC — UK is UTC+0 (GMT) or UTC+1 (BST). Check hours 1-2 UTC to cover both.
        if (now.getDay() !== 0 || (now.getHours() !== 1 && now.getHours() !== 2)) return;
        bioRunning = true;
        console.log('🤖 Starting weekly AI bio generation...');
        try {
            const players = await pool.query(
                `SELECT id FROM players WHERE total_appearances >= 5 ORDER BY total_appearances DESC`
            );
            for (const row of players.rows) {
                try {
                    await regeneratePlayerBio(row.id);
                    // 1 second delay between players — respects API rate limits
                    await new Promise(r => setTimeout(r, 1000));
                } catch (e) {
                    console.warn(`Bio batch failed for player ${row.id}:`, e.message);
                }
            }
            console.log(`🤖 Bio batch complete: ${players.rows.length} players processed`);
        } catch (e) {
            console.error('Bio cron failed:', e.message);
        } finally {
            bioRunning = false;
        }
    }, 60 * 1000); // Check every minute, run only at Sunday 2am


    // ── Coaching session reminder — 24 hours before ──────────────
    // Email: coach + all registered players + superadmin
    let coachingReminderRunning = false;
    setInterval(async () => {
        if (coachingReminderRunning) return;
        coachingReminderRunning = true;
        try {
            // Find sessions starting in 23h55m–24h05m that haven't had reminder sent
            const sessions = await pool.query(`
                SELECT cs.id, cs.session_url, cs.activity_type, cs.session_date,
                       cs.coach_player_id, v.name AS venue_name
                FROM coaching_sessions cs
                LEFT JOIN venues v ON v.id = cs.confirmed_venue_id
                WHERE cs.session_date BETWEEN NOW() + INTERVAL '23 hours 55 minutes'
                  AND NOW() + INTERVAL '24 hours 5 minutes'
                  AND cs.status IN ('finalised','venue_confirmed','coach_confirmed')
                  AND cs.reminder_sent IS NOT TRUE
            `);
            for (const sess of sessions.rows) {
                // Atomic claim
                const claimed = await pool.query(
                    `UPDATE coaching_sessions SET reminder_sent=TRUE WHERE id=$1 AND (reminder_sent IS NOT TRUE) RETURNING id`,
                    [sess.id]
                );
                if (claimed.rowCount === 0) continue;

                const dateStr = sess.session_date
                    ? new Date(sess.session_date).toLocaleString('en-GB', {
                        weekday:'long', day:'numeric', month:'long', hour:'2-digit', minute:'2-digit', timeZone:'Europe/London'
                      })
                    : 'TBC';
                const actLabel = (sess.activity_type || '').replace(/_/g, ' ');
                const sessionLink = `https://totalfooty.co.uk/session.html?url=${sess.session_url}`;
                const emailBody = `
                    <p style="color:#888">This is a reminder that you have a coaching session tomorrow.</p>
                    <table style="margin:12px 0;">
                        <tr><td style="color:#888;width:120px;">Date &amp; Time</td><td style="color:#fff;font-weight:700;">${htmlEncode(dateStr)}</td></tr>
                        <tr><td style="color:#888;">Activity</td><td style="color:#fff;">${htmlEncode(actLabel)}</td></tr>
                        ${sess.venue_name ? `<tr><td style="color:#888;">Venue</td><td style="color:#fff;">${htmlEncode(sess.venue_name)}</td></tr>` : ''}
                    </table>
                    <p style="color:#888;margin-top:12px;"><a href="${sessionLink}" style="color:#C0392B;">View Session Details →</a></p>`;

                // Get registered players
                const players = await pool.query(
                    `SELECT player_id FROM coaching_registrations WHERE session_id=$1 AND status='registered'`,
                    [sess.id]
                );
                const recipientIds = players.rows.map(r => r.player_id);
                if (sess.coach_player_id) recipientIds.push(sess.coach_player_id);

                await sendCoachingEmail(recipientIds, `Coaching Session Tomorrow — ${actLabel}`, emailBody);
                notifyAdmin('Coaching Session Reminder Sent', [['Details', `${actLabel} session on ${dateStr} — ${recipientIds.length} reminder(s) sent.`]]);
                console.log(`⏰ Coaching reminder sent for session ${sess.id} (${recipientIds.length} recipients)`);
            }
        } catch (e) {
            console.error('Coaching reminder scheduler error:', e.message);
        } finally {
            coachingReminderRunning = false;
        }
    }, 5 * 60 * 1000); // Check every 5 minutes

    // ── White-ban expiry scheduler — runs hourly ──────────────────────────────
    // After 7 days on White, inserts a negative 'ban_served' discipline record
    // to reduce revolving points to 9 (Bronze ceiling), restores tier to Bronze,
    // clears white_ban_started_at, and notifies the player.
    setInterval(async () => {
        try {
            const expired = await pool.query(`
                SELECT id FROM players
                WHERE reliability_tier = 'white'
                  AND white_ban_started_at IS NOT NULL
                  AND white_ban_started_at <= NOW() - INTERVAL '7 days'
            `);

            for (const { id: pid } of expired.rows) {
                try {
                    // FIX-292: explicit ::uuid casts on $1.
                    const revRes = await pool.query(`
                        SELECT COALESCE(SUM(dr.points), 0) AS pts
                        FROM discipline_records dr
                        WHERE dr.player_id = $1::uuid
                          AND (dr.game_id IS NULL OR dr.game_id IN (
                              SELECT r.game_id FROM registrations r
                              JOIN games g ON g.id = r.game_id
                              WHERE r.player_id = $1::uuid
                                AND r.status = 'confirmed'
                                AND g.game_status = 'completed'
                              ORDER BY g.game_date DESC LIMIT 10
                          ))
                    `, [pid]);

                    const currentPts = parseInt(revRes.rows[0].pts) || 0;
                    const TARGET_PTS = 9; // Bronze ceiling

                    if (currentPts > TARGET_PTS) {
                        await pool.query(
                            `INSERT INTO discipline_records
                                (player_id, game_id, points, offense_type, recorded_by)
                             VALUES ($1, NULL, $2, 'ban_served', NULL)`,
                            [pid, -(currentPts - TARGET_PTS)]
                        );
                    }

                    await pool.query(
                        'UPDATE players SET reliability_tier = $1, white_ban_started_at = NULL WHERE id = $2',
                        ['bronze', pid]
                    );

                    await pool.query(
                        `INSERT INTO notifications (player_id, type, message)
                         VALUES ($1, 'ban_lifted', '\u2705 Your 1-week ban has been served. You have been restored to Bronze tier — keep it clean!')`,
                        [pid]
                    );

                    sendNotification('ban_lifted', pid, {}).catch(() => {});

                    await auditLog(pool, null, 'ban_served', pid,
                        `White ban expired — revolving pts adjusted from ${currentPts} to ${Math.min(currentPts, TARGET_PTS)} — tier: bronze`);

                    console.log(`✓ Ban lifted: player ${pid} (${currentPts} pts → ${TARGET_PTS} pts)`);
                } catch (playerErr) {
                    console.error(`Ban expiry failed for player ${pid}:`, playerErr.message);
                }
            }
        } catch (e) {
            console.error('White-ban expiry scheduler error:', e.message);
        }
    }, 60 * 60 * 1000); // Every hour

});
